-- Poems batch 420
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuanqu-2347','滚绣球','杨景贤','元','元曲','yuanqu','','[]','这扇子六丁神巧铸成，五道神细打磨，阎浮间并无二个，上秤称一千斤犹有余多。',101,'元曲/yuanqu.json','["这扇子六丁神巧铸成，五道神细打磨，阎浮间并无二个，上秤称一千斤犹有余多。", "管他二十四气风，吹灭八十一洞火，火焰山神见咱也胆破，恼着我呵登时间便起干戈。", "我且着扇扇翻地狱门前树，卷起天河水波，我是第一洞妖魔。"]'),
('yuanqu-2348','叨叨令','杨景贤','元','元曲','yuanqu','','[]','我这片杀人心胆大来大，救人命志少些儿个。',194,'元曲/yuanqu.json','["我这片杀人心胆大来大，救人命志少些儿个。", "(行者云)师父过不得火焰山，特来相投。", "(公主唱)你道是火焰山师父实难过，则这个铁嵯峰的魔女能行祸。", "休得要闲中寻闹也波哥，休得要闲中寻闹也波哥，则你那秃髑髅敢禁不得刚刀剁。", "(行者云)这贼贱人好无礼。", "我是紫云罗洞主，通天大圣。", "我盗了老子金丹，炼得铜筋铁骨，火眼金睛，钅俞石屁眼，摆锡鸡巴。", "我怕甚刚刀剁下我鸟来？(公主云)这胡孙好生无礼。", "我也不是你惹的。"]'),
('yuanqu-2349','白鹤子','杨景贤','元','元曲','yuanqu','','[]','你道是花果山是祖居，铁嵯峰是我的行窝。',69,'元曲/yuanqu.json','["你道是花果山是祖居，铁嵯峰是我的行窝。", "在彼处难比强，来此处索伏些懦。", "(行者云)泼婆娘，我若拿住你，也不打你，也不骂你，你则猜。", "(公主唱)。"]'),
('yuanqu-2350','中吕/快活三','杨景贤','元','元曲','yuanqu','','[]','恼的我无明火怎收撮？泼毛团怎敢张罗？卖弄他铜筋铁骨自开合，我一扇子敢着你翻筋斗三千个。',43,'元曲/yuanqu.json','["恼的我无明火怎收撮？泼毛团怎敢张罗？卖弄他铜筋铁骨自开合，我一扇子敢着你翻筋斗三千个。"]'),
('yuanqu-2351','鲍老儿','杨景贤','元','元曲','yuanqu','','[]','他大叫高呼勒着我，更怕我杨柳腰肢袅娜。',52,'元曲/yuanqu.json','["他大叫高呼勒着我，更怕我杨柳腰肢袅娜。", "耀武扬威越逞过，更怕我桃脸风吹得破。", "弯弓蹬弩，拈枪使棒，擂鼓筛锣。"]'),
('yuanqu-2352','古鲍老','杨景贤','元','元曲','yuanqu','','[]','手提着太阿，碧澄澄恰如三尺波。',69,'元曲/yuanqu.json','["手提着太阿，碧澄澄恰如三尺波。", "额攒着翠娥，恶狠狠怒如千丈火。", "狂旗磨．战鼓敲，妖兵和。", "你便吃了灵丹数颗，争似我风声偏大，半合儿敢着你难捞摸。"]'),
('yuanqu-2353','道和','杨景贤','元','元曲','yuanqu','','[]','这扇子柄长面阔，锁铁贯嵌金磨，骨把揠薄。',65,'元曲/yuanqu.json','["这扇子柄长面阔，锁铁贯嵌金磨，骨把揠薄。", "妖气罩冷风多，云端顶上观见我。", "铁棒来抽身便躲，戒刀着怎地存活？我着戒刀折，铁棒损，力消磨。"]'),
('yuanqu-2354','柳青娘','杨景贤','元','元曲','yuanqu','','[]','休么，从来不以这妖魔，忒轻薄也待如何？那厮有神通难摸，艺高强名扬播。',123,'元曲/yuanqu.json','["休么，从来不以这妖魔，忒轻薄也待如何？那厮有神通难摸，艺高强名扬播。", "偷灵丹老子怎近他？盗蟠桃玉皇难奈何。", "那厮上天宫将神威挫，下人间兴祸多。", "看着身躯大，顷刻成微末；看着东方过，顷刻向西方落。", "一任他铁骨铜筋火眼睛，不索交兵，敢着他随风一扇扇了渡江河。"]'),
('yuanqu-2355','尾','杨景贤','元','元曲','yuanqu','','[]','或是堕在远冈，落在浅波，滴溜溜有似梧飘落。',141,'元曲/yuanqu.json','["或是堕在远冈，落在浅波，滴溜溜有似梧飘落。", "便是天着他有命？今生必定害风魔。", "(下)(行者上，云)吃这婆娘一扇子，扇得我滴溜溜半空中。", "休说甚的小孙草腹屎肠，做了四句口号，骂这弟子：婆娘忒恁高强，法宝世上无双。", "不借我呵也罢，当着你热我凉。", "待干罢，去投奔观音佛去，好歹有甚见识过去。", "(下)。"]'),
('yuanqu-2356','喜迁莺','杨景贤','元','元曲','yuanqu','','[]','又不必樵苏炙爨，通红一带峰峦，遥观，碧天将半。',59,'元曲/yuanqu.json','["又不必樵苏炙爨，通红一带峰峦，遥观，碧天将半。", "这山便有美玉也难枉着凤鸾，又我甚沟涧湍。", "镝箭的风威相助，淋琅般雨势相攒。"]'),
('yuanqu-2357','出队子','杨景贤','元','元曲','yuanqu','','[]','把天瓢来浇灌，潺潺的水势满。',44,'元曲/yuanqu.json','["把天瓢来浇灌，潺潺的水势满。", "犹胜似上元驿夜半火威宽，博望坡秋深火焰撺，赤壁山冬初火力完。"]'),
('yuanqu-2358','四门子','杨景贤','元','元曲','yuanqu','','[]','箕水豹斑斓隐雾端，壁水犭俞紧把眉攒，参水猿左右听呼唤。',96,'元曲/yuanqu.json','["箕水豹斑斓隐雾端，壁水犭俞紧把眉攒，参水猿左右听呼唤。", "水势溶宽，山高下不分匠段，路迢遥不见林峦。", "水部雄火焰消迷路平安，十万里程受苦酸。", "师父力多般，餐风宿露忙投窜。", "宵衣旰食无撺断，受驱驰百万端。"]'),
('yuanqu-2359','神仗儿','杨景贤','元','元曲','yuanqu','','[]','风神王冷气酸，雨师雷伯两意欢，电母施威，水神没乱，这功劳都一般。',64,'元曲/yuanqu.json','["风神王冷气酸，雨师雷伯两意欢，电母施威，水神没乱，这功劳都一般。", "往西天取得经完，再重来此处难顾管。", "奏天庭仍把诸佛唤，着火再休撺。"]'),
('yuanqu-2360','尾','杨景贤','元','元曲','yuanqu','','[]','此去西天路过半，月不消十数遍团圆，那壁是灵鹫两山交界管。',28,'元曲/yuanqu.json','["此去西天路过半，月不消十数遍团圆，那壁是灵鹫两山交界管。"]'),
('yuanqu-2361','邓夫人苦痛哭存孝・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','则听的乐动声齐，他是那大唐苗裔，排亲戚。',37,'元曲/yuanqu.json','["则听的乐动声齐，他是那大唐苗裔，排亲戚。", "今日俺父母相随，可正是龙虎风云会。"]'),
('yuanqu-2362','邓夫人苦痛哭存孝・混江龙','关汉卿','元','元曲','yuanqu','','[]','则俺这沙陀雄势，便有那珠围翠绕不稀奇。',87,'元曲/yuanqu.json','["则俺这沙陀雄势，便有那珠围翠绕不稀奇。", "置造下珍羞百味，又不比水酒三杯。", "每日则是炮凤烹龙真受用，那一日不宰羊杀马做筵席！把那些个义儿家将都成立，一个个请官受赏，他每都荫子封妻。"]'),
('yuanqu-2363','邓夫人苦痛哭存孝・天下乐','关汉卿','元','元曲','yuanqu','','[]','你觑！兀那大小的儿郎列的整齐，端的是虚也波实，享富贵。',64,'元曲/yuanqu.json','["你觑！兀那大小的儿郎列的整齐，端的是虚也波实，享富贵。", "我则见旁边厢坐着周德威，一壁厢摆着品肴，番官每紧紧随；我则见军排在两下里。"]'),
('yuanqu-2364','邓夫人苦痛哭存孝・节节高','关汉卿','元','元曲','yuanqu','','[]','今日可便太平无事，全不想那用人的这之际。',89,'元曲/yuanqu.json','["今日可便太平无事，全不想那用人的这之际。", "存孝与你安邦定国，他也曾恶征战图名图利。", "他觑的三层鹿角，七层围子，如登平地；端的是八卦阵图，千员骁将，施谋用计。", "阿者，他保护着唐朝社稷！。"]'),
('yuanqu-2365','邓夫人苦痛哭存孝・元和令','关汉卿','元','元曲','yuanqu','','[]','端的是人不曾去铁衣，马不曾。',14,'元曲/yuanqu.json','["端的是人不曾去铁衣，马不曾。"]'),
('yuanqu-2366','邓夫人苦痛哭存孝・游四门','关汉卿','元','元曲','yuanqu','','[]','你则会饮酒食，着别人苦战敌。',147,'元曲/yuanqu.json','["你则会饮酒食，着别人苦战敌。", "可不道生受了有谁知？阿妈，你则是抬举着李存信、康君立；他横枪纵马怎相持？你把他亏，人面逐高低。", "（李存孝云）康君立、李存信，想当日十八骑误入长安，杀败葛从周，攻破黄巢，天下太平，是我的功劳；你有甚么功劳也？（李存信云）俺两个虽无功劳，俺两个可会唱会舞也哩。", "（正旦唱）。"]'),
('yuanqu-2367','邓夫人苦痛哭存孝・胜葫芦','关汉卿','元','元曲','yuanqu','','[]','他几时得鞭敲金镫笑微微，人唱着凯歌回？遥望见军中磨绣旗，则你那滴羞蹀躞身体，迷留没乱心肺，唬的你劈留扑碌走如飞。',56,'元曲/yuanqu.json','["他几时得鞭敲金镫笑微微，人唱着凯歌回？遥望见军中磨绣旗，则你那滴羞蹀躞身体，迷留没乱心肺，唬的你劈留扑碌走如飞。"]'),
('yuanqu-2368','邓夫人苦痛哭存孝・后庭花','关汉卿','元','元曲','yuanqu','','[]','与你一匹劣马不会骑，与你一张硬弓不会射。',94,'元曲/yuanqu.json','["与你一匹劣马不会骑，与你一张硬弓不会射。", "他比别人阵面上争功劳，你则会帐房里闲坐的。", "咱可便委其实，你便休得要瞒天瞒地。", "你饿时节挝肉吃，渴时节喝酪水，闲时节打髀殖，醉时节歪唱起，醉时节歪唱起。"]'),
('yuanqu-2369','邓夫人苦痛哭存孝・柳叶儿','关汉卿','元','元曲','yuanqu','','[]','你放下一十八般兵器，你轮不动那鞭、锏、挝、槌，您怎肯袒下臂膊刀厮劈？闹吵吵三军内，但听的马频嘶，早唬的悠悠荡荡魄散魂飞。',129,'元曲/yuanqu.json','["你放下一十八般兵器，你轮不动那鞭、锏、挝、槌，您怎肯袒下臂膊刀厮劈？闹吵吵三军内，但听的马频嘶，早唬的悠悠荡荡魄散魂飞。", "（正旦云）存孝，则今日好日辰，收拾驮马辎重，辞别了阿妈、阿者，便索长行。", "（李存孝云）今日好日辰，辞别了阿妈、阿者，便索长行也。", "（正旦唱）。"]'),
('yuanqu-2370','邓夫人苦痛哭存孝・尾声','关汉卿','元','元曲','yuanqu','','[]','罢、罢、罢，你可便难倚弟兄心，我今日不可公婆意。',176,'元曲/yuanqu.json','["罢、罢、罢，你可便难倚弟兄心，我今日不可公婆意。", "（刘夫人云）孩儿，你且休要性急，待你阿妈酒醒呵，再做商议。", "（正旦云）去则便了也。", "（唱）别近谤俺夫妻每甚的，只不过发尽儿掏窝不姓李，则今日暗昧神祗。", "（带云）惭愧也！（唱）势得一个远相离，各霸着城池；不恁的呵，这李存信、康君立断送了你。", "这一个个瞒心昧己，一个个献勤卖力，存孝，这两个巧舌头奸狡赖功贼！（下）。"]'),
('yuanqu-2371','邓夫人苦痛哭存孝・南吕/一枝花','关汉卿','元','元曲','yuanqu','','[]','常言道"官清民自安，法正天心顺"，他那里"家贫显孝子"，俺可便各自立功勋。',86,'元曲/yuanqu.json','["常言道\"官清民自安，法正天心顺\"，他那里\"家贫显孝子\"，俺可便各自立功勋。", "无正事尊亲，着俺把各自姓排头儿问，则俺这叫爹娘的无气忿。", "今日个嫌俺辱没你家门，当初你将俺真心厮认。"]'),
('yuanqu-2372','邓夫人苦痛哭存孝・牧羊关','关汉卿','元','元曲','yuanqu','','[]','听说罢心怀着闷，他可便无事哏，更打着这入衙来不问讳的乔民。',120,'元曲/yuanqu.json','["听说罢心怀着闷，他可便无事哏，更打着这入衙来不问讳的乔民。", "则他这爷共儿常是相争，更和这子父每常时厮论。", "（李存孝云）小校，与我打着者！（正旦唱）词未尽将他来骂，口未落便拳敦，畅好背晦也萧丞相。", "（正旦云）赤瓦不刺嗨！（唱）你畅好是莽撞也祗候人。"]'),
('yuanqu-2373','邓夫人苦痛哭存孝・红芍药','关汉卿','元','元曲','yuanqu','','[]','见阿者一头下马入宅门，慢慢的行过阶痕；见存孝擎壶把盏两三巡，他可也并不曾沾唇。',78,'元曲/yuanqu.json','["见阿者一头下马入宅门，慢慢的行过阶痕；见存孝擎壶把盏两三巡，他可也并不曾沾唇。", "我则见他迎头里嗔忿忿，全不肯息怒停嗔。", "我这里旁边侧立索殷勤，怎敢道怠慢因循！。"]'),
('yuanqu-2374','邓夫人苦痛哭存孝・骂玉郎','关汉卿','元','元曲','yuanqu','','[]','当初你腰间挂了先锋印，俺可也须当索受辛勤。',47,'元曲/yuanqu.json','["当初你腰间挂了先锋印，俺可也须当索受辛勤。", "他将那英雄慷慨施逞尽，他则是开绣旗，聚战马，冲军阵。"]'),
('yuanqu-2375','邓夫人苦痛哭存孝・感皇恩','关汉卿','元','元曲','yuanqu','','[]','阿者，他与你建立功勋，扶立乾坤；他与你破了黄巢，敌了归霸，败了朱温。',72,'元曲/yuanqu.json','["阿者，他与你建立功勋，扶立乾坤；他与你破了黄巢，敌了归霸，败了朱温。", "那其间便招贤纳士，今日个俺可便偃武修文。", "到如今无了征战，绝了士马，罢了边尘。"]'),
('yuanqu-2376','邓夫人苦痛哭存孝・采茶歌','关汉卿','元','元曲','yuanqu','','[]','你怎生便将人不瞅问？怎生来太平不用俺旧将军？半纸功名百战身，转头高冢卧麒麟。',190,'元曲/yuanqu.json','["你怎生便将人不瞅问？怎生来太平不用俺旧将军？半纸功名百战身，转头高冢卧麒麟。", "（刘夫人云）媳妇儿，你在家中；我和孩儿两个见你阿妈，白那两个丑生的谎去来！（正旦云）阿者休着存孝去；到那里有康君立、李存信，枉送了存孝的性命也！（刘夫人云）孩儿，你放心！这句话到头来要个归着，要个下落处。", "孩儿，你在家中，我领存孝去，则有个主意也。", "（李存孝云）我这一去别辩个虚实，邓夫人放心也！（正旦唱）。"]'),
('yuanqu-2377','邓夫人苦痛哭存孝・尾声','关汉卿','元','元曲','yuanqu','','[]','到那里着俺这刘夫人扑散了心头闷；不恁的呵！着俺这李父亲怎消磨了腹内嗔！别辩个假共真，全凭着这福神，并除了那祸根。',118,'元曲/yuanqu.json','["到那里着俺这刘夫人扑散了心头闷；不恁的呵！着俺这李父亲怎消磨了腹内嗔！别辩个假共真，全凭着这福神，并除了那祸根。", "你把那康君立、李存信，用着你那打大虫的拳头着一顿！想着那厮坑人来陷人，直打的那厮心肯意肯，可与你那争潞州冤仇证了本。", "（下）。"]'),
('yuanqu-2378','邓夫人苦痛哭存孝・中吕/粉蝶儿','关汉卿','元','元曲','yuanqu','','[]','颇奈这两个奸邪，看承做当职忠烈，想俺那无正事好酒的爹爹！他两个似虺蛇，如蝮蝎，心肠乖劣。',61,'元曲/yuanqu.json','["颇奈这两个奸邪，看承做当职忠烈，想俺那无正事好酒的爹爹！他两个似虺蛇，如蝮蝎，心肠乖劣。", "我呸呸的走似风车，不付能盼到宅舍。"]'),
('yuanqu-2379','邓夫人苦痛哭存孝・醉春风','关汉卿','元','元曲','yuanqu','','[]','一托气走将来，两只脚不暂歇；从头-一对阿者，我这里便说、说。',53,'元曲/yuanqu.json','["一托气走将来，两只脚不暂歇；从头-一对阿者，我这里便说、说。", "是做的泼水难收，至死也无对，今日个一桩也不借。"]'),
('yuanqu-2380','邓夫人苦痛哭存孝・上小楼','关汉卿','元','元曲','yuanqu','','[]','做儿的会做儿，做爷的会做爷，子父每无一个差迟，生各札的义断恩绝！阿妈那里紧当者，紧拦者，不着疼热。',68,'元曲/yuanqu.json','["做儿的会做儿，做爷的会做爷，子父每无一个差迟，生各札的义断恩绝！阿妈那里紧当者，紧拦者，不着疼热。", "他道是：\"你这姓安的怎做李家枝叶！\"。"]'),
('yuanqu-2381','邓夫人苦痛哭存孝・十二月','关汉卿','元','元曲','yuanqu','','[]','则您那康君立哏绝，则您那李存信似蝎蜇；可端的凭着他劣缺，端的是今古皆绝。',53,'元曲/yuanqu.json','["则您那康君立哏绝，则您那李存信似蝎蜇；可端的凭着他劣缺，端的是今古皆绝。", "枉了他那眠霜卧雪，阿妈他水性随邪。"]'),
('yuanqu-2382','邓夫人苦痛哭存孝・尧民歌','关汉卿','元','元曲','yuanqu','','[]','他把一条紫金梁生砍做两三截，阿者休波，是他便那里每分说！想着十八骑长安城内逞豪杰，今日个则落的足律律的旋风踅，我可便伤也波嗟。',209,'元曲/yuanqu.json','["他把一条紫金梁生砍做两三截，阿者休波，是他便那里每分说！想着十八骑长安城内逞豪杰，今日个则落的足律律的旋风踅，我可便伤也波嗟。", "将存孝见时节，阿者，则除是水底下捞明月！（刘夫人云）小番，你要说来又不说，可是为甚么来？（莽古歹云）李存信、康君立的言语，将存孝五车裂死了也！(刘夫人云)苦死的儿也！（莽古歹云）他临死时，将存孝棍棒临身，毁骂了千言万语，眼见的命掩黄泉。", "（刘夫人云）存孝儿衔冤负屈，孩儿怎生死了来？（正旦唱）。"]'),
('yuanqu-2383','邓夫人苦痛哭存孝・耍孩儿','关汉卿','元','元曲','yuanqu','','[]','则听的喝一声马下如雷烈，恰便似鹘打寒鸠哏绝。',96,'元曲/yuanqu.json','["则听的喝一声马下如雷烈，恰便似鹘打寒鸠哏绝。", "那两个快走向前来，那存孝待分说怎的分说？一个指着嘴缝连骂到有三十句，一个扶着软肋里扑扑扑的撞到五六靴。", "委实的难割舍，将存孝五车裂坏，霎时间七段八节。"]'),
('yuanqu-2384','邓夫人苦痛哭存孝・三煞','关汉卿','元','元曲','yuanqu','','[]','又不曾取罪名，又不曾点纸节；可是他前推后拥强牵拽。',70,'元曲/yuanqu.json','["又不曾取罪名，又不曾点纸节；可是他前推后拥强牵拽。", "军兵铁桶周围闹，棍棒麻林前后遮，扑碌碌推到法场也。", "称了那两个贼汉的心愿，屈杀了一个英杰！。"]'),
('yuanqu-2385','邓夫人苦痛哭存孝・二煞','关汉卿','元','元曲','yuanqu','','[]','我也曾把一个邓天王来旗下斩，我也曾把孟截海马上挟，我也曾将大虫打的流鲜血，我也曾双挝打杀千员将。',120,'元曲/yuanqu.json','["我也曾把一个邓天王来旗下斩，我也曾把孟截海马上挟，我也曾将大虫打的流鲜血，我也曾双挝打杀千员将。", "今日九牛力，挡不的五辆车五下里把身躯拽。", "将军死的苦痛，见了的那一个不伤嗟！（刘夫人云）五辆车，五五二十五头牛，一齐的拽，存孝怎生者？（正旦唱）。"]'),
('yuanqu-2386','邓夫人苦痛哭存孝・七兄弟','关汉卿','元','元曲','yuanqu','','[]','你兀的据着，枉了见功劳。',39,'元曲/yuanqu.json','["你兀的据着，枉了见功劳。", "沉默默两柄燕挝落，骨剌剌杂彩绣旗摇，扑冬冬画鼓征鼙操。"]'),
('yuanqu-2387','邓夫人苦痛哭存孝・梅花酒','关汉卿','元','元曲','yuanqu','','[]','你戴一顶虎磕脑，马跨着黄骠，箭插着钢凿，弓控着花梢。',60,'元曲/yuanqu.json','["你戴一顶虎磕脑，马跨着黄骠，箭插着钢凿，弓控着花梢。", "经了些地寒毡帐冷，杀气阵云高。", "我这里猛觑了，则被你痛杀我也李存孝！。"]'),
('yuanqu-2388','邓夫人苦痛哭存孝・收江南','关汉卿','元','元曲','yuanqu','','[]','呀，可怎生帐前空挂着虎皮袍？枉了你忘生舍死立唐朝！枉了你横枪纵马过溪桥！兀的是下梢，枉了你一十八骑破黄巢！。',54,'元曲/yuanqu.json','["呀，可怎生帐前空挂着虎皮袍？枉了你忘生舍死立唐朝！枉了你横枪纵马过溪桥！兀的是下梢，枉了你一十八骑破黄巢！。"]'),
('yuanqu-2389','邓夫人苦痛哭存孝・沽美酒','关汉卿','元','元曲','yuanqu','','[]','康君立你自道，李存信祸来到。',41,'元曲/yuanqu.json','["康君立你自道，李存信祸来到。", "把存孝赚入法场屈送了，摔碎了我浑家大小，任究竟罪难逃。"]'),
('yuanqu-2390','邓夫人苦痛哭存孝・太平令','关汉卿','元','元曲','yuanqu','','[]','也是你争弱，拿住你该剐该敲！聚集的人员好闹，准备车马绳索，把这厮绑了，五车裂了，可与俺李存孝一还一报！。',52,'元曲/yuanqu.json','["也是你争弱，拿住你该剐该敲！聚集的人员好闹，准备车马绳索，把这厮绑了，五车裂了，可与俺李存孝一还一报！。"]'),
('yuanqu-2391','刘玄德独赴襄阳会・仙吕/点绛唇','高文秀','元','元曲','yuanqu','','[]','想当日汉祖开基，五年登帝，无虞日。',31,'元曲/yuanqu.json','["想当日汉祖开基，五年登帝，无虞日。", "端拱垂衣，则他那肱股能经济。"]'),
('yuanqu-2392','刘玄德独赴襄阳会・混江龙','高文秀','元','元曲','yuanqu','','[]','中兴后诸侯强力，风俗教化渐凌夷。',97,'元曲/yuanqu.json','["中兴后诸侯强力，风俗教化渐凌夷。", "将一个董卓剿灭，将一个吕布遭危。", "一头的袁绍兴兵行跋扈。", "可又早曹公霸道骋奸回。", "现如今民殷国富可便说孙权，端的是这宽仁厚德谈刘备。", "手下有二将军关羽，和他这三兄弟张飞。"]'),
('yuanqu-2393','刘玄德独赴襄阳会・油葫芦','高文秀','元','元曲','yuanqu','','[]','我这里叉手躬身施罢礼，数十年远间离。',198,'元曲/yuanqu.json','["我这里叉手躬身施罢礼，数十年远间离。", "(刘备云)吾侄，自从与曹操交锋，数年不见。", "(正末唱)都则为苦征恶战各东西。", "(刘备云)刘琦，我与你父亲都是汉之苗裔。", "(正末唱)俺须是分形连气同亲戚，叔父是先朝景帝亲苗裔。", "(刘备云)哥哥，你兄弟非为酒食而来，城池当紧。", "(正末唱)叔父要借郡州，待将那士马集。", "(刘备云)吾侄，奈您叔父身无尺寸之地，怎的与曹操交战？(正末唱)叔父道时间无尺寸安身地，普天下尽都是汉华夷。"]'),
('yuanqu-2394','刘玄德独赴襄阳会・天下乐','高文秀','元','元曲','yuanqu','','[]','常言道人急偎亲我稍知，(刘表云)玄德公，新野、樊城，你弟兄权且居止。',138,'元曲/yuanqu.json','["常言道人急偎亲我稍知，(刘表云)玄德公，新野、樊城，你弟兄权且居止。", "(刘备云)谢了哥哥。", "(正末唱)将新野樊也波城，权驻跸。", "(刘表云)玄德公，在于新野、樊城，操兵练士，积草屯粮，复兴汉世，有何不可？(正末唱)若是那重磨日月扶社稷，平定海内安，更和那烽燧息。", "恁时节叙亲亲，行大礼。"]'),
('yuanqu-2395','刘玄德独赴襄阳会・那吒令','高文秀','元','元曲','yuanqu','','[]','广设着珍羞和美味，高捧着琼浆和这玉醴，密排着歌儿和这舞姬。',211,'元曲/yuanqu.json','["广设着珍羞和美味，高捧着琼浆和这玉醴，密排着歌儿和这舞姬。", "不弱如公孙弘的东阁筵，须不是楚项羽的鸿门会，尽开怀满饮金杯。", "(刘备云)吾兄，您兄弟饮不的了也。", "(刘表做将牌印让与刘备科，云)玄德公，吾今年迈，我也掌把不住这荆襄九郡，将这荆襄九郡牌印，让与玄德公掌管，你意下若何？(刘备云)吾兄，刘备焉敢受荆州牌印！现有两个公子，当以承袭荆州牧之职。", "(刘琮云)父亲，饮酒则饮酒。", "这牌印，叔父是个知理的人，他岂肯受这牌印？(正末唱)。"]'),
('yuanqu-2396','刘玄德独赴襄阳会・鹊踏枝','高文秀','元','元曲','yuanqu','','[]','将牌印捧到尊席，多谦让苦辞推。',90,'元曲/yuanqu.json','["将牌印捧到尊席，多谦让苦辞推。", "情愿将九郡荆襄，教叔父掌握操持。", "(刘备云)吾兄，这的是父祖列土分茅之地，子孙堪可而守。", "(正末唱)你道是父祖业传留与子息，岂不闻尧舜可便天下贤圣承袭？。"]'),
('yuanqu-2397','刘玄德独赴襄阳会・寄生草','高文秀','元','元曲','yuanqu','','[]','叔父那里休夸奖，莫厮推。',93,'元曲/yuanqu.json','["叔父那里休夸奖，莫厮推。", "你道我忠君孝父行仁义，你道我驱兵领将多谋智，又道我齐家治国能兴利。", "(刘备云)论大公子有经济之才，颜闵之德。", "(正末唱)怎有那经天纶地栋梁之才？则是个粪墙朽木儿曹辈。"]'),
('yuanqu-2398','刘玄德独赴襄阳会・醉扶归','高文秀','元','元曲','yuanqu','','[]','叔父，这好枣知滋味，(刘备云)够了也。',172,'元曲/yuanqu.json','["叔父，这好枣知滋味，(刘备云)够了也。", "(正末唱)好桃也可堪食，(刘备云)我吃不的也。", "(正末唱)这醒酒清凉更好梨。", "(刘备醒科，云)吃不的了也。", "(正末唱)这果木本是同根蒂，他伤枝叶擘了面皮。", "(带云)叔父醉了，不解其意。", "(做摇醒科，云)叔父，你看这桌子上，好枣，好桃，好梨也。", "(刘备醒科，云)是、是、是，我知道了也。", "(正末唱)你怎生不解我这其中意？。"]'),
('yuanqu-2399','刘玄德独赴襄阳会・金盏儿','高文秀','元','元曲','yuanqu','','[]','你快离席，莫惊疑。',64,'元曲/yuanqu.json','["你快离席，莫惊疑。", "我这里吐实情泄漏了春消息，疾牵你那战马换征衣，则怕你意忙船去慢，心急马行迟。", "休寻入地窟，则要你寻觅他那上天梯。"]'),
('yuanqu-2400','刘玄德独赴襄阳会・尾声','高文秀','元','元曲','yuanqu','','[]','痛离别，愁分袂，我和你再相见知道是何年甚日？望新野樊城去路疾，我则要你善加兵紧护城池，则要你用心机将那士马操习，准备着那灭寇兴刘显气势。',100,'元曲/yuanqu.json','["痛离别，愁分袂，我和你再相见知道是何年甚日？望新野樊城去路疾，我则要你善加兵紧护城池，则要你用心机将那士马操习，准备着那灭寇兴刘显气势。", "那其间这干戈定息，我着他四方宁谧，恁时节风云文武拜丹墀。", "(下)。"]'),
('yuanqu-2401','刘玄德独赴襄阳会・紫花儿序','高文秀','元','元曲','yuanqu','','[]','则愿的驯良纯善，怕的是踢跳湾奔，使不着嘶喊咆哮。',79,'元曲/yuanqu.json','["则愿的驯良纯善，怕的是踢跳湾奔，使不着嘶喊咆哮。", "马乃是将之司命，盗了马步骤难熬。", "量度，又不是穴隙逾墙做贼盗，蒙差遣怎敢违拗！你正是人急偎亲，他可甚善与人交？。"]'),
('yuanqu-2402','刘玄德独赴襄阳会・金蕉叶','高文秀','元','元曲','yuanqu','','[]','恰拌上一槽料草，喂饲的十分来饱。',33,'元曲/yuanqu.json','["恰拌上一槽料草，喂饲的十分来饱。", "悄声儿潜踪蹑脚，我解放了缰绳绊索。"]'),
('yuanqu-2403','刘玄德独赴襄阳会・幺篇','高文秀','元','元曲','yuanqu','','[]','你论亲戚是汉祖根苗，论昆仲和刘表知交。',43,'元曲/yuanqu.json','["你论亲戚是汉祖根苗，论昆仲和刘表知交。", "破黄巾立大功，诛董卓建功劳，是和非心上人自评跋。"]'),
('yuanqu-2404','刘玄德独赴襄阳会・调笑令','高文秀','元','元曲','yuanqu','','[]','不索窨约，你便快奔逃，呀，再休说他乡遇故交。',79,'元曲/yuanqu.json','["不索窨约，你便快奔逃，呀，再休说他乡遇故交。", "(刘备云)将军，此路往何处去？(正末唱)遥望着新野樊城道，似飞星彻夜连霄。", "你官道上莫行小路儿抄，岂辞劳水远山遥！。"]'),
('yuanqu-2405','刘玄德独赴襄阳会・耍厮儿','高文秀','元','元曲','yuanqu','','[]','遥望见绿茸茸莎茵芳草，翻滚滚雪浪银涛。',41,'元曲/yuanqu.json','["遥望见绿茸茸莎茵芳草，翻滚滚雪浪银涛。", "檀溪大堤水围绕，无舟渡、共长桥，险慌煞英豪。"]'),
('yuanqu-2406','刘玄德独赴襄阳会・圣药王','高文秀','元','元曲','yuanqu','','[]','他将那天地祈，咒愿祷，欠彪躯整顿了锦征袍。',68,'元曲/yuanqu.json','["他将那天地祈，咒愿祷，欠彪躯整顿了锦征袍。", "半玉带兜，金镫挑，三山股摔破了紫藤梢。", "(刘备做跳过檀溪科)(正末唱)则一跳恰便似飞彩凤走潜蛟。"]'),
('yuanqu-2407','刘玄德独赴襄阳会・尾声','高文秀','元','元曲','yuanqu','','[]','你将那忠良损害合天道，他一骑马不剌剌风驱电扫。',46,'元曲/yuanqu.json','["你将那忠良损害合天道，他一骑马不剌剌风驱电扫。", "他得性命且逃灾，将我这泼残生断送了。", "(同下)。"]'),
('yuanqu-2408','刘玄德独赴襄阳会・仙吕/赏花时','高文秀','元','元曲','yuanqu','','[]','我本待要养性修真避世尘，今日个厚礼卑辞征聘紧。',115,'元曲/yuanqu.json','["我本待要养性修真避世尘，今日个厚礼卑辞征聘紧。", "我则待奉甘旨侍萱亲，(赵云云)师父此一去，俺主公必然重用师父也。", "(正末唱)谁羡您高官极品？(卜儿云)孩儿也，用心者。", "(正末云)母亲，你放心也。", "(唱)你看我扶社稷可兀的立乾坤。", "(同下)。"]'),
('yuanqu-2409','刘玄德独赴襄阳会・中吕/粉蝶儿','高文秀','元','元曲','yuanqu','','[]','想当日楚汉争持，任贤能四方云会，扫群雄定乱除危。',68,'元曲/yuanqu.json','["想当日楚汉争持，任贤能四方云会，扫群雄定乱除危。", "投至得灭了强秦，除了壮楚，才把那生民普济。", "若不是汉三杰尽力扶持，怎能够展封疆肃清海内！。"]'),
('yuanqu-2410','刘玄德独赴襄阳会・醉春风','高文秀','元','元曲','yuanqu','','[]','韩元帅凭韬略定乾坤，萧丞相用机谋安社稷。',269,'元曲/yuanqu.json','["韩元帅凭韬略定乾坤，萧丞相用机谋安社稷。", "张子房运筹帷幄看兵书，将沛公扶立起、起。", "才能够汉室兴隆，子孙永享，保护着万兵千岁。", "(刘备云)方今时世，多有英雄豪杰，师父试说一遍咱。", "(正末云)主公，想如今英雄强霸，各据疆土。", "河北袁绍，淮南袁术，荆州刘表，江东孙权。", "许都曹操，统领百万之众，虎视天下诸侯。", "主公乃汉之宗亲，争奈兵微将寡，咱且按兵自守，访谒贤俊，广结英豪，久后还有辅佐主公的人物出来哩。", "(刘备云)师父，想刘备被曹操攻破徐州，今经数载，身无所居之地。", "今日刘备幸遇尊师之面，请将师父来拜为元戎，觑曹操易如翻掌，克日而破，指日成功。", "(正末唱)。"]'),
('yuanqu-2411','刘玄德独赴襄阳会・上小楼','高文秀','元','元曲','yuanqu','','[]','他倚仗着兵雄将威，你看我便谋为定计。',88,'元曲/yuanqu.json','["他倚仗着兵雄将威，你看我便谋为定计。", "则要你便敢战当先，手内长枪，跨下的乌雅。", "则要你显气势，敢拒敌，施逞你那武艺，(带云)这一去，则要你小心在意者。", "(唱)将他那败残军片时间杀退。"]'),
('yuanqu-2412','刘玄德独赴襄阳会・幺篇','高文秀','元','元曲','yuanqu','','[]','左哨兵编排整齐，则要您公心用意。',64,'元曲/yuanqu.json','["左哨兵编排整齐，则要您公心用意。", "你与我便领将埋伏，远观输赢，近看虚实。", "你这三将的威，各自得、施谋用智，你与我便统三军紧冲他左肋。"]'),
('yuanqu-2413','刘玄德独赴襄阳会・白鹤子','高文秀','元','元曲','yuanqu','','[]','你行右哨排队伍，战曹将逞雄威。',206,'元曲/yuanqu.json','["你行右哨排队伍，战曹将逞雄威。", "则你大杆刀带肩钐，则你这宣花斧着他天灵碎。", "(巩固云)得令。", "俺弟兄二人，出的这帅府门来，与曹仁交锋走一遭去。", "临军对阵把名扬，挟人拿将我为强。", "敌兵一见魂先丧，勇敢交锋战一场。", "(同上)(正末云)唤将赵云来。", "(赵云云)师父，唤赵云那里使用？(正末云)赵云，我拨与你一千军，你先去放过曹兵来；你将许都路上埋伏了你那一千军，等着张飞先锋杀退曹兵，你在前路上截住曹兵，可则要你成功而回也。", "(唱)。"]'),
('yuanqu-2414','刘玄德独赴襄阳会・十二月','高文秀','元','元曲','yuanqu','','[]','我将这三军可便指挥，则你这众将要心齐。',54,'元曲/yuanqu.json','["我将这三军可便指挥，则你这众将要心齐。", "全凭着这先锋翼德，端的他武艺为魁。", "左右哨埋伏着准备，差你个赵子龙追袭。"]'),
('yuanqu-2415','刘玄德独赴襄阳会・尧民歌','高文秀','元','元曲','yuanqu','','[]','呀哎，你个云长英勇有谁及！你与我领将驱兵列旌旗，将千员勇猛似云齐。',70,'元曲/yuanqu.json','["呀哎，你个云长英勇有谁及！你与我领将驱兵列旌旗，将千员勇猛似云齐。", "我这里炮响连天若轰雷，杀的他输也波亏，身无片甲回，他可便岂知俺这神仙计！。"]'),
('yuanqu-2416','刘玄德独赴襄阳会・尾声','高文秀','元','元曲','yuanqu','','[]','到来日遇交锋催战鼓，助军威发喊齐。',48,'元曲/yuanqu.json','["到来日遇交锋催战鼓，助军威发喊齐。", "你看我则一阵着他那十万曹兵退，恁时节得胜收军那一场喜。", "(下)。"]'),
('yuanqu-2417','刘玄德独赴襄阳会・仙吕/赏花时','高文秀','元','元曲','yuanqu','','[]','他不合剔蝎撩蜂寻斗争，我这里布网张罗打大虫。',63,'元曲/yuanqu.json','["他不合剔蝎撩蜂寻斗争，我这里布网张罗打大虫。", "俺这里军士猛，将英雄，我将他生擒在阵中，这的是我初交战可兀的建头功！(众将同下)。"]'),
('yuanqu-2418','刘玄德独赴襄阳会・双调/新水令','高文秀','元','元曲','yuanqu','','[]','统堂堂军校出襄阳，胜军回凯歌齐唱。',47,'元曲/yuanqu.json','["统堂堂军校出襄阳，胜军回凯歌齐唱。", "旗摇笼日色，鼓凯撼空苍。", "明晃晃剑戟刀枪，杀的那败残将五魂丧。"]'),
('yuanqu-2419','刘玄德独赴襄阳会・雁儿落','高文秀','元','元曲','yuanqu','','[]','他那里领雄兵临战场，俺这里先差个先锋将。',38,'元曲/yuanqu.json','["他那里领雄兵临战场，俺这里先差个先锋将。", "凭着你长枪无对手，更和那乌马难遮当。"]'),
('yuanqu-2420','刘玄德独赴襄阳会・得胜令','高文秀','元','元曲','yuanqu','','[]','呀，他那里临阵的是曹章，俺这里左右哨暗埋藏。',73,'元曲/yuanqu.json','["呀，他那里临阵的是曹章，俺这里左右哨暗埋藏。", "那曹兵大败输亏走，赵子龙手持着牙角枪。", "他无路去潜藏，望着那山谷深林撞。", "正遇着云长，恰便似英雄的楚霸王。"]'),
('yuanqu-2421','刘玄德独赴襄阳会・沽美酒','高文秀','元','元曲','yuanqu','','[]','今日个重封官，恩赐赏；贺开宴，饮琼浆。',45,'元曲/yuanqu.json','["今日个重封官，恩赐赏；贺开宴，饮琼浆。", "则俺这将帅威风显气象，一个个英雄胆量，能挑战汉云长。"]'),
('yuanqu-2422','刘玄德独赴襄阳会・太平令','高文秀','元','元曲','yuanqu','','[]','赵子龙驱兵领将，张车骑乌马长枪。',51,'元曲/yuanqu.json','["赵子龙驱兵领将，张车骑乌马长枪。", "将士勇人人雄壮，扫群雄西除东荡。", "今日个宴亭，众将受赏，万万载皇图兴旺。"]'),
('yuanqu-2423','雁门关存孝打虎・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','止不过漠漠平沙际碧天，又不比夕贬潮阳路八千，我忙传着一纸圣人宣。',93,'元曲/yuanqu.json','["止不过漠漠平沙际碧天，又不比夕贬潮阳路八千，我忙传着一纸圣人宣。", "(殿头官云)则是路途较远难行，须要小心在意者。", "(正末唱)避不的山遥路远，(云)大人放心。", "(唱)我可也无明夜到居延。", "(下)。"]'),
('yuanqu-2424','雁门关存孝打虎・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','止不过漠漠平沙际碧天，又不比夕贬潮阳路八千，我忙传着一纸圣人宣。',93,'元曲/yuanqu.json','["止不过漠漠平沙际碧天，又不比夕贬潮阳路八千，我忙传着一纸圣人宣。", "(殿头官云)则是路途较远难行，须要小心在意者。", "(正末唱)避不的山遥路远，(云)大人放心。", "(唱)我可也无明夜到居延。", "(下)。"]'),
('yuanqu-2425','雁门关存孝打虎・隔尾','无名氏','元','元曲','yuanqu','','[]','我则见八而威的猛兽偎深涧，他可早一跳身番飞过浅山，把我这贪水食的群羊尽哄散。',64,'元曲/yuanqu.json','["我则见八而威的猛兽偎深涧，他可早一跳身番飞过浅山，把我这贪水食的群羊尽哄散。", "这厮将咱恼犯。", "我这里将皮裘紧拴，大踏步望前舍死的赶。"]'),
('yuanqu-2426','雁门关存孝打虎・牧羊关','无名氏','元','元曲','yuanqu','','[]','血鼻凹扑碌碌连打十余下，死尸骸骨鲁鲁滚到四五番，恨不的莽拳头打挫牙关。',89,'元曲/yuanqu.json','["血鼻凹扑碌碌连打十余下，死尸骸骨鲁鲁滚到四五番，恨不的莽拳头打挫牙关。", "八面威气象全无，十石力身躯软瘫。", "泥污了数尺金椽尾，血模糊几道剪刀斑。", "舒不出钢钩似十八爪，闪不开金铃也一对眼。"]'),
('yuanqu-2427','雁门关存孝打虎・贺新郎','无名氏','元','元曲','yuanqu','','[]','小人本家住在雁门关，(李克用云)你做甚买卖营生？(正末唱)与人家牧牛羊，(李克用云)你和他同财合本？(正末唱)则是苟图些衣饭。',344,'元曲/yuanqu.json','["小人本家住在雁门关，(李克用云)你做甚买卖营生？(正末唱)与人家牧牛羊，(李克用云)你和他同财合本？(正末唱)则是苟图些衣饭。", "(李克用云)你有甚么亲眷？(正末唱)没亲眷独自个单身汉。", "(李克用云)你姓甚名谁？(正末唱)名敬思小人姓安。", "(李克用云)你十八般武艺，那一般精熟？(正末唱)我学的十八般武艺熟闲。", "(李克用云)你既然学成十八般武艺，见如今黄巢作乱，纵横天下，你肯去破黄巢去么？(正末唱)不是这习兵书的好汉少，赤紧的养剑客的主人难。", "(李克用云)看了你威风凛凛，状貌堂堂，何不进取功名？(正末唱)觑了这穷身泼命难把功名干，(李克用云)你既有打虎之威，取功名有何难哉。", "(正末唱)端的是入山擒虎易，叉手告人难。", "(李克用云)兀那壮士，既学成十八般武艺，何不进取功名，在此受这等艰难？(正末唱)。"]'),
('yuanqu-2428','雁门关存孝打虎・哭皇天','无名氏','元','元曲','yuanqu','','[]','只为俺衣饭难迭办，不得已在他人眉睫间。',197,'元曲/yuanqu.json','["只为俺衣饭难迭办，不得已在他人眉睫间。", "(李克用云)你在那里居住。", "(正末唱)则这安敬思在飞虎峪，(李克用云)你为何在此受苦？(正末云)大人，不争小人一个受苦，上辈古人，多有受窘的哩。", "(李克用云)可是那几个古人受窘？(正末唱)便似班定远在玉门关。", "空学的兵书战策，争柰运拙时艰。", "淹留在此去住无门，便似苏武般陷番。", "打虎的壮士，牧羊的家奴，似梁园采木，把我做凡花、凡花-例看。", "你觑的黄巢利害，我看似等闲。"]'),
('yuanqu-2429','雁门关存孝打虎・乌夜啼','无名氏','元','元曲','yuanqu','','[]','也不要锦衣绣袄军十万，我手里要恢复你大唐江山。',93,'元曲/yuanqu.json','["也不要锦衣绣袄军十万，我手里要恢复你大唐江山。", "可怜见荒荒百姓遭涂炭，见如今地乱天番，我直教国泰民安。", "不能勾开疆展土笑谈间，算甚么顶天立地男儿汉。", "枉了你厮听使，相调慢，花根本艳，虎体元斑。"]'),
('yuanqu-2430','雁门关存孝打虎・二煞','无名氏','元','元曲','yuanqu','','[]','凭着我忠心扫荡烟尘散，捉将手扶持社稷安。',74,'元曲/yuanqu.json','["凭着我忠心扫荡烟尘散，捉将手扶持社稷安。", "华严大战那其问，上的那骏马雕鞍。", "恁般儿虽不似跨海征辽那汉，黄金铠不须擐，凭着背上雕弓月样弯，我则要定了天山。"]'),
('yuanqu-2431','雁门关存孝打虎・越调/斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','你看我对垒交锋，相持厮杀。',61,'元曲/yuanqu.json','["你看我对垒交锋，相持厮杀。", "则听的呐喊摇旗，天摧地塌。", "则我这耀武扬威，披袍擐甲。", "非小可，不要耍。", "则这八水三川，屯着千军万马。"]'),
('yuanqu-2432','雁门关存孝打虎・金蕉叶','无名氏','元','元曲','yuanqu','','[]','我则见黑黯黯云遮日华，昏邓邓风吹塞沙。',54,'元曲/yuanqu.json','["我则见黑黯黯云遮日华，昏邓邓风吹塞沙。", "见一人雄纠纠被袍擐甲，嗔忿忿横枪跃马。", "(二净云)来将何人？(正末唱)。"]'),
('yuanqu-2433','雁门关存孝打虎・调笑令','无名氏','元','元曲','yuanqu','','[]','不索你搦咱，更怕你会征伐，(二净云)来者何人？通名道姓。',165,'元曲/yuanqu.json','["不索你搦咱，更怕你会征伐，(二净云)来者何人？通名道姓。", "(正末唱)你存孝爹爹出阵咱。", "(云)你是何人？(二净云)吾乃黄巢手下大将张归霸、张归厚。", "你那牧羊子，早早下马来受死。", "(正末唱)原来是黄巢手下张归霸，嗔道这般气高胆大。", "向前来二人挑战咱。", "不索你冬冬战鼓频挝。", "(二净云)颇柰牧羊子无理，你敢与我决战三合么？(正末云)交马来。", "(唱)。"]'),
('yuanqu-2434','雁门关存孝打虎・秃厮儿','无名氏','元','元曲','yuanqu','','[]','鞍上将威风转加，坐下马筋力堪夸。',70,'元曲/yuanqu.json','["鞍上将威风转加，坐下马筋力堪夸。", "我则见纱灯儿般转到十数匝，我看你怎生收煞？(二净云)我儿李存孝，早早下马罢。", "(正末云)这厮好无理也。", "(唱)。"]'),
('yuanqu-2435','雁门关存孝打虎・圣药王','无名氏','元','元曲','yuanqu','','[]','叵耐他，小觑咱，匣中宝剑定中华。',44,'元曲/yuanqu.json','["叵耐他，小觑咱，匣中宝剑定中华。", "凭着我坐下马，手中挝，李存孝非是自矜夸，我扶立起大唐家。"]'),
('yuanqu-2436','雁门关存孝打虎・雪里梅','无名氏','元','元曲','yuanqu','','[]','猛然间入京华，谁敢道当阑咱？则这京城中可是俺大唐天下，不刺刺忙催战马。',206,'元曲/yuanqu.json','["猛然间入京华，谁敢道当阑咱？则这京城中可是俺大唐天下，不刺刺忙催战马。", "(云)进的这城来，大小三军，摆开阵势，看有甚么人来。", "(黄圭上，云)某乃御弟黄圭是也。", "叵耐大唐家去沙陀取将李克用来，他手下新收的一个牧羊子，叫做存孝，来杀俺二三十阵。", "今杀到长安城里，无人敢当，某亲身与他交战一遭去。", "兀那牧羊子，来与某交手咱。", "(正末云)这厮好无礼也，走将来交马便战，不要看这厮披挂，到骑着一匹好马。", "大小三军，看我拿那厮来。", "(唱)。"]'),
('yuanqu-2437','雁门关存孝打虎・古竹马','无名氏','元','元曲','yuanqu','','[]','也不索征鞍轻压，征靴微抹，征马宛紧跨，不刺刺直赶到海角天涯。',80,'元曲/yuanqu.json','["也不索征鞍轻压，征靴微抹，征马宛紧跨，不刺刺直赶到海角天涯。", "生熬的两事家，心惊胆战，力困神乏。", "见他，见他，战战兢兢，怯怯乔乔，黄甘甘容颜如蜡渣，全不见武艺熟滑。"]'),
('yuanqu-2438','雁门关存孝打虎・幺','无名氏','元','元曲','yuanqu','','[]','我从来劣性难拿，正恼犯如何收煞。',64,'元曲/yuanqu.json','["我从来劣性难拿，正恼犯如何收煞。", "见咱，赶他，撞阵冲军，倒戈弃甲。", "纵辔加鞭催战马，恨不的剪断紫稍，踏斜宝镫，顿宽玉勒，摆损金算刂。"]'),
('yuanqu-2439','雁门关存孝打虎・尾声','无名氏','元','元曲','yuanqu','','[]','把那仓廒府库随风化，不落根椽片瓦。',40,'元曲/yuanqu.json','["把那仓廒府库随风化，不落根椽片瓦。", "这勤王存孝得功回，教这反国黄巢没乱杀。", "(下)。"]'),
('yuanqu-2440','雁门关存孝打虎・黄钟/醉花阴','无名氏','元','元曲','yuanqu','','[]','一托气直奔数十里，遍体汗浑如水洗。',36,'元曲/yuanqu.json','["一托气直奔数十里，遍体汗浑如水洗。", "非是我说兵机，若论相持，大会垓应难比。"]'),
('yuanqu-2441','雁门关存孝打虎・喜迁莺','无名氏','元','元曲','yuanqu','','[]','火速的上阶基，一径的搀先队，(云)报、报、报，喏。',196,'元曲/yuanqu.json','["火速的上阶基，一径的搀先队，(云)报、报、报，喏。", "(唱)来报喜。", "(李克用云)好探子也，从那阵面上来，喜色旺气。", "一张弓弯秋月，两枝箭插寒星，三尺剑挂小貂裘，四方报喜问探子，五花营中来往有如撺梭，六队军中上下有如蛟龙，七尺躯肩担令字旗，八角红缨桶子帽，久久等待许多时，实实数说军情事。", "(探子唱)当日个华严川内，众诸侯聚会云集。", "端的，阿谁不会，尽是些使争好斗显气势。", "一个个挟人捉将，一个个挝鼓夺旗。"]'),
('yuanqu-2442','雁门关存孝打虎・出队子','无名氏','元','元曲','yuanqu','','[]','齐臻臻军卒摆列，韵悠悠画角吹。',42,'元曲/yuanqu.json','["齐臻臻军卒摆列，韵悠悠画角吹。", "扑冬冬振地凯征鼙，赤力力遮天磨绣旗，不剌刺追风战马嘶。"]'),
('yuanqu-2443','雁门关存孝打虎・乱地风','无名氏','元','元曲','yuanqu','','[]','则见张归霸军前猛叫起，咱两个比试高低。',124,'元曲/yuanqu.json','["则见张归霸军前猛叫起，咱两个比试高低。", "李存孝怒从心上起，呀，可早变了容仪，倒竖神眉。", "踏宝镫滴溜扑跳上乌骓，吼风雷吐虹霓，一怒千斤力。", "拚性命，厮对敌，手拿定两柄挝槌。", "(李克用云)俺存孝与贼将交马十数合，那家赢？那家输？你喘息定，再说一遍。", "(探子唱)。"]'),
('yuanqu-2444','雁门关存孝打虎・四门子','无名氏','元','元曲','yuanqu','','[]','恶口音欠口音欠撞入垓心内，张归霸走似飞，料应他武艺敌不的。',72,'元曲/yuanqu.json','["恶口音欠口音欠撞入垓心内，张归霸走似飞，料应他武艺敌不的。", "打征马宛捻玉勒，畅好是慌，好是急。", "飞虎将早来望后追，畅好是慌，好是急，误撞入长安市里。"]'),
('yuanqu-2445','雁门关存孝打虎・古水仙子','无名氏','元','元曲','yuanqu','','[]','赶来到灞河里，见一只舡来有似飞。',74,'元曲/yuanqu.json','["赶来到灞河里，见一只舡来有似飞。", "摇橹的水手又心忙，把柁的梢公胆碎，恨不的两下里纳降旗。", "一齐的马前忙跪膝，告爹爹委实敌不的，来、来、来，似小鬼见钟馗。"]'),
('yuanqu-2446','雁门关存孝打虎・寨儿令','无名氏','元','元曲','yuanqu','','[]','端的，端的，全无半点疏失，又不见敌军武艺低。',75,'元曲/yuanqu.json','["端的，端的，全无半点疏失，又不见敌军武艺低。", "虽存孝，善兵机，也托赖着当今帝。", "(李克用云)好探子也，与你两只羊，两瓶酒，十个免帖。", "回本营去。", "(探子唱)。"]'),
('yuanqu-2447','雁门关存孝打虎・尾','无名氏','元','元曲','yuanqu','','[]','到不得底，千寻浪头里。',32,'元曲/yuanqu.json','["到不得底，千寻浪头里。", "看时节显出些头盔，我则见尸堰断灞陵桥下水。"]'),
('yuanqu-2448','水斗调歌头','无名氏《张协状元》','元','元曲','yuanqu','','[]','韶华催白发，光影改朱容。',115,'元曲/yuanqu.json','["韶华催白发，光影改朱容。", "人生浮世，浑如萍梗逐西东。", "陌上争红紫，窗外莺啼燕语，花落满庭空。", "世态只如此，何用苦匆匆。", "但咱们，虽宦裔，总皆通。", "弹丝品竹，那堪咏月与嘲风。", "苦会插科使砌，何吝搽灰抹土，歌笑满堂中。", "一似长江千尺浪，别是一家风。"]'),
('yuanqu-2449','满庭芳','无名氏《张协状元》','元','元曲','yuanqu','','[]','暂息喧哗，略停笑语，试看别样门庭。',120,'元曲/yuanqu.json','["暂息喧哗，略停笑语，试看别样门庭。", "教坊格范，绯绿可仝声。", "酬酢词源诨砌，听谈论四座皆惊。", "浑不比，乍生后学，谩自逞虚名。", "《状元张叶传》，前回曾演，汝辈搬成。", "这番书会，要夺魁名。", "占断东瓯盛事，诸宫调唱出来因。", "厮罗响，贤门雅静，仔细说教听。", "(唱)。"]'),
('yuanqu-2450','凤时春','无名氏《张协状元》','元','元曲','yuanqu','','[]','张叶诗书遍历，困故乡功名未遂。',34,'元曲/yuanqu.json','["张叶诗书遍历，困故乡功名未遂。", "欲占春闱登科举，暂别爹娘，独自离乡里。"]'),
('yuanqu-2451','小重山','无名氏《张协状元》','元','元曲','yuanqu','','[]','"前时一梦断人肠，教我暗思量：平日不曾为宦旅，忧患怎生当？"。',31,'元曲/yuanqu.json','["\"前时一梦断人肠，教我暗思量：平日不曾为宦旅，忧患怎生当？\"。"]'),
('yuanqu-2452','浪淘沙','无名氏《张协状元》','元','元曲','yuanqu','','[]','迤逦离乡关。',36,'元曲/yuanqu.json','["迤逦离乡关。", "回首望家，白云直下把泪偷弹。", "极目荒郊无旅店，只听得流水潺潺。"]'),
('yuanqu-2453','绕池游','无名氏《张协状元》','元','元曲','yuanqu','','[]','张叶拜启："念是读书辈，往长安拟欲应举。',41,'元曲/yuanqu.json','["张叶拜启：\"念是读书辈，往长安拟欲应举。", "些少裹足，路途里欲得支费，望周全不须劫去。"]'),
('yuanqu-2454','烛影摇红/望江南/烛影摇红','无名氏《张协状元》','元','元曲','yuanqu','','[]','(生)暂籍轧色。',76,'元曲/yuanqu.json','["(生)暂籍轧色。", "(众)有。", "(生)罢！学个张状元似像。", "(众)谢了！(生)画堂悄最堪宴乐，绣帘垂隔断春风。", "波艳艳杯行泛绿，夜深深烛影摇戏。", "(众应)(生唱)。"]'),
('yuanqu-2455','粉蝶儿','无名氏《张协状元》','元','元曲','yuanqu','','[]','徐步花衢，只得回家，扣双亲看如何底。',53,'元曲/yuanqu.json','["徐步花衢，只得回家，扣双亲看如何底。", "(外作公出接)草堂中，听得鞋履响，是孩儿来至。", "你读书莫学，浪儿门一辈。"]'),
('yuanqu-2456','千秋岁','无名氏《张协状元》','元','元曲','yuanqu','','[]','论诗书，缓视微吟处，真个得趣。',15,'元曲/yuanqu.json','["论诗书，缓视微吟处，真个得趣。"]'),
('yuanqu-2457','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','我闻伊，夜来得一梦，你便说个详细。',72,'元曲/yuanqu.json','["我闻伊，夜来得一梦，你便说个详细。", "(生)两山之间，被一非虎擒扌追。", "(外)人之梦，不中信。", "且一面，装行李。", "(合)愿得身荣贵，管桃花浪暖，一跃云衢。"]'),
('yuanqu-2458','大圣乐','无名氏《张协状元》','元','元曲','yuanqu','','[]','村落无人要厮笑，这愁闷有谁知道。',36,'元曲/yuanqu.json','["村落无人要厮笑，这愁闷有谁知道。", "闲来徐步，桑麻径裹，独自烦恼。", "(又唱)。"]'),
('yuanqu-2459','叨叨令','无名氏《张协状元》','元','元曲','yuanqu','','[]','贫则虽贫，每恁地娇，这两眉儿扫。',81,'元曲/yuanqu.json','["贫则虽贫，每恁地娇，这两眉儿扫。", "有时暗忆妾爹娘，珠泪堕润湿芳容，甚人知道？妾又无人要。", "兼自执卓做人，除非是苦怀抱。", "妾又无倚靠。", "付分缘与人缉麻，夜间独自，宿在古庙。"]'),
('yuanqu-2460','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','几番焦躁，命直不好，埋冤知是几宵。',73,'元曲/yuanqu.json','["几番焦躁，命直不好，埋冤知是几宵。", "受千般愁闷，万种寂寥，虚度奴年少。", "每甘分粗衣布裙，寻思另般格调。", "若要奴家好，遇得一个意中人，共作结发，夫妻谐老。"]'),
('yuanqu-2461','西地锦','无名氏《张协状元》','元','元曲','yuanqu','','[]','见说道会听声，冠朝野达帝城。',29,'元曲/yuanqu.json','["见说道会听声，冠朝野达帝城。", "佳名是则闻久矣，有一梦说与听。"]'),
('yuanqu-2462','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','梦时节却未四更，此身两山上行。',30,'元曲/yuanqu.json','["梦时节却未四更，此身两山上行。", "瞥见个人如虎类，被它伤却股肱。"]'),
('yuanqu-2463','川鲍老','无名氏《张协状元》','元','元曲','yuanqu','','[]','君在两山，两山成出字。',87,'元曲/yuanqu.json','["君在两山，两山成出字。", "(末白)两个山是出字。", "(丑连唱)遇一人假虎衣。", "白虎算来，只在西方旺，西方却是川地。", "君出去向北尽得，不免有些，跌扑脓血疾。", "千里外豹变，一时掀焰，归来贺喜。"]'),
('yuanqu-2464','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','从来见说，见说君员梦，果不知似恁底奇。',40,'元曲/yuanqu.json','["从来见说，见说君员梦，果不知似恁底奇。", "(生)张协离家，一千里外，无央厄免得致疑。"]'),
('yuanqu-2465','行香子','无名氏《张协状元》','元','元曲','yuanqu','','[]','欲改门闾，须教孩儿，除非是攻着诗书。',45,'元曲/yuanqu.json','["欲改门闾，须教孩儿，除非是攻着诗书。", "(净上接)门儿咫尺，不出多时。", "为孩儿，欲出去，泪偷垂。"]'),
('yuanqu-2466','武陵春','无名氏《张协状元》','元','元曲','yuanqu','','[]','独离西川无伴侣，一路想凄惶。',14,'元曲/yuanqu.json','["独离西川无伴侣，一路想凄惶。"]'),
('yuanqu-2467','犯樱桃花','无名氏《张协状元》','元','元曲','yuanqu','','[]','孩儿去矣，间或传消息。',77,'元曲/yuanqu.json','["孩儿去矣，间或传消息。", "(合)莫教两头，顿成萦系。", "大家将息。", "取试了即便归。", "(外)每日焚香祷告，惟愿我孩儿，得遂平生志。", "(合)但愿此去，名标金榜，折取月中桂。"]'),
('yuanqu-2468','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协去矣，怕路里无支费。',66,'元曲/yuanqu.json','["张协去矣，怕路里无支费。", "(外净)爹娘与你，许多金珠。", "你莫将容易，怕人欺我儿。", "(生)谢得爹娘慈旨，须是每日里，祷告天和地。", "(合同前)。"]'),
('yuanqu-2469','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','孩儿去矣，妈妈忧忆你。',72,'元曲/yuanqu.json','["孩儿去矣，妈妈忧忆你。", "(合)须还是驮家，自能将息。", "两下休忧虑，频频寄书归。", "(净)只被当直蒿恼，日夜骂着伊。", "(末)你好没巴臂。", "(合同前)(末唱)。"]'),
('yuanqu-2470','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','哥哥去也，妹妹来辞你。',63,'元曲/yuanqu.json','["哥哥去也，妹妹来辞你。", "京都有甚，土宜则剧。", "买些归家里，妹妹须待归。", "哥哥，狗胆梳儿，花朵鞋面头须。", "(末)休要闲理会。", "(合同前)。"]'),
('yuanqu-2471','风马儿','无名氏《张协状元》','元','元曲','yuanqu','','[]','父母俱亡许多时，知它受几多灾危！独自一身依古庙，花朝月夜，多是泪偷垂。',35,'元曲/yuanqu.json','["父母俱亡许多时，知它受几多灾危！独自一身依古庙，花朝月夜，多是泪偷垂。"]'),
('yuanqu-2472','借黄花','无名氏《张协状元》','元','元曲','yuanqu','','[]','奴家命恁穷，此身无所用。',71,'元曲/yuanqu.json','["奴家命恁穷，此身无所用。", "织绢更缉麻，得人知重。", "感得，诸天打供，又遭遇李大公。", "柴米有时无，教小二频赍送。", "今夜起朔风，苦也，如何忍冻！(末出唱)。"]'),
('yuanqu-2473','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','荒村景寂寥，地僻人行少。',72,'元曲/yuanqu.json','["荒村景寂寥，地僻人行少。", "公公教唤你门，特来古庙。", "(旦)万福！君来则甚？想必是来路杳。", "(末)东畔李大公，有少事欲厮央靠。", "特遣我门来，你明日须早到。"]'),
('yuanqu-2474','望远行','无名氏《张协状元》','元','元曲','yuanqu','','[]','乡关渐远，剑阁峥嵘巅险。',45,'元曲/yuanqu.json','["乡关渐远，剑阁峥嵘巅险。", "不惯行程，愁闷怎消遣！时听峭壁猿啼，何日得临帝辇？步云衢称人心愿。"]'),
('yuanqu-2475','生查子','无名氏《张协状元》','元','元曲','yuanqu','','[]','重重叠叠山，渺渺茫茫水。',24,'元曲/yuanqu.json','["重重叠叠山，渺渺茫茫水。", "行货已赍排，独自难区处。"]'),
('yuanqu-2476','复襄阳','无名氏《张协状元》','元','元曲','yuanqu','','[]','一步又一步，一步又一步。',47,'元曲/yuanqu.json','["一步又一步，一步又一步。", "檐儿担不起，怎赶得程路？气力全无，汗出悄如雨。", "尚有三千里，怎生行路！。"]'),
('yuanqu-2477','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','一步远一步，一步远一步。',49,'元曲/yuanqu.json','["一步远一步，一步远一步。", "你与我同出路，也被人欺负。", "遇着强人，你门怎区处？把担杖钱和本，便与它将去。"]'),
('yuanqu-2478','福州歌','无名氏《张协状元》','元','元曲','yuanqu','','[]','伊夺担去，我底行货，都是川里买来底。',50,'元曲/yuanqu.json','["伊夺担去，我底行货，都是川里买来底。", "我妻我儿，家里望消息。", "(合)雪儿又飞，今夜两人在那里睡！(末)。"]'),
('yuanqu-2479','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','它来打你，你不肯和顺，好言告它去。',49,'元曲/yuanqu.json','["它来打你，你不肯和顺，好言告它去。", "使枪使棒，一心逞雄威。", "(合)担儿把去，今夜两人在那里睡！(净)。"]'),
('yuanqu-2480','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','朔风又起，担儿里，纸被袄儿尽劫去。',49,'元曲/yuanqu.json','["朔风又起，担儿里，纸被袄儿尽劫去。", "手儿脚儿，浑身悄如水。", "(合)雪儿又飞，今夜两人在那里睡！(末)。"]'),
('yuanqu-2481','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','你莫打渠，苦必苦，厮打你每早先输。',46,'元曲/yuanqu.json','["你莫打渠，苦必苦，厮打你每早先输。", "你腰我腰，没钱又无米。", "(合)担儿把去，今夜两个在那里睡！。"]'),
('yuanqu-2482','七娘子','无名氏《张协状元》','元','元曲','yuanqu','','[]','朔风四野云垂地，向长空六花飞坠。',34,'元曲/yuanqu.json','["朔风四野云垂地，向长空六花飞坠。", "独上高山，全无力气，奔名奔利直如是。"]'),
('yuanqu-2483','普天乐','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协告苍天，怜孤苦。',73,'元曲/yuanqu.json','["张协告苍天，怜孤苦。", "从小里蒙严父，教六艺通文通武，直欲更换门户。", "今应举天欲暮，大雪纷纷登山路，两头望更无宿处。", "今夜若在此山，莫教协此身，遭遇狼虎。"]'),
('yuanqu-2484','凉草虫','无名氏《张协状元》','元','元曲','yuanqu','','[]','姓张名协，是川里居。',51,'元曲/yuanqu.json','["姓张名协，是川里居。", "本是读书辈，应着科举。", "有些路途费，我日逐要支。", "望怜念心全取，饶张协，裹足一路来去。"]'),
('yuanqu-2485','胡捣练','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协有些子，盘费钱，怕一路欲支遣。',29,'元曲/yuanqu.json','["张协有些子，盘费钱，怕一路欲支遣。", "家又远，望周全，望周全。"]'),
('yuanqu-2486','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','莫将去，念身上寒，况兼又无旅店。',30,'元曲/yuanqu.json','["莫将去，念身上寒，况兼又无旅店。", "时运蹇，望君今，善眼相看！。"]'),
('yuanqu-2487','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','金珠有些子，做盘缠，返西川。',29,'元曲/yuanqu.json','["金珠有些子，做盘缠，返西川。", "若要平分，把一半与，望周全！。"]'),
('yuanqu-2488','临江仙','无名氏《张协状元》','元','元曲','yuanqu','','[]','裂帛一声人叫唤，强人打倒公侯。',42,'元曲/yuanqu.json','["裂帛一声人叫唤，强人打倒公侯。", "当山土地泪双流。", "张解元，不合在它烟焰里，争敢不低头！。"]'),
('yuanqu-2489','糖多令','无名氏《张协状元》','元','元曲','yuanqu','','[]','劫去我盘缠，皮肉打恁穿。',41,'元曲/yuanqu.json','["劫去我盘缠，皮肉打恁穿。", "一身如水没些绵。", "今夜更无存宿处，我拼一命赴黄泉！(末唱)。"]'),
('yuanqu-2490','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','今忽逢老者，下山呵。',58,'元曲/yuanqu.json','["今忽逢老者，下山呵。", "宅居那里周全歇，宿一夜。", "(末)问我时须说破，当山土地吾亲做。", "怜伊现身说些介话。", "(合同前)(末)。"]'),
('yuanqu-2491','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','今君转下山，有一家。',59,'元曲/yuanqu.json','["今君转下山，有一家。", "朱门两扇屋虽破，是鸳鸯瓦。", "(生)又怎知它着我？谢得尊神呵周全我，今宵免得心肠挂。", "(合同前)(生)。"]'),
('yuanqu-2492','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','只得扶病起，下山呵。',55,'元曲/yuanqu.json','["只得扶病起，下山呵。", "尊神恁说协心下，略托大。", "(末)草系门君解破，靠歇须有人温顾。", "不消虑及道如何过。", "(合同前)。"]'),
('yuanqu-2493','出坠子','无名氏《张协状元》','元','元曲','yuanqu','','[]','特降祥云，为强人劫那路人。',40,'元曲/yuanqu.json','["特降祥云，为强人劫那路人。", "路人是张协有佳名，桂籍之中有姓名。", "今宵定没宿处来扣门。"]'),
('yuanqu-2494','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','五鸡山下，有一强人。',46,'元曲/yuanqu.json','["五鸡山下，有一强人。", "把张协尽劫，更没分文。", "又打一查皮肉破，此人有一举登科分，科汝辈怎安稳！。"]'),
('yuanqu-2495','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','吾是值日，小鬼甲头。',69,'元曲/yuanqu.json','["吾是值日，小鬼甲头。", "也弗识肉，也弗识酒。", "(净)唯，汝口应是没量斗。", "(末白)它吃了甚么？(净连唱)满殿里个个都是口臭。", "(末)告你莫说自家丑。"]'),
('yuanqu-2496','五供养','无名氏《张协状元》','元','元曲','yuanqu','','[]','五鸡山下，更没人知我行藏。',53,'元曲/yuanqu.json','["五鸡山下，更没人知我行藏。", "衣裳剥去，露痕伤。", "雪儿又下，朱户闭景物惭惶。", "来古庙试开取，投宿又何妨。", "(又唱)。"]'),
('yuanqu-2497','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','张丈我最灵。',44,'元曲/yuanqu.json','["张丈我最灵。", "(末)会话如何不灵！(生揍)谢得尊神，特显聪明！(丑)朱门两扇，开了又还扁。"]'),
('yuanqu-2498','新水令','无名氏《张协状元》','元','元曲','yuanqu','','[]','朔风凛冽云垂地，见长空六花飞坠。',32,'元曲/yuanqu.json','["朔风凛冽云垂地，见长空六花飞坠。", "踏雪归来也，仗一点灯儿，伴岑寂。"]'),
('yuanqu-2499','江儿水','无名氏《张协状元》','元','元曲','yuanqu','','[]','甚人入奴庙里，把门到拄？(丑白)弗大过拄。',83,'元曲/yuanqu.json','["甚人入奴庙里，把门到拄？(丑白)弗大过拄。", "(末)想你夫主倒拄。", "(旦连唱)教奴独立在雪儿里，淅淅朔风似刀割体，浑身如脱在那江儿水。", "甚人来投此处？早早开门，莫教奴家立地。"]'),
('yuanqu-2500','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','路人无眠也，投此处宿。',104,'元曲/yuanqu.json','["路人无眠也，投此处宿。", "开门怕风透了人难睡。", "(移拄门开)(丑)泓！(末)又来。", "(丑揍)此是劫贼劫它去。", "(末)不干你事！(丑)道我是门神也不知。", "(生凑)衣裳剥尽身如水。", "(净)判官和着小鬼，收拾威光，且来此处立地。"]'),
('yuanqu-2501','捣练子','无名氏《张协状元》','元','元曲','yuanqu','','[]','君还是，往何方？不知怎地有痕伤？见着伊妾断肠。',28,'元曲/yuanqu.json','["君还是，往何方？不知怎地有痕伤？见着伊妾断肠。", "(生唱)。"]'),
('yuanqu-2502','锁南枝','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协本，是秀才，成都府人因乡荐。',53,'元曲/yuanqu.json','["张协本，是秀才，成都府人因乡荐。", "赍裹足欲往宸京，奈何程途远。", "(旦)莫是登，此处山，号五矶，被人骗？(生)。"]'),
('yuanqu-2503','同样换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','因登此山上，强人衣虎皮。',52,'元曲/yuanqu.json','["因登此山上，强人衣虎皮。", "把协劫掠薄贱，一查打得皮肉，破损鲜血满。", "今到此，忽遇伊。", "未审谁，想怜念！(旦)。"]'),
('yuanqu-2504','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','奴家世，本富室，只因水火家不易。',50,'元曲/yuanqu.json','["奴家世，本富室，只因水火家不易。", "年幼间父母俱亡，又没兄和弟。", "居此庙，五七年。", "又遇君，恁狼狈。", "(生)。"]'),
('yuanqu-2505','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','平日在家里，须读古圣书。',52,'元曲/yuanqu.json','["平日在家里，须读古圣书。", "这般雪儿才下，多是饮着羊羔，浅浅斟绿蚁。", "或赋诗，或探梅。", "又怎知，这滋味！(旦)。"]'),
('yuanqu-2506','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','君休要，举那时，目前是物不如意。',50,'元曲/yuanqu.json','["君休要，举那时，目前是物不如意。", "衣又没被席全无，尽出不得已。", "君口食，奴自供。", "要睡时，先自睡。", "(生)。"]'),
('yuanqu-2507','豆叶黄','无名氏《张协状元》','元','元曲','yuanqu','','[]','瑞雪纷纷，便觉丰登。',57,'元曲/yuanqu.json','["瑞雪纷纷，便觉丰登。", "感得吾皇，一人有庆。", "(净作李大婆接唱)亚公，早晨烧香谢神明，惟愿两口儿夫妻，头白牙黄免得短宁。"]'),
('yuanqu-2508','忒忒令','无名氏《张协状元》','元','元曲','yuanqu','','[]','每常问缉麻做布，那贫女赶得些功夫。',48,'元曲/yuanqu.json','["每常问缉麻做布，那贫女赶得些功夫。", "几日来雪下，你全不相顾。", "叫小二来送：一瓶酒，一方米，一块豆腐。"]'),
('yuanqu-2509','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','你闲时叫小二便走。',17,'元曲/yuanqu.json','["你闲时叫小二便走。", "(末白)如何？。"]'),
('yuanqu-2510','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','大雪下浑身都似冰，我双双底早寻思贫女。',48,'元曲/yuanqu.json','["大雪下浑身都似冰，我双双底早寻思贫女。", "有时央靠，它缉麻苎。", "有些豆腐，些儿酒，些儿米，教孩儿送与。"]'),
('yuanqu-2511','酷相思','无名氏《张协状元》','元','元曲','yuanqu','','[]','父母家乡知几里，怎知道儿狼狈！(旦上接)早听得君家长吁气，亦带累奴垂泪。',36,'元曲/yuanqu.json','["父母家乡知几里，怎知道儿狼狈！(旦上接)早听得君家长吁气，亦带累奴垂泪。"]'),
('yuanqu-2512','狮子序','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协恨时未至，居家出路，长是不利。',74,'元曲/yuanqu.json','["张协恨时未至，居家出路，长是不利。", "(旦)不在疏狂惟在自守己，看造物何如。", "(生)张协只仗托诗书。", "(旦)奴家惟凭针指。", "(合)逆来顺受，须有通时。", "(旦)。"]'),
('yuanqu-2513','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','愚意：谁无祸当自遣，将息身上，没事商议。',38,'元曲/yuanqu.json','["愚意：谁无祸当自遣，将息身上，没事商议。", "(生)眼下里衣单又值雪，况肚中饥馁。"]'),
('yuanqu-2514','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','听启：自来不识恁底，平日我衣冠济济。',37,'元曲/yuanqu.json','["听启：自来不识恁底，平日我衣冠济济。", "(旦)没奈何风云际会时，应是胜如今日。"]'),
('yuanqu-2515','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','奴觑：着君家貌美，须有个荷衣着体。',71,'元曲/yuanqu.json','["奴觑：着君家貌美，须有个荷衣着体。", "(生)深谢得娘子恁地说，却又怎忘恩义。", "(旦)奴供备粝食粗衣。", "(生)协感戴此心此意。", "(合)前生料得，曾共结会。"]'),
('yuanqu-2516','字字双','无名氏《张协状元》','元','元曲','yuanqu','','[]','一石两石米和谷，也一担担。',52,'元曲/yuanqu.json','["一石两石米和谷，也一担担。", "两桶三桶臭物事，也一担担。", "四把五把大枥柴，也一担担。", "豆腐一头酒一头，也一担担。"]'),
('yuanqu-2517','双劝酒','无名氏《张协状元》','元','元曲','yuanqu','','[]','阿爹阿娘，教我传语：些儿酒米，担来与你。',34,'元曲/yuanqu.json','["阿爹阿娘，教我传语：些儿酒米，担来与你。", "要时你便留住，不要我便将去。"]'),
('yuanqu-2518','朱奴儿','无名氏《张协状元》','元','元曲','yuanqu','','[]','奴感谢公婆恁地，大雪下托物来相惠。',59,'元曲/yuanqu.json','["奴感谢公婆恁地，大雪下托物来相惠。", "又感哥哥冒雪至，出言语话忒无知。", "你只道，没这样儿。", "怎敢要与奴为夫婿！(末)小娘子：。"]'),
('yuanqu-2519','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','适来它不担那酒米，我婆遂撩拨它说与，改日娘行与你娶贫女。',54,'元曲/yuanqu.json','["适来它不担那酒米，我婆遂撩拨它说与，改日娘行与你娶贫女。", "它欢喜冒雪担至。", "你莫道，没这样儿。", "苦欺它道没张志！。"]'),
('yuanqu-2520','夏云峰','无名氏《张协状元》','元','元曲','yuanqu','','[]','展愁眉，舒病眼，勉强徐步廊西。',15,'元曲/yuanqu.json','["展愁眉，舒病眼，勉强徐步廊西。"]'),
('yuanqu-2521','贺筵开','无名氏《张协状元》','元','元曲','yuanqu','','[]','老夫年老脚衰，近日不出外，故不探知。',40,'元曲/yuanqu.json','["老夫年老脚衰，近日不出外，故不探知。", "(旦)那更雨雪，纷纷恁作威，此处不曾得暂离。"]'),
('yuanqu-2522','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','娘行老丈恁底言语，先世曾结会，似亲故知。',82,'元曲/yuanqu.json','["娘行老丈恁底言语，先世曾结会，似亲故知。", "(旦)我公休与婆知，种些善基，有旧底衣服把赠与(末)兀底老汉有粗道服，赠君家须着取。", "(生旦)深感谢我公恁底！且得遮却血污衣。"]'),
('yuanqu-2523','金钱子','无名氏《张协状元》','元','元曲','yuanqu','','[]','桃杏仪容，不觉又年笄岁。',50,'元曲/yuanqu.json','["桃杏仪容，不觉又年笄岁。", "画堂中随它伴侣，听这别院笙歌，管弦声沸。", "蓦忽心闲，小楼东栏杆镇倚。", "(又唱)。"]'),
('yuanqu-2524','赏宫花序','无名氏《张协状元》','元','元曲','yuanqu','','[]','胜花女，四时中，心下没事萦系。',69,'元曲/yuanqu.json','["胜花女，四时中，心下没事萦系。", "除非上苑随趁，度芳菲欢会。", "思之，论梳妆和针指，怎晓得！仗托云鬟粉面，使婢随侍。", "临鸾照时，那饰容都是它辈承直。"]'),
('yuanqu-2525','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','白日，笑语长是，乐春台则剧。',64,'元曲/yuanqu.json','["白日，笑语长是，乐春台则剧。", "情和富豪家，人中最贵最第一。", "感得，吾皇时召，身赴瑶池。", "春去夏月芰荷，香镇拂鼻。", "小舟时泛，知菱歌游戏。"]'),
('yuanqu-2526','前同换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','秋至，采楼高，龙山耸月正辉。',68,'元曲/yuanqu.json','["秋至，采楼高，龙山耸月正辉。", "宴着红裙，终夜一任眠迟。", "冬季赏雪，胆瓶簪梅数枝。", "暖阁团坐，饮羊羔风味。", "须知富贵，自然娇艳，有不搽红粉也相宜。"]'),
('yuanqu-2527','薄媚令','无名氏《张协状元》','元','元曲','yuanqu','','[]','愁多怨极，历尽万千滋味。',37,'元曲/yuanqu.json','["愁多怨极，历尽万千滋味。", "幸几日身安免虑。", "(旦上接)听得旁来，无事使奴暗喜。"]'),
('yuanqu-2528','红衫儿','无名氏《张协状元》','元','元曲','yuanqu','','[]','独步廊西魂欲断，自觉孤凄，奈眼前尽成怨忆。',54,'元曲/yuanqu.json','["独步廊西魂欲断，自觉孤凄，奈眼前尽成怨忆。", "(旦)此处村僻荒羌，那人烟最稀。", "早晚奴独坐独行，□便过得。", "(生)。"]'),
('yuanqu-2529','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','才到黄昏至，虎啸猿啼起。',63,'元曲/yuanqu.json','["才到黄昏至，虎啸猿啼起。", "论娘行恁娇媚，何不嫁个良婿？(旦)孰敢痴迷！貌丑犹过一壁，奈身无寸缕。", "况兼亲戚俱无，谁来管你？(生)。"]'),
('yuanqu-2530','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','算来张协病，相将渐效可。',81,'元曲/yuanqu.json','["算来张协病，相将渐效可。", "虽然恁地，归犹未得。", "娘子无夫协无归，好共成比翼。", "饱学在肚里，异日风去际，身定到凤凰池，一举登科，强在庙里。", "带汝归到吾乡，真个好哩！(旦)。"]'),
('yuanqu-2531','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','我婆扯住！(净)秀才说话跷蹊，不要时，我做个说合底？请它归，着些言语说化伊。',92,'元曲/yuanqu.json','["我婆扯住！(净)秀才说话跷蹊，不要时，我做个说合底？请它归，着些言语说化伊。", "(末)我婆要与你说作一对儿。", "(生)仗托公公做主意。", "(净叫旦出)且休要怒起，你归来说个仔细。", "(旦)听奴咨启：。"]'),
('yuanqu-2532','金莲子','无名氏《张协状元》','元','元曲','yuanqu','','[]','庙门闭，个开留此处。',46,'元曲/yuanqu.json','["庙门闭，个开留此处。", "你没话计，我周全你。", "好不傍道理！(末净)蓦忽地恁说，他便漾出去。", "(生)。"]'),
('yuanqu-2533','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','卑人此住无所倚，幸然娘子没夫婿。',47,'元曲/yuanqu.json','["卑人此住无所倚，幸然娘子没夫婿。", "(净)你说得是。", "我公婆看时，精神恁磊落，一对好夫妻。", "(旦唱)。"]'),
('yuanqu-2534','醉太平','无名氏《张协状元》','元','元曲','yuanqu','','[]','明日恁地，神前拜跪。',63,'元曲/yuanqu.json','["明日恁地，神前拜跪。", "神还许妾嫁君时，觅一个圣杯。", "(生)娘行恁说有些儿意。", "(末)不消得我每为媒主。", "(净)公公，你出个猪头祭土地。"]'),
('yuanqu-2535','尾声','无名氏《张协状元》','元','元曲','yuanqu','','[]','只此一言是的实。',31,'元曲/yuanqu.json','["只此一言是的实。", "(净)婆婆劝你休走智。", "(生)我异日风云际会时。"]'),
('yuanqu-2536','女冠子','无名氏《张协状元》','元','元曲','yuanqu','','[]','位迁极品，簪缨势象板派。',69,'元曲/yuanqu.json','["位迁极品，簪缨势象板派。", "家传诗礼，门排朱紫。", "更兼亲戚，尽皆豪迈。", "当朝为宰执，一女笄年，未及婚嫁。", "这些儿愁闷，镇在心头，无缘可解。", "(又唱)。"]'),
('yuanqu-2537','鹤冲天','无名氏《张协状元》','元','元曲','yuanqu','','[]','沉吟一和，猛省孩儿事未员。',59,'元曲/yuanqu.json','["沉吟一和，猛省孩儿事未员。", "袅娜巧身材，桃腮和杏脸。", "每日把珠翠若神女貌，玉女面。", "百事尽皆能，试看它能写染，强一京好宅眷。"]'),
('yuanqu-2538','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','年当笄岁，感得吾皇数次宣。',57,'元曲/yuanqu.json','["年当笄岁，感得吾皇数次宣。", "着个好姻缘，除非是状元。", "若招附马也不辱貌，不偏绾，荣耀两俱全。", "试看今岁里，必有个好姻眷。"]'),
('yuanqu-2539','白','无名氏《张协状元》','元','元曲','yuanqu','','[]','我底女孩儿，它爹爹是当朝宰执，妈妈是两国夫人，终不成不求得一个好姻缘。',70,'元曲/yuanqu.json','["我底女孩儿，它爹爹是当朝宰执，妈妈是两国夫人，终不成不求得一个好姻缘。", "除非嫁个读书人，不问簪缨不问贫。", "但愿五湖风月在，不愁无处下丝纶(下)。"]'),
('yuanqu-2540','剔银灯','无名氏《张协状元》','元','元曲','yuanqu','','[]','吾血食一方却最灵，百余岁都说我感应。',52,'元曲/yuanqu.json','["吾血食一方却最灵，百余岁都说我感应。", "年年祭户，见没节病。", "献四五碟芝麻糖饼，一陌两陌纸钱，如何会通灵显圣。"]'),
('yuanqu-2541','大影戏','无名氏《张协状元》','元','元曲','yuanqu','','[]','今日设个几案，(喏)些儿事要相干。',17,'元曲/yuanqu.json','["今日设个几案，(喏)些儿事要相干。"]'),
('yuanqu-2542','缕缕金','无名氏《张协状元》','元','元曲','yuanqu','','[]','亚爹不曾见，一个大猪头。',40,'元曲/yuanqu.json','["亚爹不曾见，一个大猪头。", "移时还祭了，我便抢将走。", "(末)靠歇两个成亲后，须要吃酒。"]'),
('yuanqu-2543','思园春','无名氏《张协状元》','元','元曲','yuanqu','','[]','你要休时我未休。',57,'元曲/yuanqu.json','["你要休时我未休。", "(净)早来吾殿下吃猪头。", "(旦出)灵杯不许后，教我怎生留！(生)漾人葫芦水上游，葫芦儿沉后我共伊休。"]'),
('yuanqu-2544','菊花新','无名氏《张协状元》','元','元曲','yuanqu','','[]','灵神听启：成都府住，奈张协自幼攻书。',90,'元曲/yuanqu.json','["灵神听启：成都府住，奈张协自幼攻书。", "因往宸京，路途里被劫取。", "有裹足之费，尽劫将去，一查打倒，冒瑞雪投入神祠里。", "睡不稳，牵惹无限不如意。", "忽逢贫女又没夫，协无妻，见欲成姻契。", "献神绿蚁。"]'),
('yuanqu-2545','歇拍','无名氏《张协状元》','元','元曲','yuanqu','','[]','哽咽无言泪暗试，泻酒时又没人吃。',123,'元曲/yuanqu.json','["哽咽无言泪暗试，泻酒时又没人吃。", "鹦鹉杯深，渐迤逦，断涓滴。", "(净偷酒)(末捉唱)见得神灵异，两头都是。", "(净)殷勤来献，谢你们三献都不吃。", "(末白)犹骨不吃。", "(净揍)张协是贫女姻缘，皆宿契，今生重会。", "向绣幄，效鱼水。", "许绾同心结，永谐连理。", "(生旦合唱)。"]'),
('yuanqu-2546','终衮','无名氏《张协状元》','元','元曲','yuanqu','','[]','似鸾凤和鸣，相应青云际。',96,'元曲/yuanqu.json','["似鸾凤和鸣，相应青云际。", "效鹣鹣比翼，鸳鸯双双戏。", "相怜相爱，拼尽老，与偎随。", "待把伊，托在心儿里。", "(末)神歌鬼舞，况我们村落皆欢喜，愿厮守终久于飞。", "(合)身赴月宫折桂枝，已两两同欢会，这些滋味美。"]'),
('yuanqu-2547','添字赛红娘','无名氏《张协状元》','元','元曲','yuanqu','','[]','先来是奴心儿里闷，蓦撞见伊。',53,'元曲/yuanqu.json','["先来是奴心儿里闷，蓦撞见伊。", "姻缘怎知，君家共成连理枝，共成鸾凤飞。", "(合)愿得百岁镇同谐，浑不暂离。", "(生)。"]'),
('yuanqu-2548','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','荣辱算来是前生定，只得守己。',53,'元曲/yuanqu.json','["荣辱算来是前生定，只得守己。", "儒冠未必将人误，我直恁底，误我百年亏。", "(合)愿得一跃过龙门，荣归故里。", "(旦)。"]'),
('yuanqu-2549','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','贫穷困苦谁知道，双眉暂舒。',53,'元曲/yuanqu.json','["贫穷困苦谁知道，双眉暂舒。", "君须异日，休得要忘却奴厚期，忘却来庙里。", "(合)愿得相看镇长恁，如鱼似水。", "(生)。"]'),
('yuanqu-2550','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','诗书礼乐曾谙历，我敢负伊！伊我放心，不须要虑及辜我妻，虑及辜负伊。',49,'元曲/yuanqu.json','["诗书礼乐曾谙历，我敢负伊！伊我放心，不须要虑及辜我妻，虑及辜负伊。", "(合)愿得前意镇如初，团圆到底。"]'),
('yuanqu-2551','赛红娘','无名氏《张协状元》','元','元曲','yuanqu','','[]','先来小生心儿闷，见贫女又嫁。',14,'元曲/yuanqu.json','["先来小生心儿闷，见贫女又嫁。"]'),
('yuanqu-2552','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','先来是我脚儿小，步三寸莲。',67,'元曲/yuanqu.json','["先来是我脚儿小，步三寸莲。", "(末白)一尺三寸。", "(净揍)一个水穴，阔三尺横在庙前。", "(末白)是有一个水穴。", "(净揍)被我脱下绣鞋儿，自作度船。"]'),
('yuanqu-2553','排歌','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协谢，公婆至！感叠叠蒙周庇。',15,'元曲/yuanqu.json','["张协谢，公婆至！感叠叠蒙周庇。"]'),
('yuanqu-2554','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','两口从今日，自当爱惜，诗书自当记得。',39,'元曲/yuanqu.json','["两口从今日，自当爱惜，诗书自当记得。", "(净)你对夫妻，且恁底奇，哉对夫妻直恁底。"]'),
('yuanqu-2555','红绣鞋','无名氏《张协状元》','元','元曲','yuanqu','','[]','小二在何处说话？(丑)在卓下。',15,'元曲/yuanqu.json','["小二在何处说话？(丑)在卓下。"]'),
('yuanqu-2556','刮鼓令','无名氏《张协状元》','元','元曲','yuanqu','','[]','今夜尽欢。',15,'元曲/yuanqu.json','["今夜尽欢。", "(净)我吃酒须教满。"]'),
('yuanqu-2557','祝英台近','无名氏《张协状元》','元','元曲','yuanqu','','[]','画堂深，人悄悄，春入杏花梢。',63,'元曲/yuanqu.json','["画堂深，人悄悄，春入杏花梢。", "膏雨弄晴，蝶粉蜂黄，相傍养花时候。", "(后)碧藻，翠荇水底牵风，鱼游池沼。", "(合)画栏边，来往游人嬉笑。"]'),
('yuanqu-2558','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','时到，粉墙低，曲径窈，一段景偏好。',70,'元曲/yuanqu.json','["时到，粉墙低，曲径窈，一段景偏好。", "小院邃亭，一蔟神仙，珠翠镇相围绕。", "(后)听道，卖花声过桥西，奇葩争巧。", "(合)乱莺啼，迁着乔林声闹。", "(外)。"]'),
('yuanqu-2559','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','清晓，侍婢不惜千金，相呼斗百草。',69,'元曲/yuanqu.json','["清晓，侍婢不惜千金，相呼斗百草。", "遗珥坠簪，(合)蹙着千秋，不禁笑语声高。", "(后)夭桃，遍开浑若烧空，雏禽时叫。", "睹景处，觉得奴心烦恼。", "(外)。"]'),
('yuanqu-2560','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','失笑，我女休得闲愁，宽取汝怀抱。',63,'元曲/yuanqu.json','["失笑，我女休得闲愁，宽取汝怀抱。", "好事怎匆？今岁贤良，须是选个年少。", "(后)焦躁，此心非为求亲，容奴咨告：(合)为伤取，容光将老。"]'),
('yuanqu-2561','荷叶铺水面','无名氏《张协状元》','元','元曲','yuanqu','','[]','才郎到此处时，奴家正生怜念心。',56,'元曲/yuanqu.json','["才郎到此处时，奴家正生怜念心。", "雪若晴，君家定着出庙门。", "(合)谁知先世，已曾结定。", "恁困穷，何时免得日系萦。", "(生)。"]'),
('yuanqu-2562','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协到感我妻，同谐已约百岁期。',57,'元曲/yuanqu.json','["张协到感我妻，同谐已约百岁期。", "困此间，不惹上国夺桂枝。", "(合)身荣那时，也争得气。", "没裹足，如何便得身会起？(旦唱)。"]'),
('yuanqu-2563','孝顺歌','无名氏《张协状元》','元','元曲','yuanqu','','[]','怒愁闷，又遇君，思之两口直恁贫。',62,'元曲/yuanqu.json','["怒愁闷，又遇君，思之两口直恁贫。", "君家又无人，奴家又无亲，全没救兵。", "去则依然，奴还孤冷。", "(合)怎得盘缠，盘缠到得宸京。", "(生)。"]'),
('yuanqu-2564','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','协今去也，何时遂此情？亦欲耀家庭，亦欲要身荣。',38,'元曲/yuanqu.json','["协今去也，何时遂此情？亦欲耀家庭，亦欲要身荣。", "亦欲愿你，愿你时来，大得一命。"]'),
('yuanqu-2565','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','奴只得，往庙前，借取大公些个典。',59,'元曲/yuanqu.json','["奴只得，往庙前，借取大公些个典。", "与奴做盘缠，又欲买些绢，妆些旧绵。", "又恐春寒，衣衫不办。", "办与衣衫，一路免得身寒。", "(生)。"]'),
('yuanqu-2566','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','望娘子借与，娘子便去说。',54,'元曲/yuanqu.json','["望娘子借与，娘子便去说。", "前途怕钱欠，中途怕钱悭，钱谁与添？更望娘行，多方宛转。", "(合)宛转些添，回来自当偿还。"]'),
('yuanqu-2567','麻婆子','无名氏《张协状元》','元','元曲','yuanqu','','[]','二月春光好，秧针细细抽。',43,'元曲/yuanqu.json','["二月春光好，秧针细细抽。", "有时移步出田头，蝌蚪要无数水中游。", "婆婆傍前捞一碗，急忙去买油。"]'),
('yuanqu-2568','尹令','无名氏《张协状元》','元','元曲','yuanqu','','[]','它命又合孤令，奴家又合孤令。',48,'元曲/yuanqu.json','["它命又合孤令，奴家又合孤令。", "方得二月安静，教奴又成愁闷。", "(末净)闻伊丈夫，今直欲到帝京。", "(末)。"]'),
('yuanqu-2569','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','它又更没活路，你又更没亲故，盘缠怎生区处？(净面看别处)(末抽转)你也转来厮觑。',40,'元曲/yuanqu.json','["它又更没活路，你又更没亲故，盘缠怎生区处？(净面看别处)(末抽转)你也转来厮觑。"]'),
('yuanqu-2570','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','欲去在伊两个，不去在伊两个。',44,'元曲/yuanqu.json','["欲去在伊两个，不去在伊两个。", "说与我每一和，又说与我公一和。", "(末旦)如今来，只得又靠我婆。"]'),
('yuanqu-2571','添字尹令','无名氏《张协状元》','元','元曲','yuanqu','','[]','奴家拜告，听取奴家：得婆周庇，直欲靠婆到老。',59,'元曲/yuanqu.json','["奴家拜告，听取奴家：得婆周庇，直欲靠婆到老。", "张协要好，出路宜及早。", "(合)归来后称怀抱，除非异时，归古庙挂绿袍。", "(净)。"]'),
('yuanqu-2572','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','婆婆有宝，不与公公道。',68,'元曲/yuanqu.json','["婆婆有宝，不与公公道。", "(末白)不知底。", "(净接)公公知道，应是问婆借了。", "(末)莫是夜明珠？(旦接)婆婆借与，托取公公保。", "(合同前)(末)。"]'),
('yuanqu-2573','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','长安古道，盘费知多少。',43,'元曲/yuanqu.json','["长安古道，盘费知多少。", "婆婆早与，它便起程又早。", "(旦)今朝倚靠，非外来相扰。", "(合同前)。"]'),
('yuanqu-2574','添字尹令','无名氏《张协状元》','元','元曲','yuanqu','','[]','一杯杜酒，感你把头发剪。',38,'元曲/yuanqu.json','["一杯杜酒，感你把头发剪。", "婆婆头髻，看得许多价添。", "(旦)程途怕远，只要钱支遣。"]'),
('yuanqu-2575','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','奴家量浅，一盏桃花脸。',43,'元曲/yuanqu.json','["奴家量浅，一盏桃花脸。", "前生姻眷，结得我婆底缘。", "(净)婆婆懒出，不得来相饯。", "(合同前)。"]'),
('yuanqu-2576','懒画眉','无名氏《张协状元》','元','元曲','yuanqu','','[]','早辰临鸾此情伤，我不为爹来不为娘，头发剪了终须再长。',43,'元曲/yuanqu.json','["早辰临鸾此情伤，我不为爹来不为娘，头发剪了终须再长。", "使奴心悒怏，不是奴家又谁管你行？。"]'),
('yuanqu-2577','狮子序','无名氏《张协状元》','元','元曲','yuanqu','','[]','你忒急性，且听我言：你出路日子在眼前，我一夜思之怕没盘缠，往大公家急忙去借典。',78,'元曲/yuanqu.json','["你忒急性，且听我言：你出路日子在眼前，我一夜思之怕没盘缠，往大公家急忙去借典。", "婆婆也没金，也没典，亦没钱。", "我每把头发便来剪，得些钱，苦把杯酒来相劝。", "(生)。"]'),
('yuanqu-2578','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','没瞒过我，实是你灾。',83,'元曲/yuanqu.json','["没瞒过我，实是你灾。", "隐僻处直是会打乖，谁头发剪落便有人买？这双眼人说你最呆。", "如今那得钱？那得银？焉得酒？你说不实是少怪。", "把庙门闭，勘问你何处归来。", "(生打旦)(旦唱)。"]'),
('yuanqu-2579','临江仙','无名氏《张协状元》','元','元曲','yuanqu','','[]','一堂神道你须知：我门非别底，你不是男儿！。',21,'元曲/yuanqu.json','["一堂神道你须知：我门非别底，你不是男儿！。"]'),
('yuanqu-2580','柰子花','无名氏《张协状元》','元','元曲','yuanqu','','[]','公公，我婆婆说要头髻，奴不得只剪下些儿。',53,'元曲/yuanqu.json','["公公，我婆婆说要头髻，奴不得只剪下些儿。", "婆婆喜欢，教斟绿蚁。", "没巴臂便来打起，想是，奴家害了你家计。", "(末)。"]'),
('yuanqu-2581','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','卑人欲往京畿，从早间等到今时。',43,'元曲/yuanqu.json','["卑人欲往京畿，从早间等到今时。", "妇人爱酒贪欢喜，终久后又成何济？想起，这妇人害了我家计。"]'),
('yuanqu-2582','醉落魄','无名氏《张协状元》','元','元曲','yuanqu','','[]','冤家做作好直恁，把心不定。',41,'元曲/yuanqu.json','["冤家做作好直恁，把心不定。", "(生)张协去心不安稳，不见归来，寻你那脸节病。", "(旦唱)。"]'),
('yuanqu-2583','四换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','初人我庙门，你不曾发这般嗔。',111,'元曲/yuanqu.json','["初人我庙门，你不曾发这般嗔。", "今日里既定，把奴家直恁地轻。", "(生)伊不说一日价不见您，从早晨间只管价等。", "(合)水一似清，月一似明，怒若发时恶气便生。", "(旦)知是君家，直恁地去得紧，奴不卖这发，君须去不成。", "(生)此行必是好佳讠千。"]'),
('yuanqu-2584','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','我婆且自宽心，张协为人恁底村，婆要镜，没时岂敢上婆门。',96,'元曲/yuanqu.json','["我婆且自宽心，张协为人恁底村，婆要镜，没时岂敢上婆门。", "(净)拜辞君，我和伊今夜有人相请，隔岸村庄祭土神。", "(未白)只为吃。", "(净连唱)你道婆婆，怎地了脚头紧。", "(末)好不安分！(末净下)(旦又唱)。"]'),
('yuanqu-2585','呼唤子','无名氏《张协状元》','元','元曲','yuanqu','','[]','坚心耐烦等，须有日见情人。',64,'元曲/yuanqu.json','["坚心耐烦等，须有日见情人。", "奴待见得情人了，依然讲旧情。", "(生)眼下阿好闷，直欲到宸京。", "(旦)只恐我夫荣贵也，嫌奴身畔贫。", "(生唱)。"]'),
('yuanqu-2586','尾声','无名氏《张协状元》','元','元曲','yuanqu','','[]','这般人活短命！(合)举头三尺有神明。',26,'元曲/yuanqu.json','["这般人活短命！(合)举头三尺有神明。", "两两分飞阿好闷。"]'),
('yuanqu-2587','斗黑麻','无名氏《张协状元》','元','元曲','yuanqu','','[]','帝德广过尧，喜会太平。',48,'元曲/yuanqu.json','["帝德广过尧，喜会太平。", "我是清朝，第一大臣。", "净所为，直是英俊。", "论梗直，最怕人，好底酸醋，吃得五瓶。"]'),
('yuanqu-2588','粉蝶儿','无名氏《张协状元》','元','元曲','yuanqu','','[]','庭院深深，春色恼人天气。',38,'元曲/yuanqu.json','["庭院深深，春色恼人天气。", "(后出接)向幽闺更无情味。", "步芳堤，游上苑，便贪游戏。"]'),
('yuanqu-2589','驻马听','无名氏《张协状元》','元','元曲','yuanqu','','[]','伊看我孩儿，似这月里嫦娥到强似它。',80,'元曲/yuanqu.json','["伊看我孩儿，似这月里嫦娥到强似它。", "亚爹孩儿全没，老来惟凭着，你们一个。", "(外后)未知爹爹那雅意要如何？早言一句说交破。", "(丑)你休得误人呵，莫教我女青春过。", "(外)。"]'),
('yuanqu-2590','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','儿恁娇痴，须要个读书人为女婿。',79,'元曲/yuanqu.json','["儿恁娇痴，须要个读书人为女婿。", "我家里公侯累代，小可底苍生，怎为姻契！(丑)五百名中有多少好才人，我女拣个一般美。", "(外)爹爹甚言语，若非是状元怎成匹配。", "(后)。"]'),
('yuanqu-2591','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','朱紫骈骈，不若荷衣一状元。',71,'元曲/yuanqu.json','["朱紫骈骈，不若荷衣一状元。", "况兼奴家是豪贵，若非高甲，怎生攀羡！(外)我王择贤毕竟是今年，与我儿选个福非浅。", "(合)出得几多钱，招捉那状元为姻眷。"]'),
('yuanqu-2592','水调歌头','无名氏《张协状元》','元','元曲','yuanqu','','[]','一心离故里，只影欲朝天。',122,'元曲/yuanqu.json','["一心离故里，只影欲朝天。", "半途遭难，岂期贫女又留连。", "长记彩衣堂上，临别双亲嘱付，细想是良言。", "教逢桥须下马，遇夜莫行船。", "近日来，离古庙，意悬悬。", "爹娘又虑，料它贫女泪涟涟，是事一齐瞥样，挑取被包雨具，度领涉长川。", "正是雁飞不到处，人被利名牵。", "(生下)。"]'),
('yuanqu-2593','福清歌','无名氏《张协状元》','元','元曲','yuanqu','','[]','自离故乡，寻思断肠，两个月得共鸾凰。',50,'元曲/yuanqu.json','["自离故乡，寻思断肠，两个月得共鸾凰。", "许多时守空房，到如今依旧恁，似我不嫁郎。", "燕衔泥，寻旧垒骨自成双。"]'),
('yuanqu-2594','虞美人','无名氏《张协状元》','元','元曲','yuanqu','','[]','缉麻缉苎攻针指，亦是不得已。',32,'元曲/yuanqu.json','["缉麻缉苎攻针指，亦是不得已。", "时常眼泪不曾干，只恐别郎容易见郎难。"]'),
('yuanqu-2595','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','婆婆暗自喜，得你嫁夫婿。',41,'元曲/yuanqu.json','["婆婆暗自喜，得你嫁夫婿。", "图它此去时，早攀月桂枝。", "金冠霞帔，有分妆束你。", "我称孺人，。"]'),
('yuanqu-2596','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','不是我自夸，它自定及第。',68,'元曲/yuanqu.json','["不是我自夸，它自定及第。", "着鞭衣锦归，便是荣贵时。", "(净)我做婆婆，你做当直度。", "(末白)又占有好底。", "(合)那时价喜，买炷明香，大家答谢天地。"]'),
('yuanqu-2597','望吾乡','无名氏《张协状元》','元','元曲','yuanqu','','[]','家住西川，回首泪暗垂。',49,'元曲/yuanqu.json','["家住西川，回首泪暗垂。", "中途怎知人劫去，娶它贫女是不得已。", "幸然脱此处，都城在，眼下里，尽总是繁华地。"]'),
('yuanqu-2598','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','我只是不还赁钱。',70,'元曲/yuanqu.json','["我只是不还赁钱。", "(净)赶出去桥亭上眠。", "(生)看取同人劝您。", "(末)休要出言恁偏。", "(丑)你弄拳！(净)我弄拳？(生末合)看口休得要斗煎。", "(净)。"]'),
('yuanqu-2599','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','少我那房钱到嗔。',42,'元曲/yuanqu.json','["少我那房钱到嗔。", "(丑)骂得我教人怎忍。", "(末)你两个八两半斤。", "(生)好一对人客和主人。"]'),
('yuanqu-2600','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','要你须着这秀才。',42,'元曲/yuanqu.json','["要你须着这秀才。", "(净)我着它伊休要来。", "(末)你两个贫胎苦肥。", "(生)没紧要休得要系怀。"]'),
('yuanqu-2601','探春令','无名氏《张协状元》','元','元曲','yuanqu','','[]','三年一度选英贤，论学业非浅。',37,'元曲/yuanqu.json','["三年一度选英贤，论学业非浅。", "(后出接)又未知，谁氏登鳌首？甚日满奴心愿？。"]'),
('yuanqu-2602','神仗儿','无名氏《张协状元》','元','元曲','yuanqu','','[]','欲待取覆，欲待取覆：昨蒙钧旨，非不整肃，采楼如法价结束。',60,'元曲/yuanqu.json','["欲待取覆，欲待取覆：昨蒙钧旨，非不整肃，采楼如法价结束。", "(合)秀才明日赴阙，侣争着天禄。", "只末知甚题目？甚题目？(外唱)。"]'),
('yuanqu-2603','滴漏子','无名氏《张协状元》','元','元曲','yuanqu','','[]','豪家贵戚浑无数。',73,'元曲/yuanqu.json','["豪家贵戚浑无数。", "(合)定必欲嫁状元。", "(后)奴家分福前生定。", "(合)嫁一个应少年。", "(末)因缘因缘，心坚管教石也穿。", "(合)马前马前，合人情度鞭。", "(外)。"]'),
('yuanqu-2604','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','前日不须看入院。',18,'元曲/yuanqu.json','["前日不须看入院。", "(合)看游街看执鞭。"]'),
('yuanqu-2605','黄莺儿','无名氏《张协状元》','元','元曲','yuanqu','','[]','一去更无音耗，使双双孤令。',64,'元曲/yuanqu.json','["一去更无音耗，使双双孤令。", "未知甚日挂绿袍？使奴家称心。", "它恁地我英俊，定必占魁名。", "早得个人往江陵，问及第是甚人？(丑作小二出唱)。"]'),
('yuanqu-2606','吴小四','无名氏《张协状元》','元','元曲','yuanqu','','[]','一个大贫胎，称秀才。',42,'元曲/yuanqu.json','["一个大贫胎，称秀才。", "教我阿娘来做媒，一去京城更不回。", "算它老婆真是呆，指望平地一声雷。"]'),
('yuanqu-2607','吴小四','无名氏《张协状元》','元','元曲','yuanqu','','[]','一个大贫胎，称秀才。',66,'元曲/yuanqu.json','["一个大贫胎，称秀才。", "(旦白)这句便说张解元。", "(丑连唱)教我阿娘来做媒，(旦白)分明你做了。", "(丑连唱)一去京城更不回。", "算它老婆真是呆。"]'),
('yuanqu-2608','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','自从去京，奴泪镇零。',42,'元曲/yuanqu.json','["自从去京，奴泪镇零。", "难禁离别情，日夜我寻思没耗音。", "我门怎知你笑人，唱只曲教奴仔细听。"]'),
('yuanqu-2609','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','自从嫁它，奴办至诚，不成它负心。',41,'元曲/yuanqu.json','["自从嫁它，奴办至诚，不成它负心。", "一举登科有姓名，果然负奴绝耗音，万水千山奴也去寻。"]'),
('yuanqu-2610','卜算子','无名氏《张协状元》','元','元曲','yuanqu','','[]','百尺彩楼高，十里人挨闹。',12,'元曲/yuanqu.json','["百尺彩楼高，十里人挨闹。"]'),
('yuanqu-2611','福马郎','无名氏《张协状元》','元','元曲','yuanqu','','[]','知道是成都一秀才，五百名中占，天下魁。',49,'元曲/yuanqu.json','["知道是成都一秀才，五百名中占，天下魁。", "今日里，定游街。", "(合)十里小红楼，人争看喝道状元来。", "(占)。"]'),
('yuanqu-2612','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','公相当朝何用媒，仗托我丝鞭，去选大才。',49,'元曲/yuanqu.json','["公相当朝何用媒，仗托我丝鞭，去选大才。", "当筵宴，早安排。", "(合)凝望彩楼高，帘儿卷等取状元来。", "(末)。"]'),
('yuanqu-2613','卜算子','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协受皇恩，乍着荷衣绿。',26,'元曲/yuanqu.json','["张协受皇恩，乍着荷衣绿。", "回首爹娘万里遥，料已沾天禄。"]'),
('yuanqu-2614','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','嘈杂欢声沸，捧拥风流婿。',31,'元曲/yuanqu.json','["嘈杂欢声沸，捧拥风流婿。", "果与奴家有宿缘，接取丝鞭去。", "(末唱)。"]'),
('yuanqu-2615','大圣乐','无名氏《张协状元》','元','元曲','yuanqu','','[]','采楼高处有娇姝，赫王府求女婿。',15,'元曲/yuanqu.json','["采楼高处有娇姝，赫王府求女婿。"]'),
('yuanqu-2616','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','求名我不在求妻，欢谐事心未喜。',81,'元曲/yuanqu.json','["求名我不在求妻，欢谐事心未喜。", "豪家谩把丝鞭刺，甚娇媚又入人意。", "(后)料想君家多是不曾娶，君且接取丝鞭又妨甚底！(末)似相嫌弃，五百年未知道，缘分何如？(外出唱)。"]'),
('yuanqu-2617','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','我儿又得要痴迷，夫妻事前定矣。',15,'元曲/yuanqu.json','["我儿又得要痴迷，夫妻事前定矣。"]'),
('yuanqu-2618','十五郎','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协托在洪福，今叨冒身挂绿。',14,'元曲/yuanqu.json','["张协托在洪福，今叨冒身挂绿。"]'),
('yuanqu-2619','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协家住在西川，随爹妈心意转。',15,'元曲/yuanqu.json','["张协家住在西川，随爹妈心意转。"]'),
('yuanqu-2620','江头送别','无名氏《张协状元》','元','元曲','yuanqu','','[]','才及第，才及第，我女便嫁你。',46,'元曲/yuanqu.json','["才及第，才及第，我女便嫁你。", "张家府，王家府，怎不知是？忒作怪不接丝鞭去，想它都跷蹊。", "(末)。"]'),
('yuanqu-2621','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','因缘事，因缘事，五百年注已。',42,'元曲/yuanqu.json','["因缘事，因缘事，五百年注已。", "它不肯，它不肯，怕没别底。", "(丑白)怕没别底，须不是状元。"]'),
('yuanqu-2622','金蕉叶','无名氏《张协状元》','元','元曲','yuanqu','','[]','脱白挂绿，苦不肯共成眷属。',31,'元曲/yuanqu.json','["脱白挂绿，苦不肯共成眷属。", "(后出接)蓦忽地思量，簌是奴没分福。"]'),
('yuanqu-2623','斗虼麻','无名氏《张协状元》','元','元曲','yuanqu','','[]','几年东床，要纳状元。',38,'元曲/yuanqu.json','["几年东床，要纳状元。", "怎知道新来底，被它弃嫌？不肯与，接丝鞭。", "使孩儿，泪涟涟。"]'),
('yuanqu-2624','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','自古道东床，女婿有万千。',40,'元曲/yuanqu.json','["自古道东床，女婿有万千。", "怎知它一举，便做着状元。", "奴只道，永团圆。", "必来接，那丝鞭。"]'),
('yuanqu-2625','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','你不是初来，莫要度鞭。',53,'元曲/yuanqu.json','["你不是初来，莫要度鞭。", "我妆做孩儿，敛袂傍前。", "(末)莫咫尺，有神仙？(丑)不接鞭，且一拳。", "(合同前)(末)。"]'),
('yuanqu-2626','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','五百位官员，何可向前？又何苦特骨底，要嫁状元？(丑)伊着我，此心坚。',49,'元曲/yuanqu.json','["五百位官员，何可向前？又何苦特骨底，要嫁状元？(丑)伊着我，此心坚。", "石头须，定教它穿。", "(合同前)。"]'),
('yuanqu-2627','花儿','无名氏《张协状元》','元','元曲','yuanqu','','[]','三文买着状元，五百姓名及州县。',31,'元曲/yuanqu.json','["三文买着状元，五百姓名及州县。", "两本直你六文钱，要千本交五贯文。"]'),
('yuanqu-2628','抟山子','无名氏《张协状元》','元','元曲','yuanqu','','[]','天不从人这些愿，使子母悬悬。',35,'元曲/yuanqu.json','["天不从人这些愿，使子母悬悬。", "(后出接)谁信道不接丝鞭，毕竟是非奴姻眷。"]'),
('yuanqu-2629','醉太平','无名氏《张协状元》','元','元曲','yuanqu','','[]','从来我意，镇有心，便欲求伊姻契。',16,'元曲/yuanqu.json','["从来我意，镇有心，便欲求伊姻契。"]'),
('yuanqu-2630','山坡里羊','无名氏《张协状元》','元','元曲','yuanqu','','[]','知它你是及第？知它你是不第？知它在上国？知它归来未？镇使奴终日泪暗垂。',72,'元曲/yuanqu.json','["知它你是及第？知它你是不第？知它在上国？知它归来未？镇使奴终日泪暗垂。", "莫非不第了羞归乡里？又恐嫌奴贫穷恁地。", "别也别来断信息，断信息。", "(净出唱)。"]'),
('yuanqu-2631','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','阿公也恁欢喜，阿波也恁欢喜。',65,'元曲/yuanqu.json','["阿公也恁欢喜，阿波也恁欢喜。", "我阿儿归报，与娘行知会。", "小二出江陵干事归，道娘行交倩买登科记。", "且说张郎作状元，特也特来拜贺喜，拜贺喜。"]'),
('yuanqu-2632','哭妓婆','无名氏《张协状元》','元','元曲','yuanqu','','[]','得两面镜儿，我每好笑。',39,'元曲/yuanqu.json','["得两面镜儿，我每好笑。", "双手把了，时时来照。", "左手照了右手又照，右手照了左手又照。"]'),
('yuanqu-2633','沉醉东风','无名氏《张协状元》','元','元曲','yuanqu','','[]','与张协相别往帝都，我没公婆后有谁相顾。',70,'元曲/yuanqu.json','["与张协相别往帝都，我没公婆后有谁相顾。", "它既然挂绿，立见豪富。", "(末)你不去后谩留此处。", "(合)爹娘又无，弟兄又无。", "不如上国，追寻着丈夫。", "(净)。"]'),
('yuanqu-2634','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','你不曾着那道途，怕一路后怎熬得寒暑？是没裹足，婆婆相助。',41,'元曲/yuanqu.json','["你不曾着那道途，怕一路后怎熬得寒暑？是没裹足，婆婆相助。", "(旦)妾归来后断不敢有负。"]'),
('yuanqu-2635','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','不留伊是它不要汝，你须是早寻着归路。',40,'元曲/yuanqu.json','["不留伊是它不要汝，你须是早寻着归路。", "你不早省，教伊孤苦。", "(净)敢直恁底负它贫女。"]'),
('yuanqu-2636','似娘儿','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协感皇恩，折桂枝平步青云。',37,'元曲/yuanqu.json','["张协感皇恩，折桂枝平步青云。", "望断乡关家山远，修书倩取，专人预先，通报双亲。"]'),
('yuanqu-2637','卖花声','无名氏《张协状元》','元','元曲','yuanqu','','[]','那日红楼数里，要纳夫婿，谁知道苦相嫌弃？(净扶后出接)孩儿饮气，尽日没情没绪。',52,'元曲/yuanqu.json','["那日红楼数里，要纳夫婿，谁知道苦相嫌弃？(净扶后出接)孩儿饮气，尽日没情没绪。", "阿娘怎知，恹恹害自觉着体。"]'),
('yuanqu-2638','雁过沙','无名氏《张协状元》','元','元曲','yuanqu','','[]','那一日过丝鞭，道十分是好姻缘。',72,'元曲/yuanqu.json','["那一日过丝鞭，道十分是好姻缘。", "前遮后拥一少年，绿袍掩映桃花脸，把奴家只苦成抛闪。", "(后低声)被人笑嫁不得一状元。", "(合)被人笑嫁不得一状元。", "(外)。"]'),
('yuanqu-2639','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','大凡事是姻缘，我孩儿莫忧煎。',39,'元曲/yuanqu.json','["大凡事是姻缘，我孩儿莫忧煎。", "侯门相府知有万千，读书人怕没为姻眷，料它每福缘浅。"]'),
('yuanqu-2640','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','请娘子看看，请娘子笑一面。',40,'元曲/yuanqu.json','["请娘子看看，请娘子笑一面。", "休得要两眉蹙远山，吃些个饭食浑莫管，好姻缘怕没为方便。"]'),
('yuanqu-2641','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','孩儿你休要泪涟涟，我与你报仇冤，终不怕它一状元！张协授梓州为佥判。',67,'元曲/yuanqu.json','["孩儿你休要泪涟涟，我与你报仇冤，终不怕它一状元！张协授梓州为佥判。", "(后)苦！听爹爹恁说肠欲断，被人笑嫁不得一状元，被人笑嫁不得一状元。"]'),
('yuanqu-2642','台州歌','无名氏《张协状元》','元','元曲','yuanqu','','[]','亚奴，是人道相公女子好做妇，弗比小人子女穷合穷。',132,'元曲/yuanqu.json','["亚奴，是人道相公女子好做妇，弗比小人子女穷合穷。", "我个胜花娘子生得白蓬蓬，一个头髻长长似盘龙。", "巧小身材子，常着个好千红。", "东华门外傍在小楼东，当初只道个状元迎出似喜相逢，刺起丝鞭两不管，谁知道状元似鬼头风。", "日日吵得亚爹耳朵聋，两三日饭也不吃一口，谁知你今日死了一场空。"]'),
('yuanqu-2643','五方神','无名氏《张协状元》','元','元曲','yuanqu','','[]','庇一方，为神道，镇焦躁。',28,'元曲/yuanqu.json','["庇一方，为神道，镇焦躁。", "要好空口休祷告，非酒非肉莫抛照。"]'),
('yuanqu-2644','望江南','无名氏《张协状元》','元','元曲','yuanqu','','[]','吾显圣，八百有余年。',70,'元曲/yuanqu.json','["吾显圣，八百有余年。", "每岁村公称作主，曾与贫女做场虔，又喜又埋冤。", "张协去，今已夺魁元。", "薄幸冤家成间阻，痴心女子望团圆。", "小圣不能言。", "(末出唱)。"]'),
('yuanqu-2645','乌夜啼','无名氏《张协状元》','元','元曲','yuanqu','','[]','听得你鸡鸣起。',58,'元曲/yuanqu.json','["听得你鸡鸣起。", "(旦出接)扑簌簌泪两下。", "(末)你郎今挂绿在京华。", "(旦)音书断，没成虚假。", "(合)不免辞庙去，京里试寻它。"]'),
('yuanqu-2646','五方神','无名氏《张协状元》','元','元曲','yuanqu','','[]','告尊神：今贫女，上国去。',38,'元曲/yuanqu.json','["告尊神：今贫女，上国去。", "(旦)怕它张协相抛弃，望圣手遮拦奴到京里。", "(净唱)。"]'),
('yuanqu-2647','亭前柳','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协自到京都，及第也没音书。',54,'元曲/yuanqu.json','["张协自到京都，及第也没音书。", "何须得问神道，已成虚。", "(旦)告神奴今只得去。", "(合)近日来，怕迤逦见人疏。", "(旦)。"]'),
('yuanqu-2648','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','它还是把奴辜，实是记不得苦。',55,'元曲/yuanqu.json','["它还是把奴辜，实是记不得苦。", "到京里果不管，下死工夫。", "(净)下梢头有团圆日。", "(旦)既为官，怕迤逦向人疏。", "(末)。"]'),
('yuanqu-2649','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','神道念它孤，平昔未惯出路。',50,'元曲/yuanqu.json','["神道念它孤，平昔未惯出路。", "今日里辞庙去，望相扶。", "(净)见它莫十分出言语。", "(合)怒伊时，怕迤逦向人疏。"]'),
('yuanqu-2650','青玉案','无名氏《张协状元》','元','元曲','yuanqu','','[]','绿袍乍着皇恩重，对答如流圣颜动。',40,'元曲/yuanqu.json','["绿袍乍着皇恩重，对答如流圣颜动。", "谩接丝鞭成何用？思之贫女，要成鸾凤。", "近日浑如梦。"]'),
('yuanqu-2651','赵皮鞋','无名氏《张协状元》','元','元曲','yuanqu','','[]','状元真大才，衙门面向两扇开。',32,'元曲/yuanqu.json','["状元真大才，衙门面向两扇开。", "你还不曾会读书，苍生还相见，休要来。"]'),
('yuanqu-2652','喜迁鸾','无名氏《张协状元》','元','元曲','yuanqu','','[]','喜到宸京，涉山川万般愁闷。',43,'元曲/yuanqu.json','["喜到宸京，涉山川万般愁闷。", "儿夫见免萦奴方寸，未知是何处深藏见在身？遍寻觅，浑不见故人。"]'),
('yuanqu-2653','赵皮鞋','无名氏《张协状元》','元','元曲','yuanqu','','[]','状元是谁敢覆，连它发怒直是毒。',36,'元曲/yuanqu.json','["状元是谁敢覆，连它发怒直是毒。", "你还欲要见它时，如法底高叫：\"奴万福！\"。"]'),
('yuanqu-2654','五更传','无名氏《张协状元》','元','元曲','yuanqu','','[]','这状元，是奴夫婿，奴是它亲娶妻。',66,'元曲/yuanqu.json','["这状元，是奴夫婿，奴是它亲娶妻。", "才得两个月余日，苦相别特来京里。", "买登科记，试看时，是奴夫及第。", "不辞路远来相寻觅，你不知，便教我出去。"]'),
('yuanqu-2655','赵皮鞋','无名氏《张协状元》','元','元曲','yuanqu','','[]','我的状元分付它：官员相见便没奈何。',37,'元曲/yuanqu.json','["我的状元分付它：官员相见便没奈何。", "还是妇女庄家到厅下，十三小杖，把门子打。"]'),
('yuanqu-2656','旦','无名氏《张协状元》','元','元曲','yuanqu','','[]','奴家是状元浑家。',36,'元曲/yuanqu.json','["奴家是状元浑家。", "(净)慢行，慢行，怕头上珠牌脱下来。", "(末)又道路无拾遗。"]'),
('yuanqu-2657','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','是我夫，不相认，见着我忙闭了门。',65,'元曲/yuanqu.json','["是我夫，不相认，见着我忙闭了门。", "我当初闭门不留伊，你及第应是无分。", "千余里，到此来，望你厮存问。", "目下要归我没盘缠，我今宵，更无投奔。"]'),
('yuanqu-2658','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','你记得，要来京里，卖头发把钱与伊。',65,'元曲/yuanqu.json','["你记得，要来京里，卖头发把钱与伊。", "当初道嫁鸡便逐鸡飞，好言语教奴出去！没盘费，教化归，回乡里。", "买炷好香祝苍天，愿你亏心，长长荣贵。"]'),
('yuanqu-2659','太师引','无名氏《张协状元》','元','元曲','yuanqu','','[]','余去载穷途里，被强人劫没那寸缕。',62,'元曲/yuanqu.json','["余去载穷途里，被强人劫没那寸缕。", "张协遂投荒庙，贫女蓦然留住，说化我结为姻契。", "唱名了故来寻觅，都不道朱紫满朝，还知后与阿谁？。"]'),
('yuanqu-2660','一枝花','无名氏《张协状元》','元','元曲','yuanqu','','[]','奴住江陵府，家内多豪贵。',54,'元曲/yuanqu.json','["奴住江陵府，家内多豪贵。", "幼年失恃怙，镇孤苦。", "因往皇都，特特来寻亲故。", "争奈相辜负，裹足全无，怎生底回归乡里！。"]'),
('yuanqu-2661','金钱花','无名氏《张协状元》','元','元曲','yuanqu','','[]','一街两岸英贤，相怜。',42,'元曲/yuanqu.json','["一街两岸英贤，相怜。", "忍辱不敢埋冤，薄贱。", "故乡有路没盘缠，今哀告望怜念，全取我两文钱。"]'),
('yuanqu-2662','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','一街两岸官员，宅眷。',43,'元曲/yuanqu.json','["一街两岸官员，宅眷。", "念奴夫妇不团圆，折散。", "赶奴出去怎留连，千里远没盘缠，全取我两文钱。"]'),
('yuanqu-2663','白','无名氏《张协状元》','元','元曲','yuanqu','','[]','寻取儿夫到此来，奈何薄命此情乖。',37,'元曲/yuanqu.json','["寻取儿夫到此来，奈何薄命此情乖。", "朝朝只好浓霜打，才见春风眼便开。", "(又唱)。"]'),
('yuanqu-2664','满江红','无名氏《张协状元》','元','元曲','yuanqu','','[]','望大贤周济我两文钱，归乡去。',14,'元曲/yuanqu.json','["望大贤周济我两文钱，归乡去。"]'),
('yuanqu-2665','绵搭絮','无名氏《张协状元》','元','元曲','yuanqu','','[]','状元娘子去许多价时，应是到京里，两口儿一对美。',57,'元曲/yuanqu.json','["状元娘子去许多价时，应是到京里，两口儿一对美。", "(净出)记得我，买将归。", "(末白)亚婆，甚物事？(净连唱)许我青铜镜。"]'),
('yuanqu-2666','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','去时春暮子规正啼，如今柳岸前枯，见嫩菊开数枝。',60,'元曲/yuanqu.json','["去时春暮子规正啼，如今柳岸前枯，见嫩菊开数枝。", "料张状元，见它喜，如鱼投水，如胶投漆。", "(净)两个不记得，当初买镜归作土宜。"]'),
('yuanqu-2667','哭梧桐','无名氏《张协状元》','元','元曲','yuanqu','','[]','谁人谁人信道奴，得恁时乖蹇？一路里奔波到京辇，山路到处多巅险。',55,'元曲/yuanqu.json','["谁人谁人信道奴，得恁时乖蹇？一路里奔波到京辇，山路到处多巅险。", "去时团空柳飘绵，归后梧桐更叶乱。", "惭愧见得家乡面。"]'),
('yuanqu-2668','哭梧桐','无名氏《张协状元》','元','元曲','yuanqu','','[]','一路自去时，是奴吃薄贱。',60,'元曲/yuanqu.json','["一路自去时，是奴吃薄贱。", "水远山高甚般价险，谁知见我先抛闪。", "到得宸京讨得眼儿穿，三十六条巷寻得遍，都不见那情人面。", "(净)。"]'),
('yuanqu-2669','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','婆婆望你归，道你为宅眷。',39,'元曲/yuanqu.json','["婆婆望你归，道你为宅眷。", "裙破衣穿瘦着脸，一似乍出卑田院。", "(旦)教化归乡为没钱。"]'),
('yuanqu-2670','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','它还有意时，与你必相见。',65,'元曲/yuanqu.json','["它还有意时，与你必相见。", "(旦)怕日远日疏负奴恩愿。", "(末)寻思那人情忒浅，往复相将是一年。", "(净)记不得伊时须记得俺，我要照着多娇面。"]'),
('yuanqu-2671','望梅花','无名氏《张协状元》','元','元曲','yuanqu','','[]','谢得我尊神也，被张协直恁底误呵。',37,'元曲/yuanqu.json','["谢得我尊神也，被张协直恁底误呵。", "一似哑子，吃了苦瓜。", "到如今，教我吞吐不下。"]'),
('yuanqu-2672','河传','无名氏《张协状元》','元','元曲','yuanqu','','[]','瓜期到矣，离征鞍着鞭，迤逦前去。',40,'元曲/yuanqu.json','["瓜期到矣，离征鞍着鞭，迤逦前去。", "春到柳塘，冰释鱼游春水。", "山嵯峨，蓦山溪，玩佳致。"]'),
('yuanqu-2673','上堂水陆','无名氏《张协状元》','元','元曲','yuanqu','','[]','衣锦归故乡。',14,'元曲/yuanqu.json','["衣锦归故乡。", "(合)我门得意。"]'),
('yuanqu-2674','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','回首望帝京。',69,'元曲/yuanqu.json','["回首望帝京。", "(合)水村隔住。", "(末)长亭共短亭。", "(合)休斟绿蚁。", "(末)恩官教你快行。", "(合)领台旨。", "(末)目即便离城。", "(合)不觉过一里又一里。"]'),
('yuanqu-2675','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','行得气喘。',68,'元曲/yuanqu.json','["行得气喘。", "(合)肚中饥馁。", "(丑)都不见打火。", "(合)歇歇了去。", "(生)不行时我打你。", "(合)领台旨。", "(丑)涉溪东渡水。", "(合)不觉过一里又一里。"]'),
('yuanqu-2676','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','江陵在眼前。',69,'元曲/yuanqu.json','["江陵在眼前。", "(合)五鸡山至。", "(净)如投着地脉。", "(合)不辞迢递。", "(生)快行时我赏你。", "(合)领台旨。", "(净)回马不用鞭。", "(合)不觉过一里又一里。"]'),
('yuanqu-2677','天下乐','无名氏《张协状元》','元','元曲','yuanqu','','[]','春到郊原日迟迟，枪旗展山谷里。',30,'元曲/yuanqu.json','["春到郊原日迟迟，枪旗展山谷里。", "幽居古庙浑无侣，采些茶为活计。"]'),
('yuanqu-2678','秋江送别','无名氏《张协状元》','元','元曲','yuanqu','','[]','徐徐步野径，晓痕青柳弄金。',67,'元曲/yuanqu.json','["徐徐步野径，晓痕青柳弄金。", "东风尚料峭，丽日升寒渐轻。", "(生出)记得年时投上国，早一年珠泪泠。", "此山又登，此身渐亨，是你否极还泰生。", "(旦)。"]'),
('yuanqu-2679','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','山高处个人，好似奴家张解元。',75,'元曲/yuanqu.json','["山高处个人，好似奴家张解元。", "(生)山脚下个人，似贫女衣恁单。", "(旦)天愿得儿夫厮撞见，问冤家心恁底偏。", "(生)是贫女来。", "(旦)是张解元，我今日会重见面！。"]'),
('yuanqu-2680','刮鼓令','无名氏《张协状元》','元','元曲','yuanqu','','[]','君恩怒少停，且容奴说与你听：大雪下被强人劫去，到古庙奴救你，我为你几艰辛。',69,'元曲/yuanqu.json','["君恩怒少停，且容奴说与你听：大雪下被强人劫去，到古庙奴救你，我为你几艰辛。", "登科到喜欢奴到京，(合)缘何一向便生嗔？你门直是没前程。", "(生)。"]'),
('yuanqu-2681','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','伊前日到京，我不成留住你，敢说道我浑家来至，我荣贵伊恁贫。',54,'元曲/yuanqu.json','["伊前日到京，我不成留住你，敢说道我浑家来至，我荣贵伊恁贫。", "我不道你痴心，别寻个计结来闭门。", "(合同前)(旦)。"]'),
('yuanqu-2682','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','同连理至诚，我许多恩情陪伴你。',55,'元曲/yuanqu.json','["同连理至诚，我许多恩情陪伴你。", "卖头发得钱为盘费，雁塔上题姓名。", "跋涉到宸京，教门子打得身上疼。", "(合同前)(生)。"]'),
('yuanqu-2683','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','一心要离京，是州城不暂停。',49,'元曲/yuanqu.json','["一心要离京，是州城不暂停。", "我与伊家欢笑，骂得我恶气生。", "说一和你惺惺，才相见剪头来骂人。", "(合同前)。"]'),
('yuanqu-2684','步步娇','无名氏《张协状元》','元','元曲','yuanqu','','[]','仙卉丛丛春来早，蓓蕾在枝头少。',45,'元曲/yuanqu.json','["仙卉丛丛春来早，蓓蕾在枝头少。", "公公去采樵，小二往田头，看秧苗。", "见说嫩茶偏好，每日还婆一到。"]'),
('yuanqu-2685','打球场','无名氏《张协状元》','元','元曲','yuanqu','','[]','论娘行，见茶便折，缘何到翻了吃跌？莫是有人来阴害你，浑身尽都是鲜血。',39,'元曲/yuanqu.json','["论娘行，见茶便折，缘何到翻了吃跌？莫是有人来阴害你，浑身尽都是鲜血。", "(旦唱)。"]'),
('yuanqu-2686','香遍满','无名氏《张协状元》','元','元曲','yuanqu','','[]','公婆且住，待奴家款款松口气说：独立岩头攀茶来折，岂知道失脚，似刀斫臂折。',53,'元曲/yuanqu.json','["公婆且住，待奴家款款松口气说：独立岩头攀茶来折，岂知道失脚，似刀斫臂折。", "(合)遭一跌，寸肠千百结。", "(末)。"]'),
('yuanqu-2687','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','伊回京阙，没一日暂时得少歇，织素织缣不宁贴。',42,'元曲/yuanqu.json','["伊回京阙，没一日暂时得少歇，织素织缣不宁贴。", "这般时运，这般恶岁月。", "(合同前)(净)。"]'),
('yuanqu-2688','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','伊才跌下，那得遍身都是血，宁可将伊脚骨跌折。',40,'元曲/yuanqu.json','["伊才跌下，那得遍身都是血，宁可将伊脚骨跌折。", "采茶人无数，你门直是拙。", "(合同前)。"]'),
('yuanqu-2689','金牌郎','无名氏《张协状元》','元','元曲','yuanqu','','[]','我扶你门归去。',57,'元曲/yuanqu.json','["我扶你门归去。", "(合)我扶你门归去，勉强且行着山路。", "(旦)我门直是孤苦。", "(合)先是被人欺负，你下得直是淋漉。", "(旦)。"]'),
('yuanqu-2690','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','我门几时得好？(合)我们几时得好？只得去寻些药草。',52,'元曲/yuanqu.json','["我门几时得好？(合)我们几时得好？只得去寻些药草。", "(净)我儿休要烦恼。", "(合)款款回归古庙，只得靠着神道。"]'),
('yuanqu-2691','薄幸','无名氏《张协状元》','元','元曲','yuanqu','','[]','春日融和，江山秀丽。',40,'元曲/yuanqu.json','["春日融和，江山秀丽。", "记孩儿贪爱，这般天气。", "名园里，蹙秋千斗草嬉。", "你神魂在那里？。"]'),
('yuanqu-2692','临江仙','无名氏《张协状元》','元','元曲','yuanqu','','[]','庭院深沉日正永。',46,'元曲/yuanqu.json','["庭院深沉日正永。", "(净出接)杨花点点沾襟。", "(丑)许多侍婢汝知音。", "(末)梓州今一任，你去直夫人。"]'),
('yuanqu-2693','马鞍儿','无名氏《张协状元》','元','元曲','yuanqu','','[]','唱彻《阳关》斟别酒，这一景最清佳。',77,'元曲/yuanqu.json','["唱彻《阳关》斟别酒，这一景最清佳。", "夹岸见这山叠翠，尽间簇山花野花。", "(末)听得丁宁祝付，小心伏事恩家。", "(丑)(合)都乘轿儿先去，俺待跨马，匆匆去也。", "(后)。"]'),
('yuanqu-2694','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','唱彻《阳关》人凄惨，路途里景潇洒。',60,'元曲/yuanqu.json','["唱彻《阳关》人凄惨，路途里景潇洒。", "绿水绕人处，细柳拂波心嫩荷。", "(净)去意浑如奔骑，目即早离京华。", "(丑)(合同前)(末)。"]'),
('yuanqu-2695','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','唱彻《阳关》离故里，梓州路在天涯。',61,'元曲/yuanqu.json','["唱彻《阳关》离故里，梓州路在天涯。", "诸般仗都搬发了，请早乘香车宝马。", "(净后)二妾目今先去，少歇时等取恩家。", "(丑)(合同前)。"]'),
('yuanqu-2696','锦缠道','无名氏《张协状元》','元','元曲','yuanqu','','[]','苦天天，几年来劳笼着万千，寻思自埋冤。',79,'元曲/yuanqu.json','["苦天天，几年来劳笼着万千，寻思自埋冤。", "少它张协债负，是奴前缘。", "大雪下身无寸缕，投古庙泪珠涟涟。", "奴家便相怜，与它身衣口食。", "教人说化我，共它成因眷，只图它共百年。"]'),
('yuanqu-2697','川拨棹','无名氏《张协状元》','元','元曲','yuanqu','','[]','为孩儿，特特来蜀地。',30,'元曲/yuanqu.json','["为孩儿，特特来蜀地。", "满目薄芜见古庙，教人转悲，我寻思珠泪垂。"]'),
('yuanqu-2698','长相思','无名氏《张协状元》','元','元曲','yuanqu','','[]','好因缘，恶因缘。',186,'元曲/yuanqu.json','["好因缘，恶因缘。", "儿又青春正少年，那堪遇状元。", "儿分悭，子分悭。", "马上徘徊不接鞭，浓婚结厚冤。", "(末出白)覆夫人：前无旅店，后绝茅檐，村市人家难以安泊，古庙中可以少歇。", "(外)相公来未？(末)相公下马来。", "(丑)帮帮八帮帮。", "(叫)具报！(末)具报甚人？(丑)下官下马多时，马后乐只管八帮帮帮。", "(末)好，具报你。", "(丑)夫人，你看一堂神道塑得精神。", "(外)也是精神。", "(丑)你看小鬼到长丈二。"]'),
('yuanqu-2699','桃红菊','无名氏《张协状元》','元','元曲','yuanqu','','[]','野方直入庙中，见一佳人困穷。',30,'元曲/yuanqu.json','["野方直入庙中，见一佳人困穷。", "似胜花娘子无异，血染得衣衫煞红。"]'),
('yuanqu-2700','香柳娘','无名氏《张协状元》','元','元曲','yuanqu','','[]','数十年庙中，少人存问。',72,'元曲/yuanqu.json','["数十年庙中，少人存问。", "独自做人了，浑没投奔。", "(后)你出来勉强作礼，叫夫人霍索你方寸。", "(旦)奴家万福！万福！寻思断魂。", "(合)你缘何愁闷？(丑唱)。"]'),
('yuanqu-2701','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','眉儿和那眼儿，与我儿无二，身材袅娜腰肢细。',70,'元曲/yuanqu.json','["眉儿和那眼儿，与我儿无二，身材袅娜腰肢细。", "(外)我瞥见你门，心下便怜伊。", "因甚脸憔翠？(后)不知怎底？怎底？鲜血污衣。", "(合)缘何如是？(旦)。"]'),
('yuanqu-2702','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','念妾自幼来，清贫守己。',66,'元曲/yuanqu.json','["念妾自幼来，清贫守己。", "只因去采茶，跌却一臂。", "(外)你独自那得粥食，与药草将息你容仪？(旦)前村自有大公，相怜爱惜。", "(合)是前生宿契。"]'),
('yuanqu-2703','太子游四门','无名氏《张协状元》','元','元曲','yuanqu','','[]','奴本世豪奢，爹娘怜妾多。',49,'元曲/yuanqu.json','["奴本世豪奢，爹娘怜妾多。", "年幼两俱亡，是奴贫苦多。", "织素与缉麻，春来采茶。", "怎知一跌了那臂，有谁人管呵。"]'),
('yuanqu-2704','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','媳妇建官人，官人莫是贫女亲？在古庙五六春，有谁人采您！山上采茶芽，跌一臂膊损。',59,'元曲/yuanqu.json','["媳妇建官人，官人莫是贫女亲？在古庙五六春，有谁人采您！山上采茶芽，跌一臂膊损。", "告夫人周全此身，又何须去施贫。", "(丑唱)。"]'),
('yuanqu-2705','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','吾乃赫王相公，今判梓州郡。',63,'元曲/yuanqu.json','["吾乃赫王相公，今判梓州郡。", "贫女身上狼狈，我女近才丧亡，脸儿相类恁精神。", "夫人要为养女，汝若故生阻节，堂后官，缚在马前别有施行！。"]'),
('yuanqu-2706','鹅鸭满渡船','无名氏《张协状元》','元','元曲','yuanqu','','[]','论妾家豪贵，又岂得随人去。',13,'元曲/yuanqu.json','["论妾家豪贵，又岂得随人去。"]'),
('yuanqu-2707','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','细想吾一女，比它仪容美。',38,'元曲/yuanqu.json','["细想吾一女，比它仪容美。", "(外)所为及张协，悄无二。", "(后)奴家煮些粥食伊去吃。"]'),
('yuanqu-2708','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','劝你休窨约，随去你福至。',82,'元曲/yuanqu.json','["劝你休窨约，随去你福至。", "(合)最好俱丰足，衣共食随汝意。", "(净)从小我惜伊，伊去婆亦去。", "(合)病尤未可。", "(净)婆一路当直你。", "(合)厮系绾免忧虑，成伴侣几风味。", "(净)。"]'),
('yuanqu-2709','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','我公休去你门家里，好好看孩儿。',15,'元曲/yuanqu.json','["我公休去你门家里，好好看孩儿。"]'),
('yuanqu-2710','蛮牌令','无名氏《张协状元》','元','元曲','yuanqu','','[]','一意要读诗书，一身望改换门闾。',59,'元曲/yuanqu.json','["一意要读诗书，一身望改换门闾。", "一路到京里受钳锤，一查打得浑身破损，一妻济不得吾儒。", "一举早题雁塔，第一是张协，方表勤渠。"]'),
('yuanqu-2711','金莲花','无名氏《张协状元》','元','元曲','yuanqu','','[]','谩然回首望京城。',72,'元曲/yuanqu.json','["谩然回首望京城。", "(外出)瑞烟平，咸肃静。", "(旦出)吴江一派水泠泠。", "(后出)蜀山青，侵碧汉。", "(合)但见连云栈，听得野猿声，真个是帏屏。", "也罗。", "(后)。"]'),
('yuanqu-2712','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','新来似娘子貌妖娆。',63,'元曲/yuanqu.json','["新来似娘子貌妖娆。", "(合)脸桃花，檀口小。", "(外)今朝梳裹胜儿曹。", "(合)夜合花，斜插带。", "金为凤，翠为翘，莫道胜花娇。", "也罗。", "(旦)。"]'),
('yuanqu-2713','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','孩儿疮疾幸然干。',60,'元曲/yuanqu.json','["孩儿疮疾幸然干。", "(合)自今番，常打扮。", "(后)沉香亭畔倚阑杆。", "(合)夜合花，红牡丹。", "姚黄间满，这太湖仙，真个最堪观。", "也罗。"]'),
('yuanqu-2714','夜游湖','无名氏《张协状元》','元','元曲','yuanqu','','[]','合那官员有万千。',41,'元曲/yuanqu.json','["合那官员有万千。", "(丑)甚人才先来拜见。", "(净)小子名为柳屯田。", "(合)揖揖两个通寒暄。"]'),
('yuanqu-2715','五韵美','无名氏《张协状元》','元','元曲','yuanqu','','[]','洒家即日共维。',67,'元曲/yuanqu.json','["洒家即日共维。", "(丑)间阔不见你多时。", "(净)洒家一向，关西冗迫，不及通书。", "(丑)下车未及参侍。", "(净)降接不胜欣喜。", "(丑)首辱光访甚得罪。"]'),
('yuanqu-2716','生查子','无名氏《张协状元》','元','元曲','yuanqu','','[]','不见去年人，心事谁知得！。',13,'元曲/yuanqu.json','["不见去年人，心事谁知得！。"]'),
('yuanqu-2717','缠枝花','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协是我不接见。',64,'元曲/yuanqu.json','["张协是我不接见。", "(末)领钧旨教逐便。", "(生揖)长官，既蒙天眷，望特赐相荐。", "(末)告恩官免叱谴。", "(丑)到把那驴骑转，永不见这畜生面。"]'),
('yuanqu-2718','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','张协也无触犯，怕礼数供不惯。',41,'元曲/yuanqu.json','["张协也无触犯，怕礼数供不惯。", "(丑)你不接丝鞭后，哭损我一双眼。", "(生)协后知悔已晚。"]'),
('yuanqu-2719','一枝花','无名氏《张协状元》','元','元曲','yuanqu','','[]','孩儿过来，试出幽闺，徐步花街。',58,'元曲/yuanqu.json','["孩儿过来，试出幽闺，徐步花街。", "(旦出)喜奴今日会开怀，是这花如锦，柳垂带。", "(后净出合)穿红度绿，折朵奇葩带，奇葩带。"]'),
('yuanqu-2720','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','名园郡圃，是处秋千，花板争蹙。',15,'元曲/yuanqu.json','["名园郡圃，是处秋千，花板争蹙。"]'),
('yuanqu-2721','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','脚下转身，相公特特，教请夫人。',15,'元曲/yuanqu.json','["脚下转身，相公特特，教请夫人。"]'),
('yuanqu-2722','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','明日坐庭，状元来时，教立到天明。',16,'元曲/yuanqu.json','["明日坐庭，状元来时，教立到天明。"]'),
('yuanqu-2723','桃柳争放','无名氏《张协状元》','元','元曲','yuanqu','','[]','丝鞭刺起选英贤，苦不肯秋采，今朝奈何都来。',38,'元曲/yuanqu.json','["丝鞭刺起选英贤，苦不肯秋采，今朝奈何都来。", "接郡相逢，有谁人可介？叫左右过来。"]'),
('yuanqu-2724','山坡羊','无名氏《张协状元》','元','元曲','yuanqu','','[]','协惶恐再拜，常侍眷爱，苦屈大才，少慰下怀。',48,'元曲/yuanqu.json','["协惶恐再拜，常侍眷爱，苦屈大才，少慰下怀。", "不沐劝介，必成祸胎，专等左右过来。", "不宣。", "张协惶恐再拜。"]'),
('yuanqu-2725','红衲袄','无名氏《张协状元》','元','元曲','yuanqu','','[]','洒伏辱云函至。',17,'元曲/yuanqu.json','["洒伏辱云函至。", "(生)荷足下特步砌。"]'),
('yuanqu-2726','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','相公是协故人，为及第不议它亲。',53,'元曲/yuanqu.json','["相公是协故人，为及第不议它亲。", "遂特来判此一郡，今日见协骨恁嗔。", "来命君，来命君。", "欲要介和，浑没个因。", "(净)。"]'),
('yuanqu-2727','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','洒出自相公庇，论人情常是美。',52,'元曲/yuanqu.json','["洒出自相公庇，论人情常是美。", "见说一女已倾弃，人道却有一女奇。", "若是时，若是时，却当与君，作个道理。", "(末)。"]'),
('yuanqu-2728','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','那丝鞭刺在马前，再三教接不接那鞭。',56,'元曲/yuanqu.json','["那丝鞭刺在马前，再三教接不接那鞭。", "胜花娘子早赴黄泉。", "若得再合出自大贤。", "(合)缺又圆，缺又圆，却与后人，作个话传。"]'),
('yuanqu-2729','引番子','无名氏《张协状元》','元','元曲','yuanqu','','[]','即刻共惟，判府相公。',64,'元曲/yuanqu.json','["即刻共惟，判府相公。", "有少事，特欲来相议，见夫人只怕失礼。", "(丑)唤我儿和夫人至，出来这里，休要致疑。", "(合)既是亲戚，亲戚不妨对席。"]'),
('yuanqu-2730','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','闻道是关西，老将太尉。',62,'元曲/yuanqu.json','["闻道是关西，老将太尉。", "(净)本不敢，直入来谒见，托在同官，又是亲戚。", "请郡主出来这里，听洒拜启，休要致疑。", "(合同前)(旦出)。"]'),
('yuanqu-2731','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','徐步金莲，款款步砌。',64,'元曲/yuanqu.json','["徐步金莲，款款步砌。", "(外丑)这老将，却是我亲契。", "(旦)万福不罪，未及参侍。", "(净)这郡主洒不曾见，生得恁奇，休要致疑。", "(合同前)。"]'),
('yuanqu-2732','浆水令','无名氏《张协状元》','元','元曲','yuanqu','','[]','告莫说张状元，才说后泪涟涟。',14,'元曲/yuanqu.json','["告莫说张状元，才说后泪涟涟。"]'),
('yuanqu-2733','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','洒特特来拜侍。',18,'元曲/yuanqu.json','["洒特特来拜侍。", "(外丑)方知道是不弃。"]'),
('yuanqu-2734','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','细寻思常怒起。',18,'元曲/yuanqu.json','["细寻思常怒起。", "(合)因它后丧一女儿。"]'),
('yuanqu-2735','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','怕奴家福分悭。',17,'元曲/yuanqu.json','["怕奴家福分悭。", "(合)夫妻事是前缘。"]'),
('yuanqu-2736','红芍药','无名氏《张协状元》','元','元曲','yuanqu','','[]','才宴罢琼林，出东华门外，彩楼直下刺丝鞭，将谓喜欢接取。',57,'元曲/yuanqu.json','["才宴罢琼林，出东华门外，彩楼直下刺丝鞭，将谓喜欢接取。", "张协此心不在彼，只欲要耀吾闾里。", "岂知接取相公冤，今日尚不已。"]'),
('yuanqu-2737','生姜牙','无名氏《张协状元》','元','元曲','yuanqu','','[]','洒亲曾见，谩致疑。',58,'元曲/yuanqu.json','["洒亲曾见，谩致疑。", "目下免得相轻视，目下料得没言语。", "孩儿甚般价，多殊丽。", "(合)五百年前是因缘，君今打合成一对。", "(生)。"]'),
('yuanqu-2738','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','初不道，事恁地。',42,'元曲/yuanqu.json','["初不道，事恁地。", "一心自欲荣闾里，一心又欲多殊翠。", "谁知公相，成嗔讳。", "(合同前)(净)。"]'),
('yuanqu-2739','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','这孩儿出，步恁迟。',43,'元曲/yuanqu.json','["这孩儿出，步恁迟。", "天生似玉肌肤腻，天生又得为夫婿。", "今番且免，争闲气。", "(合同前)(生)。"]'),
('yuanqu-2740','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','非公如是，事怎底？今番定做风流婿，今番且免鸳鸯拆。',40,'元曲/yuanqu.json','["非公如是，事怎底？今番定做风流婿，今番且免鸳鸯拆。", "便教选日，成匹配。", "(合同前)。"]'),
('yuanqu-2741','斗双鸡','无名氏《张协状元》','元','元曲','yuanqu','','[]','幞头儿，幞头儿，甚般价好。',59,'元曲/yuanqu.json','["幞头儿，幞头儿，甚般价好。", "花儿闹，花儿闹，佐得恁巧。", "伞儿簇得绝妙，刺起恁地高，风儿又飘。", "(末)好似傀儡棚前，一个鲍老。"]'),
('yuanqu-2742','紫苏丸','无名氏《张协状元》','元','元曲','yuanqu','','[]','蓬莱路不远，两情休怨夤缘浅。',32,'元曲/yuanqu.json','["蓬莱路不远，两情休怨夤缘浅。", "只听得丝竹管弦声，料今宵得遂鸳鸯愿。"]'),
('yuanqu-2743','迎仙客','无名氏《张协状元》','元','元曲','yuanqu','','[]','谁信道，是因缘，即日蒙恩贺万全。',16,'元曲/yuanqu.json','["谁信道，是因缘，即日蒙恩贺万全。"]'),
('yuanqu-2744','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','协冒渎，望周全，到此谁知月再圆。',16,'元曲/yuanqu.json','["协冒渎，望周全，到此谁知月再圆。"]'),
('yuanqu-2745','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','……。',3,'元曲/yuanqu.json','["……。"]'),
('yuanqu-2746','幽花子','无名氏《张协状元》','元','元曲','yuanqu','','[]','盖头试待都揭起。',80,'元曲/yuanqu.json','["盖头试待都揭起。", "(后)春胜也不须留住。", "(合)天生缘分克定，好一对夫妻。", "(旦)张协记得斩却奴一臂？如今怎得成匹配！(丑绰住)(外)爹爹息怒，听取我儿拜启。", "(生)。"]'),
('yuanqu-2747','同前换头','无名氏《张协状元》','元','元曲','yuanqu','','[]','雄威暂息，听取张协，禀许多详细。',80,'元曲/yuanqu.json','["雄威暂息，听取张协，禀许多详细。", "(外)孩儿你说破它何亏负？(旦)启初张协被贼劫尽，庙中来投睡。", "一查击损，奴供乃衣乃食。", "续得遂成姻契，及第怎接丝鞭娶别底？(合)。"]'),
('yuanqu-2748','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','既当初已得做夫妻，今日天教重会。',64,'元曲/yuanqu.json','["既当初已得做夫妻，今日天教重会。", "休得要恁说，目前事不是。", "(旦)卖头发相助到京畿，一举鳌头及第。", "教门子打出，临了斩一臂。", "(外唱)。"]'),
('yuanqu-2749','和佛儿','无名氏《张协状元》','元','元曲','yuanqu','','[]','贤既晓文墨不当恁地。',18,'元曲/yuanqu.json','["贤既晓文墨不当恁地。", "(合)没道理！。"]'),
('yuanqu-2750','红绣鞋','无名氏《张协状元》','元','元曲','yuanqu','','[]','状元与婆婆施礼。',72,'元曲/yuanqu.json','["状元与婆婆施礼。", "(合)不易。", "(生)婆婆忘了你容仪。", "(合)谁氏？(净)李大公，那婆婆，随娘子去，弃了儿女。", "施粉朱，来到此处，如何认不得？(旦唱)。"]'),
('yuanqu-2751','越恁好','无名氏《张协状元》','元','元曲','yuanqu','','[]','大公家里，有万千恩共义。',71,'元曲/yuanqu.json','["大公家里，有万千恩共义。", "(合)都休要恁说，交欢处饮三杯。", "(丑)从今两情如鱼似水。", "日前那怨语，(合)如今尽撇在东流水，如今尽撇在东流水。", "(外)。"]'),
('yuanqu-2752','同前','无名氏《张协状元》','元','元曲','yuanqu','','[]','好儿好女，两情厮绾系。',61,'元曲/yuanqu.json','["好儿好女，两情厮绾系。", "(合)如鸾凤对双飞，都夸道郑州梨。", "(净)当初许我青铜镜儿，今番定有，一面也买归家里，百面也得归家里。"]'),
('yuanqu-2753','南吕・一枝花咏剑','施惠','元','元曲','yuanqu','','[]','离匣牛斗寒，到手风云助，插腰奸胆破，出袖鬼神伏。',63,'元曲/yuanqu.json','["离匣牛斗寒，到手风云助，插腰奸胆破，出袖鬼神伏。", "正直规模，香檀把虎口双吞玉，沙鱼鞘龙鳞密砌珠。", "挂三尺壁上飞泉，响半夜床头骤雨。"]'),
('yuanqu-2754','梁州・金错落盘花扣挂，碧玲珑镂玉妆束，美名儿今古人争慕。弹鱼空馆，','施惠','元','元曲','yuanqu','','[]','断蟒长途，逢贤把赠，遇寇即除。',103,'元曲/yuanqu.json','["断蟒长途，逢贤把赠，遇寇即除。", "比镆铘端的全殊，纵干将未必能如。", "曾遭遇诤朝才烈士朱云，能回避叹苍穹雄天项羽，怕追陪报私仇侠客专诸。", "价孤，世无，数十年是俺家藏物。", "吓人魂，射人目，相伴着万卷图书酒一壶，遍历江湖。"]'),
('yuanqu-2755','尾声・笑提常向尊前舞，醉解多从醒后赎，则为俺未遂封侯把他久担误。','施惠','元','元曲','yuanqu','','[]','有一日修文用武，驱蛮静虏，好与清时定边土。',21,'元曲/yuanqu.json','["有一日修文用武，驱蛮静虏，好与清时定边土。"]'),
('yuanqu-2756','仙吕・点绛唇','王大学士','元','元曲','yuanqu','','[]','探卷抽签，看书学剑，皆是虚谄。',30,'元曲/yuanqu.json','["探卷抽签，看书学剑，皆是虚谄。", "指望待折桂攀蟾，谁承望无凭验。"]'),
('yuanqu-2757','混江龙・少年风欠，老来赢得病恹恹。自忖身居村野，几时曾再想闾阎。','王大学士','元','元曲','yuanqu','','[]','四面土墙缺处补，二椽茅屋破时添，且把时光渐。',38,'元曲/yuanqu.json','["四面土墙缺处补，二椽茅屋破时添，且把时光渐。", "落一个身心自在，煞强如名利拘箝。"]'),
('yuanqu-2758','天下乐・一个黄桑叶拈将来额上粘，一个那里磨镰。一个将榆树舔，一个','王大学士','元','元曲','yuanqu','','[]','树梢头ㄋ歌不怕险。',40,'元曲/yuanqu.json','["树梢头ㄋ歌不怕险。", "一个吊小鬼的灰抹眉，一个扮判官的墨画了髯，一个扮牛王着土抢脸。"]'),
('yuanqu-2759','后庭花・一个调灰驴的将脚面闪，一个学相扑的手腕来扌扇。一个革刃将','王大学士','元','元曲','yuanqu','','[]','葫瓜割，一个棘针将酸枣签。',58,'元曲/yuanqu.json','["葫瓜割，一个棘针将酸枣签。", "一个把鹊儿拈，一个手拖着席片。", "一个瓦[A12N][A12N]衮罢合掂，一个泥窝窝ㄏ破合添。"]'),
('yuanqu-2760','柳叶儿・一个把绿蓑衣披苫，一个将布留儿风彡，一味的掀ㄎ。一个撮金','王大学士','元','元曲','yuanqu','','[]','钱手扌若着衣襟验，一个寻方门任谁嫌，一个挑蜂窠不离房檐。',28,'元曲/yuanqu.json','["钱手扌若着衣襟验，一个寻方门任谁嫌，一个挑蜂窠不离房檐。"]'),
('yuanqu-2761','仙吕・点绛唇','王大学士','元','元曲','yuanqu','','[]','丰稔年华，酒旗斜插。',27,'元曲/yuanqu.json','["丰稔年华，酒旗斜插。", "茅檐下，小桥流水人家，一带山如画。"]'),
('yuanqu-2762','混江龙・桔槔闲挂，呼童汲水旋烹茶。柔桑荏苒，古柏槎牙。雾锁草桥三','王大学士','元','元曲','yuanqu','','[]','四横，烟笼茅舍数十家。',85,'元曲/yuanqu.json','["四横，烟笼茅舍数十家。", "岗盘曲畎兜答，莺迁乔木丘篆。", "一个鸥鹭水面，雁落平沙。", "喧檐宿雀，啼树栖鸦。", "柴扉吠犬，鼓吹鸣蛙。", "侬家鹦鹉洲，不入麒麟画。", "百姓每讴歌鼓腹，一弄儿笑语喧哗。"]'),
('yuanqu-2763','油葫芦・刚儿一百个儿童刀刀厥厥的耍，更那堪景物佳。一个将尧民歌乱','王大学士','元','元曲','yuanqu','','[]','唱的令儿差，一个匹风彡扑冬冬擂鼓无高下，一个支周知挣羌管吹难收煞。',73,'元曲/yuanqu.json','["唱的令儿差，一个匹风彡扑冬冬擂鼓无高下，一个支周知挣羌管吹难收煞。", "一个水盆里击着料瓜，一个拖床上拍着布瓦，一个一张锨舞得了千斤乍，一个学舞斗虾蟆。"]'),
('yuanqu-2764','天下乐・一个道一阵黄风一阵沙，一个天生丑势煞，一个无店三碌轴上闲','王大学士','元','元曲','yuanqu','','[]','坐衙。',26,'元曲/yuanqu.json','["坐衙。", "一个将斤斗番，一个将背抛打，一个响扑儿学咯牙。"]'),
('yuanqu-2765','那吒令・一个向瓜田里坐树乱扯，一个向枣树上胡风彡乱打，一个向古墓','王大学士','元','元曲','yuanqu','','[]','上番砖弄瓦。',27,'元曲/yuanqu.json','["上番砖弄瓦。", "一个扯着衣衫，一个揪住棍把，一个播土扬沙。"]'),
('yuanqu-2766','鹊踏枝・一个眼麻花，一个手支沙，一个浅水涡里摸鳖捞虾。一个见麒麟','王大学士','元','元曲','yuanqu','','[]','打煞，一个舞着唱着匾担禾叉。',14,'元曲/yuanqu.json','["打煞，一个舞着唱着匾担禾叉。"]'),
('yuanqu-2767','寄生草・一个擎着山鹧，一个架着老鸦。一个向柳阴中笑把人头画，一个','王大学士','元','元曲','yuanqu','','[]','向桑园里学揭龟儿卦，一个向墙匡里引的芒郎骂。',45,'元曲/yuanqu.json','["向桑园里学揭龟儿卦，一个向墙匡里引的芒郎骂。", "一个跳灰驴大闹麦场头，一个踏竹马偃卧在葫芦架。"]'),
('yuanqu-2768','金盏儿・一个叫丫丫，一个笑呷呷。一个棘斜混倒上树千般耍，一个山声','王大学士','元','元曲','yuanqu','','[]','野调学唱搅筝琶。',47,'元曲/yuanqu.json','["野调学唱搅筝琶。", "一个斗巨子抢了嘴问，一个竖直立的磕了门牙。", "一个无人处寻豆角，一个背地里咽生瓜。"]'),
('yuanqu-2769','元和令・一个舞乔捉蛇呆木答，一个舞屎裹蛆的法刀把，一个跳百索扌颠','王大学士','元','元曲','yuanqu','','[]','背儿仰剌叉。',42,'元曲/yuanqu.json','["背儿仰剌叉。", "一个一个儿窝的眼又瞎，一个将纸鸦儿放起盼的人眼睛花，一个递撇牛的没乱杀。"]'),
('yuanqu-2770','上马娇・一个村，一个又沙，一个丑嘴脸特胡沙。一个将花桑树纽捏搬调','王大学士','元','元曲','yuanqu','','[]','话，一个打和的差，一个不剌着簸箕拨琵琶。',20,'元曲/yuanqu.json','["话，一个打和的差，一个不剌着簸箕拨琵琶。"]'),
('yuanqu-2771','青哥儿・一个牛斤，一个谎诈，一个光答答又无头发。一个蒙松雨里种芝','王大学士','元','元曲','yuanqu','','[]','一个兜答，一个奸滑。',36,'元曲/yuanqu.json','["一个兜答，一个奸滑。", "一个交加，一个皱查。", "这一坐乔民闹交加，定害的爷娘骂。"]'),
('yuanqu-2772','南吕・一枝花辞官','孛罗御史','元','元曲','yuanqu','','[]','懒簪獬豸冠，不入麒麟画。',64,'元曲/yuanqu.json','["懒簪獬豸冠，不入麒麟画。", "旋栽陶令菊，学种邵平瓜。", "觑不的闹穰穰蚁阵蜂衙，卖了青骢马，换耕牛度岁华。", "利名场再不行踏，风波海其实怕他。"]'),
('yuanqu-2773','梁州・尽燕雀喧檐聒耳，任豺狼当道磨牙。无官守无言责相牵挂。春风桃','孛罗御史','元','元曲','yuanqu','','[]','李，夏月桑麻，秋天禾黍，冬月梅茶。',95,'元曲/yuanqu.json','["李，夏月桑麻，秋天禾黍，冬月梅茶。", "四时景物清佳，一门和气欢洽。", "叹子牙渭水垂钓，胜潘岳河阳种花，笑张骞河汉乘槎。", "这家，那家，黄鸡白酒安排下，撒会顽放会耍。", "拚着老瓦盆边醉后扶，一任他风落了乌纱。"]'),
('yuanqu-2774','牧羊关・王大户相邀请，赵乡司扶下马，则听得扑冬冬社鼓频挝。有几个','孛罗御史','元','元曲','yuanqu','','[]','不求仕的官员，东庄措大，他每都拍手歌丰稔，俺再不想巡案去奸猾。',45,'元曲/yuanqu.json','["不求仕的官员，东庄措大，他每都拍手歌丰稔，俺再不想巡案去奸猾。", "御史台开除我，尧民图添上咱。"]'),
('yuanqu-2775','贺新郎・奴耕婢织足生涯，随分村疃人情，赛强如宪台风化。趁一溪流水','孛罗御史','元','元曲','yuanqu','','[]','浮鸥鸭，小桥掩映蒹葭。',43,'元曲/yuanqu.json','["浮鸥鸭，小桥掩映蒹葭。", "芦花千顷雪，红树一川霞，长江落日牛羊下。", "山中闲宰相，林外野人家。"]'),
('yuanqu-2776','隔尾・诵诗书稚子无闲暇，奉甘旨萱堂到白发，伴辘轳村翁说一会挺膊子','孛罗御史','元','元曲','yuanqu','','[]','闲时节笑咱，醉时节睡咱，今日里无是无非快活煞！。',24,'元曲/yuanqu.json','["闲时节笑咱，醉时节睡咱，今日里无是无非快活煞！。"]'),
('yuanqu-2777','张天师断风花雪月・仙吕/点绛唇','吴昌龄','元','元曲','yuanqu','','[]','夜色溶溶，桂花风动，天香送。',48,'元曲/yuanqu.json','["夜色溶溶，桂花风动，天香送。", "万里长空，是谁把银盘捧？(封姨云)俺趁着这月色行动些咱。", "(正旦唱)。"]'),
('yuanqu-2778','张天师断风花雪月・混江龙','吴昌龄','元','元曲','yuanqu','','[]','俺可便疾忙行动，怕的是五云楼畔日华东。',176,'元曲/yuanqu.json','["俺可便疾忙行动，怕的是五云楼畔日华东。", "(桃花仙云)俺和您私离天宫之上，早来到人间了。", "(正旦唱)俺如今偷临凡世，私下天宫。", "这其间风弄竹声穿户牖，更那堪月移花影上帘栊。", "(封姨云)仙子，则俺三个在这月明之下，又无甚跟随的使数，怎生是好？(正旦唱)俺本是冰魂素魄不寻常，要甚么金童玉女相随从。", "(带云)十八姨，你只跟着我者。", "(唱)又没甚幽期密约，止不过明月清风。"]'),
('yuanqu-2779','张天师断风花雪月・油葫芦','吴昌龄','元','元曲','yuanqu','','[]','俺和您回首瑶台隔几重，早来到书院中，怕甚么人间天上路难通。',196,'元曲/yuanqu.json','["俺和您回首瑶台隔几重，早来到书院中，怕甚么人间天上路难通。", "(云)封家姨也，则不俺思凡。", "(封姨云)仙子，可再有何人思凡哩？(正旦唱)想当日那天孙和董永曾把琼梭弄，(桃花仙云)可再有何人？(正旦唱)想巫娥和宋玉曾做阳台梦。", "(封姨云)姐姐，你此一去报恩，可是如何？(正旦唱)他若肯早近傍，我也肯紧过从。", "拚着个赚刘晨笑入桃源洞，(桃花仙云)不知刘震别后，可曾得再会来？(正旦唱)到后来天台山下再相逢。"]'),
('yuanqu-2780','张天师断风花雪月・天下乐','吴昌龄','元','元曲','yuanqu','','[]','却不道流水桃花片片红。',119,'元曲/yuanqu.json','["却不道流水桃花片片红。", "(桃花仙云)这桃花是我家的故事，你此去敢被那生折下桂花来也。", "(正旦唱)则你个娇也波容，可便将人厮调哄。", "我则为报德酬恩要始终，不索你不索你这个咕，那个哝。", "(封姨云)仙子，我曾敢说甚么？(正旦唱)哎！只你个十八姨口是风。"]'),
('yuanqu-2781','张天师断风花雪月・鹊踏柱','吴昌龄','元','元曲','yuanqu','','[]','则见他不惺忄葱，假朦胧，却待要拄眼睁睛，觅迹寻踪。',46,'元曲/yuanqu.json','["则见他不惺忄葱，假朦胧，却待要拄眼睁睛，觅迹寻踪。", "莫非他锦阵花营，不曾厮共？险教咱风月无功。"]'),
('yuanqu-2782','张天师断风花雪月・一半儿','吴昌龄','元','元曲','yuanqu','','[]','只见他高烧银烛影摇红，满注名香宝鼎中。',51,'元曲/yuanqu.json','["只见他高烧银烛影摇红，满注名香宝鼎中。", "全不似初见时恁般乔面孔，殷勤地捧金钟。", "元来是一半儿妆呆一半儿懂。"]'),
('yuanqu-2783','张天师断风花雪月・金盏儿','吴昌龄','元','元曲','yuanqu','','[]','我本待鸾凤配雌雄，你只想雕鹗起秋风。',169,'元曲/yuanqu.json','["我本待鸾凤配雌雄，你只想雕鹗起秋风。", "怎知我月中丹桂非凡种？(陈世英云)念小生凡胎浊体，怎敢和仙子陪奉？你只说小生来年应举，果是如何？(正旦唱)你问我来年春动有甚吉和凶？则你那文章千卷富，(陈世英云)便有了文章，也要命运哩。", "(正旦唱)怕不的命运一时通。", "(陈世英云)若得如此，小生早则喜也。", "(正旦唱)秀才，我道你来年登虎榜，总不如今夜抱蟾宫。"]'),
('yuanqu-2784','张天师断风花雪月・醉中天','吴昌龄','元','元曲','yuanqu','','[]','六印掌元戎，七纵显英雄。',68,'元曲/yuanqu.json','["六印掌元戎，七纵显英雄。", "向八座里气昂昂列上公，稳请受着九重天雨露恩和宠。", "也不枉了十年间苦功，到今朝享用。", "是必休忘了，我这报前程仙女淳风。"]'),
('yuanqu-2785','张天师断风花雪月・赚煞尾','吴昌龄','元','元曲','yuanqu','','[]','你若有十分的至诚心，我怕没九转丹相送？(陈世英云)小生来年八月十五日，专候仙子来也。',324,'元曲/yuanqu.json','["你若有十分的至诚心，我怕没九转丹相送？(陈世英云)小生来年八月十五日，专候仙子来也。", "(正旦唱)到来年又怕你八月中秋事冗。", "(陈世英云)既蒙仙子相许，小生怎敢负了此心？但仙子虽同织女，小生非比牵牛，怎么也要一年一会？做这般老远的期约也。", "(正旦唱)那七夕，会牛女佳期，你可也休卖弄。", "(陈世英云)仙子若果有心于小生，便不到的来年，怕甚么那？(正旦唱)我则怕六丁神告与天蓬，(陈世英云)那六丁总是天上神位，料仙子也不怕他！(正旦唱)更怕的是五更钟，催别匆匆，只落的四眼相看泪珠涌。", "(陈世英云)仙子，您直恁般慌速，便再停止一会儿也好。", "(正旦唱)兀的不三星在东。", "(陈世英云)仙子此一去，休忘了今宵欢会也。", "(正旦唱)正照着俺二人情重，一般潇洒月明中。", "(同二旦下)。"]'),
('yuanqu-2786','张天师断风花雪月・南宫/一枝花','吴昌龄','元','元曲','yuanqu','','[]','可不道既读孔吊书，那里也必达周公礼？你今日相思容易得，岂不闻饱病可兀的最难医？他从来老老实实，忒软善忒温若，近新来陡恁的。',82,'元曲/yuanqu.json','["可不道既读孔吊书，那里也必达周公礼？你今日相思容易得，岂不闻饱病可兀的最难医？他从来老老实实，忒软善忒温若，近新来陡恁的。", "他待学遇云英乞玉的裴航，赋洛神来珠的曹植。"]'),
('yuanqu-2787','张天师断风花雪月・梁州第七','吴昌龄','元','元曲','yuanqu','','[]','翻笑着不风流闭门的颜叔，假乖张拍案的封陟。',180,'元曲/yuanqu.json','["翻笑着不风流闭门的颜叔，假乖张拍案的封陟。", "他不肯左笔尖上挣扎个名和利，兀的不辱抹杀题桥的才思掷果的容仪。", "直这般无廉鲜耻，乱作胡为三餐饭并不曾想吃，五车书并不肯攻习。", "他、他、他，则待要美甘甘傍玉软香温。", "是、是、是，则待要悄促促在星前月底，等、等、等，则待要薄孜孜赴燕约莺期。", "奉相公省会，教老身直到那书房内，在左右看详细。", "只他这废寝忘餐可也因甚的？要一个明白消息。"]'),
('yuanqu-2788','张天师断风花雪月・牧羊关','吴昌龄','元','元曲','yuanqu','','[]','则见他恹恹的，说就里，不由我冷笑微微。',99,'元曲/yuanqu.json','["则见他恹恹的，说就里，不由我冷笑微微。", "你是个浊骨凡胎，他须是冰肌的这玉体。", "(陈世英云)仙子，你好失信也。", "(正旦唱)你敢要攀月桂谐连理，可不似指画饼待待充饥。", "常言道：杳茫神鬼事，哥哥也，知他布那里？。"]'),
('yuanqu-2789','张天师断风花雪月・骂玉郎','吴昌龄','元','元曲','yuanqu','','[]','莫不是崔莺莺害了你这张君瑞？只指望西厢下暗偷期，把镜中花生扭做蟾宫桂。',84,'元曲/yuanqu.json','["莫不是崔莺莺害了你这张君瑞？只指望西厢下暗偷期，把镜中花生扭做蟾宫桂。", "现如今你瘦岩岩病怎支？他虚飘飘占不归，知甚日重会？(陈世英云)仙子，则被你想杀小生也。", "(正旦唱)。"]'),
('yuanqu-2790','张天师断风花雪月・感皇恩','吴昌龄','元','元曲','yuanqu','','[]','怪不着你正是遥授夫妻，你可甚步步相随？更做道秀才每忒上紧，忒着迷。',70,'元曲/yuanqu.json','["怪不着你正是遥授夫妻，你可甚步步相随？更做道秀才每忒上紧，忒着迷。", "你伴的是琴书度日，怎想着那广寒宫窃药的仙姬？专等待三更后，才斗转，恰星移。"]'),
('yuanqu-2791','张天师断风花雪月・采茶歌','吴昌龄','元','元曲','yuanqu','','[]','想的你意儿痴，望的你眼儿疲，只等五言诗作上天梯。',48,'元曲/yuanqu.json','["想的你意儿痴，望的你眼儿疲，只等五言诗作上天梯。", "但得个一夕鸳鸯配成对，那里也还记十年身到凤凰池。"]'),
('yuanqu-2792','张天师断风花雪月・三煞','吴昌龄','元','元曲','yuanqu','','[]','我越劝着越妆出风风势，则说是病在心头那个知？怎么耳边傍不住相潮戏，百般的话不投机。',80,'元曲/yuanqu.json','["我越劝着越妆出风风势，则说是病在心头那个知？怎么耳边傍不住相潮戏，百般的话不投机。", "待着淹早些回避，我可道不关亲耽干系。", "就也着冷眼儿来看你，且看你直等的月色沉西。"]'),
('yuanqu-2793','张天师断风花雪月・二煞','吴昌龄','元','元曲','yuanqu','','[]','你道叔父行怎不敢医药来调治，这的是心病还从心上医。',148,'元曲/yuanqu.json','["你道叔父行怎不敢医药来调治，这的是心病还从心上医。", "便有那仓公、扁鹊成何济？也无过草树根皮，怎比得玉天仙知心着意。", "只想他今夜里休贪睡，重向书帏叙别离，敢胜似百补参芪。", "(云)哥哥，你保重将息，我回老相公话去也。", "(陈世英云)仙子，这早晚还不见来？兀的不害杀小生也。", "(正旦云)哥哥，你则听我劝者。", "(唱)。"]'),
('yuanqu-2794','张天师断风花雪月・黄钟尾','吴昌龄','元','元曲','yuanqu','','[]','我劝你好将息这不存不济千金体，再休想那无影无形百媚姿。',97,'元曲/yuanqu.json','["我劝你好将息这不存不济千金体，再休想那无影无形百媚姿。", "自去年到今日，曾有甚为盟记？只管里苦思忆，直等得佛出世，可不的干着你。", "这相思无尽极，倒不如早收拾，将一段云雨幽期，都付与高唐梦儿里。", "(下)。"]'),
('yuanqu-2795','张天师断风花雪月・仙吕/赏花时','吴昌龄','元','元曲','yuanqu','','[]','强扶策恹恹病里身，空凝望盈效月下人。',51,'元曲/yuanqu.json','["强扶策恹恹病里身，空凝望盈效月下人。", "我和他曾把酒结情亲，早隔了一年时分，兀的不愁杀我也桂华新。", "(下)。"]'),
('yuanqu-2796','张天师断风花雪月・正宫/端正好','吴昌龄','元','元曲','yuanqu','','[]','则被你催！逼得我两三番，喝掇得我十余次。',48,'元曲/yuanqu.json','["则被你催！逼得我两三番，喝掇得我十余次。", "我不合暗约通私，怎当那驱邪院一伙天兵伞至，狠恶的忒如此。"]'),
('yuanqu-2797','张天师断风花雪月・倘秀才','吴昌龄','元','元曲','yuanqu','','[]','我为甚先吐了这招承的口词？常言道明人不做那暗事。',52,'元曲/yuanqu.json','["我为甚先吐了这招承的口词？常言道明人不做那暗事。", "则俺这闭月羞花绝代姿，到如今自做出自当之，妆甚的谎子？。"]'),
('yuanqu-2798','张天师断风花雪月・叫声','吴昌龄','元','元曲','yuanqu','','[]','见放着正名师，不是，不是胡攀指。',31,'元曲/yuanqu.json','["见放着正名师，不是，不是胡攀指。", "准教你隐藏下这个可喜的女孩儿。"]'),
('yuanqu-2799','张天师断风花雪月・上小楼','吴昌龄','元','元曲','yuanqu','','[]','你休那耻便伶牙俐齿，调三斡四，说人好歹，许人暖昧，损人行止。',122,'元曲/yuanqu.json','["你休那耻便伶牙俐齿，调三斡四，说人好歹，许人暖昧，损人行止。", "你可便道这个，道那个，做的不是，都揣与这广寒宫宵奔的卓氏。", "(天师云)莫不是尔桃花打合的他来么？(桃花云)桂花仙子，你自思凡，我可为甚的来，却牵连着我那。", "(正旦云)偏你无过犯哩。", "(唱)。"]'),
('yuanqu-2800','张天师断风花雪月・石榴花','吴昌龄','元','元曲','yuanqu','','[]','当日个天台流水泛胭脂，谁引逗的刘晨、阮肇至于斯。',227,'元曲/yuanqu.json','["当日个天台流水泛胭脂，谁引逗的刘晨、阮肇至于斯。", "(天师云)荷花，你可怎生不近前来折辩？(荷花云)桂花仙子，你认了罪罢。", "(正旦唱)你可也要推辞，那并头莲就是你过犯公私。", "(天师云)菊花，你近前与他质对者。", "(菊花云)桂花仙子，你思凡干俺甚事？(正旦唱)想当日陶潜为你可便辞荣仕，在东篱下满饮金卮。", "(天师云)梅花，你也向前对词来。", "(梅花云)桂花仙子，你何不早早认了罪也，要累我做甚么？(正旦云)偏你无过犯那？(唱)你道你梅花孤洁全终始，我只问那孟浩然骑的瘦驴儿。"]'),
('yuanqu-2801','张天师断风花雪月・满庭芳','吴昌龄','元','元曲','yuanqu','','[]','你也合心中暗思，你待把强言折证，不辩个雄雌。',147,'元曲/yuanqu.json','["你也合心中暗思，你待把强言折证，不辩个雄雌。", "只你那风亭门馆书名字，可不是招伏下亲笔情词。", "元来你全无那风流情思，也枉耽着-个风月的这名儿。", "(风神云)我有甚么过犯在那哩？(正旦唱)你道你便无讥剌束，常记得杜少陵吟了诗。", "(封姨云)杜诗上怎么？你只管说。", "真人在此，我也不赖。", "(正旦唱)可不道风雨夜来时。"]'),
('yuanqu-2802','张天师断风花雪月・红绣鞋','吴昌龄','元','元曲','yuanqu','','[]','你守得个映雪的孙康苦志，你逼得个袁安在雪内横尸。',524,'元曲/yuanqu.json','["你守得个映雪的孙康苦志，你逼得个袁安在雪内横尸。", "赚得个王子猷，山阴雪夜上船时。", "(雪神云)也只为老夫忒慈善些儿。", "(正旦唱)你道你便忒性慢，式心慈，你则问那蓝关前韩退之。", "(雪神云)真人问谁要招？(天师云)要你招。", "(雪神云)吾神则知其功，不知其罪。", "(天师云)这老匹夫则知其功，不知其罪。", "你有甚么功在那里？(雪神云)真人差矣。", "吾乃天地正神，岂比那桂花思凡？做这等淫邪之事？风神管的是春风夏雨，吾神管的是秋霜冬雪。", "调和鼎鼐，燮理阴阳。", "滋五谷，润百草。", "压障气，兆丰年。", "于民有益，为国有功。", "(诗云)我本亲承帝旨把天门，今朝被你勾摄坛前折辨真。", "若要误犯天条招伏状，怎到的玉洁冰清白雪神。", "(天师云)噤声！你道我管不得你？天仙管得你么？(雪神云)管不得。", "(天师云)地仙管得你么？(雪神云)管不得。", "(天师云)贫道管得你么？(雪神云)你便是管得着哩。", "(天师云)噤声！吾非浊骨，本是仙胎。", "祖公留下三件法宝，信香一瓣，雌雄剑二口，降妖印一颗，专管天上天下三界仙精鬼怪，魍魉邪魔。", "量你是一块雪，我管不得你，怎管天上许多神将？吾今宣召天上火，地下火，山头火，霹雳火，炉中火，将你围在中间，立化一池黄水。", "老匹夫，看你招也是不招。", "(雪神做慌科，云)真人，小神招伏则便了也。", "(正旦唱)。"]'),
('yuanqu-2803','张天师断风花雪月・快活三','吴昌龄','元','元曲','yuanqu','','[]','你今日雪消也下流澌，花落也显枯枝。',35,'元曲/yuanqu.json','["你今日雪消也下流澌，花落也显枯枝。", "猛想起贾岛破风诗，和那扫雪的陶学士。"]'),
('yuanqu-2804','张天师断风花雪月・煞尾','吴昌龄','元','元曲','yuanqu','','[]','谢真人勘问我赴四池对会词，拚的个尽场儿诉出俺心间事，都向那蟠桃会上听仙旨。',43,'元曲/yuanqu.json','["谢真人勘问我赴四池对会词，拚的个尽场儿诉出俺心间事，都向那蟠桃会上听仙旨。", "(众同下)。"]'),
('yuanqu-2805','张天师断风花雪月・折桂令','吴昌龄','元','元曲','yuanqu','','[]','这罪犯是我贱妾应该，没米由误犯天条，私下瑶台。',126,'元曲/yuanqu.json','["这罪犯是我贱妾应该，没米由误犯天条，私下瑶台。", "却带累花神，干连风雪，都也不伏烧埋。", "俺本是广寒宫冰魂素魄，怎比那阎浮世浊骨凡胎？(长眉仙云)敢是你捱不过那凄凉寂寞，看上了陈秀才么？(正旦唱)俺可行甚难捱，觑上乔才？屈屈的将西没东生，错认做了夜去的这明来。"]'),
('yuanqu-2806','张天师断风花雪月・雁儿落','吴昌龄','元','元曲','yuanqu','','[]','想当日被计罗早缠作灾，多感的娄金宿将咱解。',43,'元曲/yuanqu.json','["想当日被计罗早缠作灾，多感的娄金宿将咱解。", "这都是陈秀才能见可怜，因此上俺桂花仙思酬待。"]'),
('yuanqu-2807','张天师断风花雪月・得胜令','吴昌龄','元','元曲','yuanqu','','[]','兀那座读书斋，须不是楚阳台。',53,'元曲/yuanqu.json','["兀那座读书斋，须不是楚阳台。", "他救我元无意，我见他有甚歹？冤哉！怎将俺这一火同禁害？诉的明白，望仙尊别处裁。"]'),
('yuanqu-2808','张天师断风花雪月・川拨棹','吴昌龄','元','元曲','yuanqu','','[]','则听的他闹垓垓，闹垓垓加罪责。',43,'元曲/yuanqu.json','["则听的他闹垓垓，闹垓垓加罪责。", "怎生的全没矜哀，狠下差排？贬咱到阴山口外，活活的折罚煞。"]'),
('yuanqu-2809','张天师断风花雪月・七弟兄','吴昌龄','元','元曲','yuanqu','','[]','我可也左猜，右猜，端的是为谁来？现放着斫桂的吴刚巨斧风般快，只问他奔月的嫦娥曾否下妆台？更和那捣药的兔儿那日当何在？(长眉仙云)罪定了，不必多说，(直符云)仙旨',93,'元曲/yuanqu.json','["我可也左猜，右猜，端的是为谁来？现放着斫桂的吴刚巨斧风般快，只问他奔月的嫦娥曾否下妆台？更和那捣药的兔儿那日当何在？(长眉仙云)罪定了，不必多说，(直符云)仙旨已下，行动些。", "(正旦唱)。"]'),
('yuanqu-2810','张天师断风花雪月・梅花酒','吴昌龄','元','元曲','yuanqu','','[]','呀！我待挣扎怎挣扎？也是我运拙时衰，月值年灾，鬼使也那神差。',194,'元曲/yuanqu.json','["呀！我待挣扎怎挣扎？也是我运拙时衰，月值年灾，鬼使也那神差。", "(长眉仙云)我想陈秀才患病在床，若不将他魂魄勾摄前来，看见这个境头，怎得有痊可之日？疾！(陈世英上)小生陈世英。", "兀的不是桂花仙子来了也。", "(正旦唱)淹的呵，下瑶阶，将两步做一步蓦。", "呀！早转过甚人来？是、是、是，有情人陈秀才，他、他、他，怎容易到天台？敢、敢、敢，为着我旧情怀，待、待、待，折桂子索和谐，怎、怎、怎，不教我添惊怪？。"]'),
('yuanqu-2811','张天师断风花雪月・喜江南','吴昌龄','元','元曲','yuanqu','','[]','兀的不是月明千里故人来，抵多少洛阳花酒一时来。',97,'元曲/yuanqu.json','["兀的不是月明千里故人来，抵多少洛阳花酒一时来。", "你呵，休猜做春风来似不曾来。", "(正旦同陈世英走科，唱)咱两个去来。", "(封姨、雪神喝科，云)小鬼头那里去？(正旦唱)偏撞着这满头风雪却回来。", "(陈世英下)。"]'),
('yuanqu-2812','楚昭王疏者下船・仙吕/点绛唇','郑延玉','元','元曲','yuanqu','','[]','这剑呵冰刃霜寒，玉华光灿，孜孜看。',83,'元曲/yuanqu.json','["这剑呵冰刃霜寒，玉华光灿，孜孜看。", "怎飞来坐榻之间，委实的紫气冲霄汉。", "(芈旋云)哥哥，量此物强杀者波，则是一口剑，那里取神光冲射牛斗之上？听那风胡子做甚么？(正末唱)。"]'),
('yuanqu-2813','楚昭王疏者下船・混江龙','郑延玉','元','元曲','yuanqu','','[]','这剑真为奇幻，世人休做等闲看。',136,'元曲/yuanqu.json','["这剑真为奇幻，世人休做等闲看。", "我则见英英结秀，湛湛生斑。", "这剑本在东方平百越，今日个飞来南国镇荆蛮。", "这剑按阴阳斡运，顺天地循环。", "采铜出那溪之水，取锡在赤堇之山。", "下雷雨消隔尘滓，有鬼神守护炉间。", "这剑他抱精灵多气爽助神威，真乃是免忧愁绝惊恐除危难。", "现如今河清海晏，国泰的这民安。"]'),
('yuanqu-2814','楚昭王疏者下船・油葫芦','郑延玉','元','元曲','yuanqu','','[]','久与吴国姬光阻面颜，(芈旋云)哥哥，既是他下将战书来，凭着俺这里兵多将广，马壮人强，量吴国姬光到的那里，就怕着他哩！(正末云)我不怕姬光，怕是那一个人！(唱)怕',232,'元曲/yuanqu.json','["久与吴国姬光阻面颜，(芈旋云)哥哥，既是他下将战书来，凭着俺这里兵多将广，马壮人强，量吴国姬光到的那里，就怕着他哩！(正末云)我不怕姬光，怕是那一个人！(唱)怕的那伍盟府天下罕，(芈旋云)量伍子胥有何英雄，哥哥直这般怕他？(正末唱)他正是良才奇宝在人间。", "我则道重修讯问传书简，原来他相期恶战呈公案。", "(芈旋云)虽然那子胥多有本事，凭着俺这名山大川，长江险阻，那伍子胥怎便容易到的俺国来？(正末唱)你休道是阻着大川，隔着大山，便有那波涛滚滚长江限，假若是无敌手战应难。"]'),
('yuanqu-2815','楚昭王疏者下船・那吒令','郑延玉','元','元曲','yuanqu','','[]','我端坐在，朝堂这间；聚集着，英才这班；怎经的，会临潼那番。',96,'元曲/yuanqu.json','["我端坐在，朝堂这间；聚集着，英才这班；怎经的，会临潼那番。", "(芈旋云)这伍子胥当初在临潼会上，怎生般英雄，哥哥试说一遍，您兄弟听咱。", "(正末唱)哪里取这般忠义人，英雄汉。", "他举鼎时，多敢有神力相关。"]'),
('yuanqu-2816','楚昭王疏者下船・寄生草','郑延玉','元','元曲','yuanqu','','[]','从来道要得千军易，偏求一将难。',186,'元曲/yuanqu.json','["从来道要得千军易，偏求一将难。", "闲时故把忠臣慢，差时不听忠臣谏，危时却要忠臣干。", "谁当这借吴雪恨伍将军，我则索求那扶周摄政姬公旦。", "(申包胥云)主公，若子胥领兵前来，切不可与他交战。", "你则深沟高垒，紧守城池。", "等小官直至西秦，借他兵来，那其间内外夹攻，方能取胜。", "(正末云)则怕秦昭公不肯借与咱兵，怎生是好？(申包胥云)主公，想秦、楚旧为亲戚之邦，必在借与咱兵，不必疑虑。", "(正末唱)。"]'),
('yuanqu-2817','楚昭王疏者下船・幺篇','郑延玉','元','元曲','yuanqu','','[]','你须想着归期急，休言他去路艰。',97,'元曲/yuanqu.json','["你须想着归期急，休言他去路艰。", "止不过船临古渡垂杨岸，路逢峻岭滩头涧，小可如君骑羸马连云栈。", "(申包胥云)小官既为国解难，怎敢避的途路之苦。", "(正末唱)你休辞山遥水远路三千，我专等你坚甲利刃那兵十万。"]'),
('yuanqu-2818','楚昭王疏者下船・金盏儿','郑延玉','元','元曲','yuanqu','','[]','你道是一个月借兵还，三十日报平安。',181,'元曲/yuanqu.json','["你道是一个月借兵还，三十日报平安。", "但愿你晓行晚宿无辞惮，休着我悬望的恶心烦。", "你只看风传金柝远，霜照铁衣寒。", "(申包胥云)主公放心，小官若见了秦昭公，借的军马即便回也。", "(正末唱)我可为甚着贤人投敌国，也则怕那猛将过昭关！(申包胥云)那吴国孙武子深知兵法，又加以子胥之勇，俺国中无能胜之者。", "小官去后，只愿主公坚壁不战，以待秦兵。", "休听一时之言，坐失万全之策。", "(正末唱)。"]'),
('yuanqu-2819','楚昭王疏者下船・醉扶归','郑延玉','元','元曲','yuanqu','','[]','你道是伍盟府能雄悍，孙武子又非凡。',53,'元曲/yuanqu.json','["你道是伍盟府能雄悍，孙武子又非凡。", "只要我高垒深沟紧闭关，专等待秦邦返。", "我只怕你人疲意懒，早淹的过了程期限。"]'),
('yuanqu-2820','楚昭王疏者下船・赚煞','郑延玉','元','元曲','yuanqu','','[]','你去后我夜忧到明，明忧到晚。',255,'元曲/yuanqu.json','["你去后我夜忧到明，明忧到晚。", "若是那秦公子将卿傲慢，你则索将火性儿全然都放坦，是必休便冒渎容颜。", "那其间借的些金鼓旗幡，将你那洗尘酒开怀儿做了送路盏。", "(申包胥公)主公，我这一去，若借得秦兵来时，料那伍子胥恐怕前后受敌，必解兵而归矣。", "(正末云)只要借得秦兵呵，(唱)恁时节吴兵自还，楚城无患，生则怕你别时容易见时难！(下)(申包胥云)二公子，你紧记者，若伍子胥领兵来时，休听费无忌那短见，就要与他家厮杀，有误大事。", "我即日往秦邦借兵去也。", "(诗云)东吴滚滚动征尘，济困扶危投远亲。", "方信家贫显孝子，楚邦有难识忠臣。", "(下)。"]'),
('yuanqu-2821','楚昭王疏者下船・紫花儿序','郑延玉','元','元曲','yuanqu','','[]','将他那乾坤忠孝，更和盖世界英雄，来寻那旧日杀父母冤仇。',78,'元曲/yuanqu.json','["将他那乾坤忠孝，更和盖世界英雄，来寻那旧日杀父母冤仇。", "我则见征云不散，杀气难收。", "飕飕凛凛，寒风不住吼。", "大刚来也则是冤仇深厚，扑腾腾鼙鼓惊心，明晃晃剑戟侵眸。"]'),
('yuanqu-2822','楚昭王疏者下船・调笑令','郑延玉','元','元曲','yuanqu','','[]','你每做的来不周，结下了父兄仇，抵多少不是冤家不聚头。',66,'元曲/yuanqu.json','["你每做的来不周，结下了父兄仇，抵多少不是冤家不聚头。", "今日在杀场上面争驰骤，费无忌你索担忧。", "他只待摘了你心肝标了你首，可兀的便肯干休。"]'),
('yuanqu-2823','楚昭王疏者下船・小桃红','郑延玉','元','元曲','yuanqu','','[]','史见他旗门开处跃骅骝，高叫道谁敢来和咱斗。',74,'元曲/yuanqu.json','["史见他旗门开处跃骅骝，高叫道谁敢来和咱斗。", "早着俺千军万马都惊走，急难收，兀的般威风不信人间有。", "淹的呵抛下了戈矛，氲的呵遮漫了宇宙，莫不是剑气上连牛。"]'),
('yuanqu-2824','楚昭王疏者下船・金焦叶','郑延玉','元','元曲','yuanqu','','[]','那一个锦征袍窄窄的把狮蛮款兜，这一个凤翅盔律律的把红缨乱丢。',60,'元曲/yuanqu.json','["那一个锦征袍窄窄的把狮蛮款兜，这一个凤翅盔律律的把红缨乱丢。", "那一个点钢枪支支的把黄幡狠揪，这一个铁胎弓率率的把雕翎稳扣。"]'),
('yuanqu-2825','楚昭王疏者下船・秃厮儿','郑延玉','元','元曲','yuanqu','','[]','马以处敌兵乱走，枪着处鲜血交流，偏爱杀伐争战斗。',87,'元曲/yuanqu.json','["马以处敌兵乱走，枪着处鲜血交流，偏爱杀伐争战斗。", "两下里，不相投，难休。", "(费无忌云)我敌不过他，只是逃命的好，走、走、走！(伍子胥云)你这老匹夫，走那里去！(追科)(正末唱)。"]'),
('yuanqu-2826','楚昭王疏者下船・圣药王','郑延玉','元','元曲','yuanqu','','[]','则他那枪似虬，马似彪，骨碌碌地上滚人头，数载仇一鼓收，片时间叠尸高耸似山丘，恰便似落叶尽归秋。',47,'元曲/yuanqu.json','["则他那枪似虬，马似彪，骨碌碌地上滚人头，数载仇一鼓收，片时间叠尸高耸似山丘，恰便似落叶尽归秋。"]'),
('yuanqu-2827','楚昭王疏者下船・收尾','郑延玉','元','元曲','yuanqu','','[]','眼睁睁见死可也无人救，索把这泼残生告天保佑。',85,'元曲/yuanqu.json','["眼睁睁见死可也无人救，索把这泼残生告天保佑。", "则被那借吴兵的伍相逞尽了十分强。", "(芈旋云)怎得这申包胥救兵到来，可也好也！(正末唱)遥望俺复楚国的包胥且耐着一时守。", "(同下)。"]'),
('yuanqu-2828','楚昭王疏者下船・中吕/粉蝶儿','郑延玉','元','元曲','yuanqu','','[]','则听的兵起东吴，可扑扑胆惊心惧，早则不三战杀入王都。',62,'元曲/yuanqu.json','["则听的兵起东吴，可扑扑胆惊心惧，早则不三战杀入王都。", "吓得我乱慌慌，忙劫劫，不成活路。", "偏生生的望眼模糊，悄不见那西秦远来相助。"]'),
('yuanqu-2829','楚昭王疏者下船・醉春风','郑延玉','元','元曲','yuanqu','','[]','则俺这妻子似瑟和琴，弟兄如手共足。',74,'元曲/yuanqu.json','["则俺这妻子似瑟和琴，弟兄如手共足。", "(芈旋云)俺怎肯撇下了嫂嫂侄儿也！(正末唱)俺一家四口儿盼程途，俺端的苦，苦。", "几能够罢息干戈，还归宫阙，抚安黎庶。"]'),
('yuanqu-2830','楚昭王疏者下船・迎仙客','郑延玉','元','元曲','yuanqu','','[]','一个报冤仇称了子胥，一个打赌赛去了包胥，何处也济困扶危重复楚。',128,'元曲/yuanqu.json','["一个报冤仇称了子胥，一个打赌赛去了包胥，何处也济困扶危重复楚。", "慌速速的强逃生，急煎煎的甘受苦。", "(内发喊科)(正末唱)脑背后闹吵吵的起军卒，(芈旋云)哥哥，兀的不是追兵渐近了也？前面又阻着长江，江水泛涨，无船可渡，怎生是好？(正末唱)眼前面翻滚滚野水无人渡。"]'),
('yuanqu-2831','楚昭王疏者下船・红绣鞋','郑延玉','元','元曲','yuanqu','','[]','不得已央及你个渔父，(梢公云)肯载不肯载，也则自的我。',124,'元曲/yuanqu.json','["不得已央及你个渔父，(梢公云)肯载不肯载，也则自的我。", "(正末唱)似这般装着势待要何如？我与你也是近疃邻庄共乡闾。", "(梢公云)怕不是乡闾，大家要看个风水，实是船小，载不起这几个人。", "(正末唱)你道是船儿小难装载，则要你量儿大救俺家属，早早的过长江无间阻。"]'),
('yuanqu-2832','楚昭王疏者下船・石榴花','郑延玉','元','元曲','yuanqu','','[]','俺只见云涛雪浪接天隅，这的是海阔洞庭湖。',215,'元曲/yuanqu.json','["俺只见云涛雪浪接天隅，这的是海阔洞庭湖。", "(梢公云)我说不载，不载，您强要上这船来，还不开的半里，早起风了。", "你看泼天也似的大浪，可不苦也！(正末唱)你看这大惊小怪泼村夫，那里便叫苦，吓的俺魄散魂无。", "(梢公云)风浪越大了。", "船儿又小，淹上水来了也。", "不着亲的，快请一个下水去，才救的一船人性命。", "(众做悲科)(正末唱)他道是不关亲者当身故，俺四口儿那一个为疏？则被这一家老小同奔赴，(带云)艄公，你小心在意者！(唱)到今日只仗的你做护身符。"]'),
('yuanqu-2833','楚昭王疏者下船・普天乐','郑延玉','元','元曲','yuanqu','','[]','俺只见掩掩泼泼画船儿歪，囊囊突突梢公絮。',201,'元曲/yuanqu.json','["俺只见掩掩泼泼画船儿歪，囊囊突突梢公絮。", "(梢公云)这风把船掀过来，淹上水了。", "还不着个下水去，敢多要死哩？(正末唱)我则见他无休的催促，待不的须臾。", "(旦儿悲科，云)儿也，则被你痛杀我也。", "(正末唱)儿悲啼为母离，母痛哭抛儿去。", "哎，你个掌命司的梢公可便休催促，百忙里割不断他子母每肠肚。", "但保全了孩儿的身躯，怎顾得夫人的性命？(芈旋云)哥哥，您兄弟下水去也。", "(正末云)兄弟，你住者！(唱)紧揪住俺这兄弟的衣服。"]'),
('yuanqu-2834','楚昭王疏者下船・满庭芳','郑延玉','元','元曲','yuanqu','','[]','哀哉子母，如今稀有，从古应无。',284,'元曲/yuanqu.json','["哀哉子母，如今稀有，从古应无。", "又不是进胶舟那日昭王渡，怎生的也共为鱼？儿也你舍性命投江伴母，妻也你可便守贞烈出嫁从夫。", "似这等难相顾，总只是皇天丧楚，教你去龙颔下探明珠。", "(梢公云)渡过江了，撺下脚踏板，请登岸。", "(做上岸科)(芈旋云)解这金鱼下来，赏了梢公。", "后面有人追来时，若非本国之人，你是必休渡他过江也。", "(梢公云)理会的。", "等您回来时，我另打一只大海船在此等候。", "(下)(正末云)谢天谢地，上的岸来，兄弟也，这两条路您自往那一条路去？(芈旋云)哥哥，现今嫂嫂、侄儿都无了也，则有您兄弟一人相随，可怎生又教我那一条路去？不知哥哥主着何意？(正末云)兄弟，你那里知道！(唱)。"]'),
('yuanqu-2835','楚昭王疏者下船・耍孩儿','郑延玉','元','元曲','yuanqu','','[]','本待要相随相从相将去，也则为我胆儿自虚。',151,'元曲/yuanqu.json','["本待要相随相从相将去，也则为我胆儿自虚。", "我只见前山掩映苍苍树，那其间必有埋伏。", "小路行怕撞着孙都统，大路走须防他伍子胥。", "兄和弟谁防护？可不是免鱼鳖才离江上，逢豺虎又断送山谷。", "(芈旋云)既然这等，您兄弟则往这小路上，抄出大路相会。", "且辞别了哥哥去也。", "哥哥受您兄弟一拜，只愿哥哥稳登前路，无惊无恐。", "(正末唱)。"]'),
('yuanqu-2836','楚昭王疏者下船・二煞','郑延玉','元','元曲','yuanqu','','[]','兄弟也咱相逢时有限期，别离了无限苦，(正末走科)(芈旋追上，云)哥哥，您兄弟再送哥哥几步。',121,'元曲/yuanqu.json','["兄弟也咱相逢时有限期，别离了无限苦，(正末走科)(芈旋追上，云)哥哥，您兄弟再送哥哥几步。", "(正末唱)两下里欲去也频回觑。", "好着我悲切切痛煞煞提着胆向刀尖过，倒不如悄促促低着头在剑下诛。", "兄弟也哭一声行一步，俺兄弟情气吁成云雾，他子母恨泪滴满江湖。"]'),
('yuanqu-2837','楚昭王疏者下船・煞尾','郑延玉','元','元曲','yuanqu','','[]','俺如今一程程逐去途，一心心怀故土。',47,'元曲/yuanqu.json','["俺如今一程程逐去途，一心心怀故土。", "大都来是一兴一败天之数，但不知肯分的秦兵几时到得楚。", "(下)。"]'),
('yuanqu-2838','楚昭王疏者下船・双调/新水令','郑延玉','元','元曲','yuanqu','','[]','包胥烈气子胥知，听的道借军来，他可便引兵先退。',60,'元曲/yuanqu.json','["包胥烈气子胥知，听的道借军来，他可便引兵先退。", "借兵的重扶楚国安，投吴的齐着凯歌回。", "这两个名姓天下知，真乃是忠与孝两完备。"]'),
('yuanqu-2839','楚昭王疏者下船・驻马听','郑延玉','元','元曲','yuanqu','','[]','伍员无敌，入楚地鞭尸尚恨迟；包胥有智，借秦兵复国偏能疾。',351,'元曲/yuanqu.json','["伍员无敌，入楚地鞭尸尚恨迟；包胥有智，借秦兵复国偏能疾。", "(申包胥子云)子胥若不想旧交之情，凭着他武艺，量小官到的那里？(正末唱)虽然他会临潼八面虎狼威，怎如你哭秦亭七日英雄泪。", "(做悲科)(申包胥云)主公为何发起悲来？(正末唱)我今日安居宝殿里，猛想起渡江时，不觉心如碎。", "(申包胥云)主公，吴兵已退，楚国重安，此乃如天之喜，且省烦恼。", "(芈旋上，云)某芈旋。", "自从江边与哥哥别后，一向避于随地，可早半年光景也。", "听的申包胥借的秦兵，重扶楚国。", "我如今回去，见我哥哥咱。", "令人报复去，道有芈旋在于门首。", "(卒子云)喏，报的大王得知，有二公子来了也。", "(正末云)快有请！(卒子云)请进去。", "(芈旋做见，悲科)(正末云)兄弟也，你在那里来？(芈旋云)您兄弟自与哥哥相别之后，流落随国，听知哥哥复楚，一径的寻将来也。", "(正末唱)。"]'),
('yuanqu-2840','楚昭王疏者下船・沉醉东风','郑延玉','元','元曲','yuanqu','','[]','自间别伯夷、叔齐，我常只是坐想行悲。',351,'元曲/yuanqu.json','["自间别伯夷、叔齐，我常只是坐想行悲。", "(芈旋云)许久不见哥哥，请受您兄弟几拜。", "(正末唱)既然为兄弟情，讲甚君臣礼。", "想当年在小船中寸步难移。", "(芈旋打悲科，云)您兄弟岂望今日与哥哥相见也！(正末云)令人，安排酒果来与兄弟拂尘者。", "(唱)今日相逢有限期，我又恐怕是南柯梦里。", "(云)兄弟，你满饮一杯。", "(芈旋云)您兄弟吃不下这酒去。", "(正末云)兄弟，你为甚么吃酒不下？(芈旋云)您兄弟心下则想着嫂嫂和侄儿哩。", "(正末云)兄弟，你嫂嫂有。", "(芈旋云)既然有嫂嫂，何不请将出来相见咱？(正末云)令人，请将夫人来者。", "(卒子云)夫人有请。", "(二旦上，云)妾身乃楚昭公继室夫人。", "大王呼唤，须索见去来。", "(做出见科)(正末云)兄弟，兀的不是你嫂嫂。", "(芈旋做认科，云)哥哥，这那里是我那嫂嫂也？(正末云)兄弟也，可知不是你那嫂嫂哩！(唱)。"]'),
('yuanqu-2841','楚昭王疏者下船・落梅风','郑延玉','元','元曲','yuanqu','','[]','他身丧在波涛内，名标在书传里。',102,'元曲/yuanqu.json','["他身丧在波涛内，名标在书传里。", "一个忠则尽命，一个孝当竭力。", "我今日立安邦还成子共妻，(云)兄弟也，当初我弃了嫂嫂侄儿，留得你在。", "哥哥今日还有嫂嫂，少不的生下侄儿。", "若无了你也呵，(唱)那里去再寻个同胞兄弟？。"]'),
('yuanqu-2842','楚昭王疏者下船・甜水令','郑延玉','元','元曲','yuanqu','','[]','我恰才与兄弟团圆，开怀笑饮，同欢同会。',78,'元曲/yuanqu.json','["我恰才与兄弟团圆，开怀笑饮，同欢同会。", "我这里那步出宫闱，远听声音，近观相貌，端详仔细，(旦儿云)大王万福！(正末做惊科)(唱)呀，原来是俺咏睢鸠窈窕元妃！。"]'),
('yuanqu-2843','楚昭王疏者下船・折桂令','郑延玉','元','元曲','yuanqu','','[]','我则道你趁横波一去无消息，可正是堂上糟糠，休猜做墙上泥皮。',98,'元曲/yuanqu.json','["我则道你趁横波一去无消息，可正是堂上糟糠，休猜做墙上泥皮。", "想当日船小江深，风高浪涌，云锁天地。", "若不是贤达妇三从四德，若不是仁孝子百顺千随。", "我则道夫妇分离，父子乖违，怎能彀再得团圆，还见这笑眼欢眉。"]'),
('yuanqu-2844','楚昭王疏者下船・沽美酒','郑延玉','元','元曲','yuanqu','','[]','谢大王怜下国，借猛将解重围。',43,'元曲/yuanqu.json','["谢大王怜下国，借猛将解重围。", "也只为丧败初还百无备，尚未及酬恩报德，非是俺急时偎缓时弃。"]'),
('yuanqu-2845','楚昭王疏者下船・太平令','郑延玉','元','元曲','yuanqu','','[]','自斗宝临潼赴会，赐无祥公主来归。',50,'元曲/yuanqu.json','["自斗宝临潼赴会，赐无祥公主来归。", "曾对天割襟为记，愿世世无相违背。", "这信誓，在彼，怎悔？难得见今朝这日。"]'),
('yuanqu-2846','楚昭王疏者下船・锦上花','郑延玉','元','元曲','yuanqu','','[]','当日个避难临江，扁舟同济。',78,'元曲/yuanqu.json','["当日个避难临江，扁舟同济。", "陡遇风波，梢子惊啼。", "(云)他道是船小不能重载，内中有疏者，请一位下水，方才有救。", "(唱)他道所未倾危，刚争半米。", "疏者非亲，请其下水。"]'),
('yuanqu-2847','楚昭王疏者下船・幺篇','郑延玉','元','元曲','yuanqu','','[]','夫人先拜辞，稚子继沉溺。',45,'元曲/yuanqu.json','["夫人先拜辞，稚子继沉溺。", "也只为兄弟情深，难忍抛弃。", "谁想龙神，暗中呵卫。", "死者重生，生者不愧。"]'),
('yuanqu-2848','楚昭王疏者下船・清江引','郑延玉','元','元曲','yuanqu','','[]','可又得金枝公主成配匹，岂不是天缘美？永为唇齿邦，万古干戈息，将着甚的般花红酬谢你个秦百里？。',46,'元曲/yuanqu.json','["可又得金枝公主成配匹，岂不是天缘美？永为唇齿邦，万古干戈息，将着甚的般花红酬谢你个秦百里？。"]'),
('yuanqu-2849','楚昭王疏者下船・收尾','郑延玉','元','元曲','yuanqu','','[]','殿庭中摆设下千金席，列两行鸾歌风吹。',45,'元曲/yuanqu.json','["殿庭中摆设下千金席，列两行鸾歌风吹。", "不争为青锋剑揽惹了那场灾，还落的赤绳书接受了这重喜！。"]'),
('yuanqu-2850','西江月','施惠《幽闺记》','元','元曲','yuanqu','','[]','(副末上)轻薄人情似纸，迁移世事如棋。',63,'元曲/yuanqu.json','["(副末上)轻薄人情似纸，迁移世事如棋。", "今来古往不胜悲，何用虚名虚利？遇景且须行乐，当场谩共衔杯。", "莫教花落子规啼，懊恨春光去矣。"]'),
('yuanqu-2851','沁园春','施惠《幽闺记》','元','元曲','yuanqu','','[]','蒋氏世隆，中都贡士，妹子瑞莲。',141,'元曲/yuanqu.json','["蒋氏世隆，中都贡士，妹子瑞莲。", "遇兴福逃生，结为兄弟。", "瑞兰王女，失母为随迁。", "荒村寻妹，频呼小字，音韵相同事偶然。", "应声处，佳人才子，旅馆就良缘。", "岳翁瞥见生嗔怒，拆散鸳鸯最可怜。", "叹幽闺寂寞，亭前拜月。", "几多心事，分付与婵娟。", "兄中文科，弟登武举。", "恩赐尚书赘状元。", "当此际，夫妻重会，百岁永团圆。"]'),
('yuanqu-2852','珍珠帘','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生扮蒋世隆上)十年映雪囊萤，苦学干禄，幸首获州庠乡举。',69,'元曲/yuanqu.json','["(生扮蒋世隆上)十年映雪囊萤，苦学干禄，幸首获州庠乡举。", "继晷与焚膏，祗勤习诗书，咳唾珠玑才灿锦，养浩然春闱必取。", "一跃过龙门，当此青云得路。"]'),
('yuanqu-2853','鹧鸪天','施惠《幽闺记》','元','元曲','yuanqu','','[]','正是锦绣胸襟气若虹，文章才学足三冬；循循善道驰庠校，济济儒风蔼郡中。',66,'元曲/yuanqu.json','["正是锦绣胸襟气若虹，文章才学足三冬；循循善道驰庠校，济济儒风蔼郡中。", "题雁塔，步蟾宫，前程万里附溟鸿。", "此时衣锦还乡客，五百名中让世隆。"]'),
('yuanqu-2854','月上海棠','施惠《幽闺记》','元','元曲','yuanqu','','[]','君子儒，文章学业驰名誉；但一心忧道，岂为贫居？十年挨淡饭黄齑，终身享鼎食重褥。',52,'元曲/yuanqu.json','["君子儒，文章学业驰名誉；但一心忧道，岂为贫居？十年挨淡饭黄齑，终身享鼎食重褥。", "前贤语，果是书中自有金玉。"]'),
('yuanqu-2855','点绛唇','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净扮番将上)势压中华，仁将夷化，威风大。',32,'元曲/yuanqu.json','["(净扮番将上)势压中华，仁将夷化，威风大。", "一曲琵琶，醉后驱鹰马。"]'),
('yuanqu-2856','水底鱼','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生、外、末扮番军上)白草黄沙，毡房为住家。',57,'元曲/yuanqu.json','["(小生、外、末扮番军上)白草黄沙，毡房为住家。", "胡儿胡女惯能骑战马。", "因贪财宝到中华，闲戏耍，被他拿住，铁里温都哈喇。"]'),
('yuanqu-2857','豹子令','施惠《幽闺记》','元','元曲','yuanqu','','[]','点起番家百万兵，百万兵，纷纷快马似腾云，似腾云。',59,'元曲/yuanqu.json','["点起番家百万兵，百万兵，纷纷快马似腾云，似腾云。", "叵耐大金无道理，与他交战定输赢。", "(合)安排器械便登程，杀教片甲不留存。"]'),
('yuanqu-2858','点绛唇','施惠《幽闺记》','元','元曲','yuanqu','','[]','渐辟东方，星残月淡，苍龙犹显。',26,'元曲/yuanqu.json','["渐辟东方，星残月淡，苍龙犹显。", "平闪清光，点滴檐铃响。"]'),
('yuanqu-2859','出队子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净扮聂贾列上)番兵突至，番兵突至，御敌无人为出师，教人门夜苦忧思。',52,'元曲/yuanqu.json','["(净扮聂贾列上)番兵突至，番兵突至，御敌无人为出师，教人门夜苦忧思。", "事到临危不可迟，奏议迁都，伏乞圣旨。"]'),
('yuanqu-2860','点绛唇','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外扮陀满海牙上)长乐钟鸣，未央宫启。',35,'元曲/yuanqu.json','["(外扮陀满海牙上)长乐钟鸣，未央宫启。", "千官至，顿首丹墀，遥拜着红云里。"]'),
('yuanqu-2861','新水令','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外怒科，外)九重天听望垂慈，主君贤谏臣须直。',38,'元曲/yuanqu.json','["(外怒科，外)九重天听望垂慈，主君贤谏臣须直。", "事当言敢自欺？既为官要尽臣职。"]'),
('yuanqu-2862','折桂令','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)古人言自有权舆，能者迁之，否则存之。',41,'元曲/yuanqu.json','["(外)古人言自有权舆，能者迁之，否则存之。", "(净)说得好！说得好！你说圣上不如太王。"]'),
('yuanqu-2863','江儿水','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净)臣道当卑顺，秋毫敢犯之？你道能如太王则迁之，不能则谨守常法。',92,'元曲/yuanqu.json','["(净)臣道当卑顺，秋毫敢犯之？你道能如太王则迁之，不能则谨守常法。", "这是不能尧舜其君罪。", "那百姓每呵，见说仁君迁都避，纷纷从者如归市。", "你道效死而民勿去，这等拘守之言，怎及得迁国图存之计？。"]'),
('yuanqu-2864','雁儿落','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)俺穿一领裹乾坤缝掖衣，要干着儒家事；读几行正纲常贤圣书，要识着君臣义。',163,'元曲/yuanqu.json','["(外)俺穿一领裹乾坤缝掖衣，要干着儒家事；读几行正纲常贤圣书，要识着君臣义。", "俺则是一心儿清白本无私。", "(净)你触犯了圣上，就该万死。", "(外)言如达，死何辞？(净)常言道：\"闭口深藏舌，安身处处牢。", "\"(外)怎做得窨无气？(净)你许多年纪了，还要管这等闲事怎么？(外)怎做得老无为？今日任你就打落张巡齿，痴也么痴，常自把严颜头手内提。"]'),
('yuanqu-2865','侥侥令','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净)半空横剑戟，四面列旌旗，战鼓如雷轰天地。',35,'元曲/yuanqu.json','["(净)半空横剑戟，四面列旌旗，战鼓如雷轰天地。", "你却唱太平歌，念孔圣书。"]'),
('yuanqu-2866','收江南','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)呀！恰便是骄骢立仗，噤住口不容嘶。',59,'元曲/yuanqu.json','["(外)呀！恰便是骄骢立仗，噤住口不容嘶。", "将焉用彼过谁欤？那知越瘦与秦肥？你这般所为，你这般所为，恨不得啖伊血肉寝伊皮。"]'),
('yuanqu-2867','园林好','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净)朝廷上尊严去处，岂容你谈论是非？全不识君臣之体。',43,'元曲/yuanqu.json','["(净)朝廷上尊严去处，岂容你谈论是非？全不识君臣之体。", "凭河死，悔时迟。", "凭河死，悔时迟。"]'),
('yuanqu-2868','红衲袄','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生扮陀满兴福上)将门庭，非小轻。',71,'元曲/yuanqu.json','["(小生扮陀满兴福上)将门庭，非小轻。", "掌貔貅，百万兵。", "威权勇猛千般计，势显英雄一派征。", "官宦族，名誉称，声闻彻帝京。", "好笑番魔也，怎当俺三千忠孝军。"]'),
('yuanqu-2869','赵皮鞋','施惠《幽闺记》','元','元曲','yuanqu','','[]','(丑上)我是个巡警官，日夜差科千万端。',36,'元曲/yuanqu.json','["(丑上)我是个巡警官，日夜差科千万端。", "俸钱些少几曾关，怎得三年官债满？。"]'),
('yuanqu-2870','大斋郎','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净上)狂秀才，命儿乖。',41,'元曲/yuanqu.json','["(净上)狂秀才，命儿乖。", "身允坊正是官差。", "三隅两巷民受灾。", "要无违碍，好生只把月钱来。"]'),
('yuanqu-2871','恤刑儿','施惠《幽闺记》','元','元曲','yuanqu','','[]','(丑)你十三，我十三，三个十三三十九，赛过东京白牡丹。',27,'元曲/yuanqu.json','["(丑)你十三，我十三，三个十三三十九，赛过东京白牡丹。"]'),
('yuanqu-2872','柳絮飞','施惠《幽闺记》','元','元曲','yuanqu','','[]','(丑)听我分付：一军人尽诛戮，诛戮；走了陀满兴福，兴福。',60,'元曲/yuanqu.json','["(丑)听我分付：一军人尽诛戮，诛戮；走了陀满兴福，兴福。", "遍将文榜诸州挂，都用心跟捉囚徒。", "(合)邻佑与窝主，停藏的罪同诛。"]'),
('yuanqu-2873','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末)圣旨非比寻俗，寻俗。',39,'元曲/yuanqu.json','["(末)圣旨非比寻俗，寻俗。", "明立官赏条局，条局。", "反叛朝廷非小可，市曹中影画形图。"]'),
('yuanqu-2874','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净)排门粉壁明书，明书。',39,'元曲/yuanqu.json','["(净)排门粉壁明书，明书。", "扰扰攘攘中都，中都。", "坊正干系天来大，没钱撰不比差夫。"]'),
('yuanqu-2875','金珑璁','施惠《幽闺记》','元','元曲','yuanqu','','[]','銮舆迁汴梁，朝廷，你信谗言杀害忠良，忠孝军尽沫亡。',45,'元曲/yuanqu.json','["銮舆迁汴梁，朝廷，你信谗言杀害忠良，忠孝军尽沫亡。", "慌慌逃命走，此身前往何方？天可表我衷肠。"]'),
('yuanqu-2876','北绛都春','施惠《幽闺记》','元','元曲','yuanqu','','[]','兴福家九族遭殃，六亲俱丧。',39,'元曲/yuanqu.json','["兴福家九族遭殃，六亲俱丧。", "衔冤枉，怎教俺三百口无罪身亡？兀的是平地里灾从天降。"]'),
('yuanqu-2877','混江龙','施惠《幽闺记》','元','元曲','yuanqu','','[]','大金主上，怨着大金主上，信谗言佞语，杀害我忠良。',128,'元曲/yuanqu.json','["大金主上，怨着大金主上，信谗言佞语，杀害我忠良。", "把俺忠孝军都杀尽，教俺一身逃难，离了家乡。", "朝廷忙传圣旨，差使命前往他方。", "把兴福图形画影，将文榜遍地里开张。", "拿住的请功受赏，但人家不许窝藏。", "却教俺走一步一步回头望。", "痛杀淹爹和娘。", "走得俺筋舒力乏，唬得俺魄散魂扬。"]'),
('yuanqu-2878','旋风子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末扮太白星上)祥云缥缈，飞升体探人间。',52,'元曲/yuanqu.json','["(末扮太白星上)祥云缥缈，飞升体探人间。", "湛湛清天不可欺，未曾举意早先知。", "善恶到头终有报，只争来早与来迟。"]'),
('yuanqu-2879','北雁儿落带过得胜令','施惠《幽闺记》','元','元曲','yuanqu','','[]','总乾坤一转丸，睹日月双琶箭。',71,'元曲/yuanqu.json','["总乾坤一转丸，睹日月双琶箭。", "浮生梦-场，世事云千变。", "万里玉门关，七里钓鱼滩。", "晓日长安近，秋风蜀道难。", "险些儿误杀了个英雄汉，凄凄冷冷，埋冤世间。"]'),
('yuanqu-2880','混江龙后','施惠《幽闺记》','元','元曲','yuanqu','','[]','望神圣将身隐藏。',46,'元曲/yuanqu.json','["望神圣将身隐藏。", "兴福撮土为香，祷告上苍，但愿得俺兴福离了天罗。", "脱了地纲。", "(推丑下，自坐科)。"]'),
('yuanqu-2881','六么令','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外、末、净、丑上)官司遍榜，捕捉陀满兴福恶党，正身拿住受官赏。',64,'元曲/yuanqu.json','["(外、末、净、丑上)官司遍榜，捕捉陀满兴福恶党，正身拿住受官赏。", "寻踪迹，问行藏，俺待见了，休想轻轻饶放。", "俺待见了，休想轻轻饶放。"]'),
('yuanqu-2882','好花儿','施惠《幽闺记》','元','元曲','yuanqu','','[]','(众)恨不得掘地翻天，见树边一人端然，是个土地公公塑在花园。',39,'元曲/yuanqu.json','["(众)恨不得掘地翻天，见树边一人端然，是个土地公公塑在花园。", "许金钱，望指点，。"]'),
('yuanqu-2883','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(众)寻不见连忙向前，搜索尽墙边院边。',43,'元曲/yuanqu.json','["(众)寻不见连忙向前，搜索尽墙边院边。", "莫不是隐身法术似神仙？走如烟，眼寻穿。", "(合前)。"]'),
('yuanqu-2884','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(众)捉拿了三千六千，做公人十年五年。',40,'元曲/yuanqu.json','["(众)捉拿了三千六千，做公人十年五年。", "马翰司公且休言，见着钱，最为先。", "(合前)。"]'),
('yuanqu-2885','金蕉叶','施惠《幽闺记》','元','元曲','yuanqu','','[]','谢天，谢了天，怎么不拜谢明郎神爷？谢神，避难来，幸脱离了祸门。',88,'元曲/yuanqu.json','["谢天，谢了天，怎么不拜谢明郎神爷？谢神，避难来，幸脱离了祸门。", "(欲下科。", "生上)咄！是何人入我园中暗隐？(小生跪科)告少息雷霆怒嗔。", "(生)汉子，这不是说话的去处，随我到亭子上来。"]'),
('yuanqu-2886','章台柳','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)情既紧，言又窘，我斟量非奸即盗贼。',93,'元曲/yuanqu.json','["(生)情既紧，言又窘，我斟量非奸即盗贼。", "(小生)小人不是贼，逃躯潜地奔。", "(生)既不是贼呵，无故入人家，有何事囚？(小生)小人也是好人家儿女。", "(生)你休得要逞花唇，稍虚词。", "送你到有司推问。"]'),
('yuanqu-2887','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','我将冤苦陈，教君不忍闻。',40,'元曲/yuanqu.json','["我将冤苦陈，教君不忍闻。", "(生)你是何处人氏？姓甚名谁？(小生)念兴福生来女直人。"]'),
('yuanqu-2888','醉娘儿','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)我听言，此情实为可悯。',165,'元曲/yuanqu.json','["(生)我听言，此情实为可悯。", "汉子，抬起头来我看。", "(小生抬头科生)觑着他貌英雄出辈群。", "(背云科)结交在未遇之先，施恩在当厄之日。", "看此人一貌堂堂，后来必有好处。", "欲结义他为兄弟，未知他意下何如？汉子，请起。", "你不嫌秀士贫，和你弟兄相识认。", "(小生)小人该死之徒，得蒙长者饶恕，已出望外，焉敢与长者齐躯？(生)这也非在今日，他时须记取今危困。"]'),
('yuanqu-2889','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生)死重生，怎敢忘伊大恩？(生)你多少年纪了？(小生)小人二十八岁。',174,'元曲/yuanqu.json','["(小生)死重生，怎敢忘伊大恩？(生)你多少年纪了？(小生)小人二十八岁。", "(生)我今年三十岁，长你二岁，你称我为兄便了。", "(小生)既如此，哥哥请上，受兄弟几拜。", "(生)不劳拜罢。", "(小生拜科)既为兄，休谦逊。", "(生)你拜我受之不稳。", "(小生)休道是百拜受不稳，受兄弟千拜何劳顿？除了仁兄呵，谁肯把我负屈衔冤问？(生)兄弟，我本待要留你在此。", "暂住几时，只是一件。"]'),
('yuanqu-2890','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生)拜别拜别，方欲离门。',259,'元曲/yuanqu.json','["(小生)拜别拜别，方欲离门。", "且住。", "我陀满兴福聪明了一世，懵懂在一时。", "方才跳入那秀士园中，他不拿我送官请赏，反助我银两，又结义我为兄弟。", "我久后若得寸进，欲报恩义，未知他姓甚名谁？猛回身，猛回身，又还思忖。", "(生)呀，兄弟，你去了怎么又转来？(小生)特有少禀，欲言又忍。", "(生)兄弟有甚话？但说不妨。", "(小生)哥哥姓和名，小兄弟敢问？(生)自家姓蒋，双名世隆。", "中都路人氏。", "兄弟，你三回四次问我的姓名，莫非恐人拿住，要攀扯着我么？(小生)无他效芹，略得进身，犬马报，怎敢做半米儿生分？(走科。", "生)兄弟且慢去，我还有几句言语嘱咐你。"]'),
('yuanqu-2891','山麻客','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)你去渡关津，怕有人盘问，又没个官司文凭路引。',50,'元曲/yuanqu.json','["(生)你去渡关津，怕有人盘问，又没个官司文凭路引。", "此行何处能安顿？蓦忽地怕有便人，寄取一封平安书信。"]'),
('yuanqu-2892','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生)兄长言，极明论。',52,'元曲/yuanqu.json','["(小生)兄长言，极明论。", "遍地军州，立赏明文。", "世没个男儿，有谁投奔？一片心，后土皇天，表我忠直，不陷良人。"]'),
('yuanqu-2893','尾声','施惠《幽闺记》','元','元曲','yuanqu','','[]','埋名避祸捱时运，满望取皇家赦恩。',65,'元曲/yuanqu.json','["埋名避祸捱时运，满望取皇家赦恩。", "罪大弥天，其时许自新。", "(生)古语积善逢善，(小生)常言知恩报恩。", "(合)此去愿逢吉地，前行莫撞凶门。"]'),
('yuanqu-2894','七娘子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦扮王瑞兰上)生居画阁兰堂里，正青春岁方及笄。',43,'元曲/yuanqu.json','["(旦扮王瑞兰上)生居画阁兰堂里，正青春岁方及笄。", "家世簪缨，仪容娇媚，那堪身处欢娱地？。"]'),
('yuanqu-2895','锦缠道','施惠《幽闺记》','元','元曲','yuanqu','','[]','髻云堆，珠翠簇。',78,'元曲/yuanqu.json','["髻云堆，珠翠簇。", "兰姿蕙质，香肌称罗绮。", "黛眉长，盈盈照一泓秋水。", "鞋直上冠儿至底。", "诸余没半星儿不美。", "针指暂闲时，花朝月夕，丫鬟侍妾随。", "好景须欢会，四时不负佳致。"]'),
('yuanqu-2896','朱奴儿','施惠《幽闺记》','元','元曲','yuanqu','','[]','春名苑，奇葩异卉。',51,'元曲/yuanqu.json','["春名苑，奇葩异卉。", "夏水阁，浮瓜沉李。", "秋玩蟾光折桂枝。", "逢冬景赏雪观梅。", "呼呼唤唤，愁是甚的？总不解愁滋味。"]'),
('yuanqu-2897','节节高','施惠《幽闺记》','元','元曲','yuanqu','','[]','(众)强梁勇猛人会一家，杀人放火张威霸。',68,'元曲/yuanqu.json','["(众)强梁勇猛人会一家，杀人放火张威霸。", "行劫掠，聚草粮，屯人马。", "惯战武艺多潇洒，从来贼胆天来大，蛟龙猛虎离山窝，闻风那个不惊怕？(下)。"]'),
('yuanqu-2898','醉罗哥','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生上)那日那日离都下，流落流落在天涯。',100,'元曲/yuanqu.json','["(小生上)那日那日离都下，流落流落在天涯。", "画影图形遍挨查，到处都张挂。", "草为茵褥，桥为住家。", "山花当饭，溪水当茶。", "陀满兴福这般苦楚呵。", "那些个\"一刻千金价。", "\"(内喊科。", "小生)兵戈扰，道路赊。", "几番回首望京华。"]'),
('yuanqu-2899','红绣鞋','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生)本为盖世英雄，英雄。',56,'元曲/yuanqu.json','["(小生)本为盖世英雄，英雄。", "奸邪疾妒难容，难容。", "万山深处隐其踪。", "不是路，且相从。", "屯作蚁，聚成蜂。", "屯作蚁，聚成蜂。"]'),
('yuanqu-2900','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(众)将军凛凛威风，威风。',55,'元曲/yuanqu.json','["(众)将军凛凛威风，威风。", "战袍绣虎雕龙，雕龙。", "山花斜插茜巾红。", "新寨上，坐山中。", "商旅过。", "莫遭逢。", "商旅过，莫遭逢。"]'),
('yuanqu-2901','丞相贤','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外扮王尚书上)弯弓驰骑射双雕，武勇超群胆气豪。',44,'元曲/yuanqu.json','["(外扮王尚书上)弯弓驰骑射双雕，武勇超群胆气豪。", "紫袍会带非同小，见随朝，兵部尚书官养老。"]'),
('yuanqu-2902','番鼓儿','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净)为塞北。',67,'元曲/yuanqu.json','["(净)为塞北。", "为塞北，兴兵临边鄙。", "但州城关津险隘，势怎当敌？待欲迁都回避。", "不许稽迟，上京去缉探事实。", "(合)火速便驰驿，等回音星飞电急。"]'),
('yuanqu-2903','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)念老臣，念老臣，年登七十岁。',56,'元曲/yuanqu.json','["(外)念老臣，念老臣，年登七十岁。", "今又奉朝廷敕旨。", "事屈安危，恨不得肋生双翅。", "两头白日，多只行五里十里。", "(合前)。"]'),
('yuanqu-2904','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末)紧使人，紧使人，疾速催驿骑。',55,'元曲/yuanqu.json','["(末)紧使人，紧使人，疾速催驿骑。", "便疾忙安排鞍辔，打点行李。", "这回须教仔细，先解缰绳，怕骑了没头马儿。", "(合前)。"]'),
('yuanqu-2905','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净)兀剌赤，兀剌赤。',17,'元曲/yuanqu.json','["(净)兀剌赤，兀剌赤。", "门外等多时。"]'),
('yuanqu-2906','双劝酒','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)军情紧急，国家责委，不敢行违滞。',52,'元曲/yuanqu.json','["(外)军情紧急，国家责委，不敢行违滞。", "常言道，养兵千日，今朝用人之际。", "(合)火速便驰驿，等回音星飞电急。"]'),
('yuanqu-2907','东风第一枝','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦上)宫日添长，壶冰结满，仲冬天气严寒。',72,'元曲/yuanqu.json','["(老旦上)宫日添长，壶冰结满，仲冬天气严寒。", "(旦上)绣工停却金针，红炉画阁人闲。", "金猊香袅。", "丽曲趁舞袖弓弯。", "(合)锦帐中褥隐荚蓉。", "怎教鹦鹉杯干？。"]'),
('yuanqu-2908','摧拍','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)受君恩，身居从班。',79,'元曲/yuanqu.json','["(外)受君恩，身居从班。", "食君禄，怎敢辞难？(老旦)此行非同小看，非同小看。", "缉探上京虚实，便往边关。", "漠漠平沙，路远天寒。", "(合)一别后涉水登山。", "今日去，甚时还？。"]'),
('yuanqu-2909','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)气力衰，行履尚难，怎驱驰挥鞭跨鞍？(旦)愁只愁路里；愁只愁路里，难禁冒雨蒙霜。',63,'元曲/yuanqu.json','["(老旦)气力衰，行履尚难，怎驱驰挥鞭跨鞍？(旦)愁只愁路里；愁只愁路里，难禁冒雨蒙霜。", "此身劳烦，谁奉兴居？暮宿朝餐。", "(合前)。"]'),
('yuanqu-2910','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)去难留，愁擎凤盏。',68,'元曲/yuanqu.json','["(旦)去难留，愁擎凤盏。", "爱情深，重掩泪眼。", "(外)休忧虑放怀，休忧虑放怀。", "堂上母亲，叮咛小心相看。", "(老旦)娘女在家中，怎免愁烦？(合前)。"]'),
('yuanqu-2911','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(丑、末)宣限紧，休作等闲。',65,'元曲/yuanqu.json','["(丑、末)宣限紧，休作等闲。", "报国家，忠心似丹。", "(旦)稍迟延半晌，稍迟延半晌。", "寻思只得些时，面觑尊颜。", "子父隔绝，雾阻云拦。", "(合前)。"]'),
('yuanqu-2912','一撮棹','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)夫人只得就此分别了。',100,'元曲/yuanqu.json','["(外)夫人只得就此分别了。", "今日去，便驰驿离乡关。", "朝廷命，疾登途，怕迟晚。", "(老旦)兵南进，兴戈甲，取江山。", "(旦)遭离乱，家无仁，怎逃难？(外)虽士马侵边紧，两三月便回还。", "(老旦)专心望，望佳音，报平安。"]'),
('yuanqu-2913','缑山月','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生上)守正处寒炉，勤苦诵诗书。',334,'元曲/yuanqu.json','["(生上)守正处寒炉，勤苦诵诗书。", "盼春闱身进践荣途。", "奈双亲服制，前程未遂，敢仰天呼。", "(小旦上)乐道安贫巨儒，嗟怨是何如？但孜孜有志效鸿鹄，似藏珍韫匮，韬光隐讳，待价沽诸。", "哥哥万福。", "(生)妹子到来，妹子请坐。", "(小旦)哥哥请。", "哥哥，妹子往常间见哥哥眉开眼笑，今日因甚眉头不展，面带忧容，却为何来？(生)妹子，你不知道我有三件事在心，所以不乐。", "(小旦)那三件？(生)第一件，父母灵柩在堂，未曾殡葬；第二件，我服制在身，难以进取；第三件，你我年纪长大，亲事未谐。", "以此不乐。", "(小旦)［玉楼春］瑞莲愚不将贤谏，安居温习何嗟叹？退藏山水作渔樵，进身皇阙为官宦。", "(生)妹子，迅速光阴如转眼，少年何事功名赚？苍天未必误儒冠，儒冠岂误男儿汉？(小旦)哥哥，你平日攻书多少，谅必自知上达之意。"]'),
('yuanqu-2914','玉芙蓉','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)胸中书，富五车，笔下句，高千古。',72,'元曲/yuanqu.json','["(生)胸中书，富五车，笔下句，高千古。", "镇朝经暮史，寐晚兴夙。", "拟蟾宫折桂云梯步，待求官奈何服制拘？教人怨，怨不沾寸禄。", "(合)望当今圣明天子诏贤书。"]'),
('yuanqu-2915','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)功名事本在天，何必心过虑？且从他得失，任取荣枯。',60,'元曲/yuanqu.json','["(小旦)功名事本在天，何必心过虑？且从他得失，任取荣枯。", "为人只恐身无艺。", "暂时间未从心所欲，金埋土，也须会离土。", "(合前)。"]'),
('yuanqu-2916','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)难服，晚进儿童，肥马轻裘，污紫夺朱。',60,'元曲/yuanqu.json','["(生)难服，晚进儿童，肥马轻裘，污紫夺朱。", "磊落男儿，暂睹蠢尔之徒。", "(小旦)听语，万事皆由天命，尽皆非者也之乎。", "(合前)。"]'),
('yuanqu-2917','薄媚衮','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生、小旦)听人报军马近城，国主迁都汴。',62,'元曲/yuanqu.json','["(生、小旦)听人报军马近城，国主迁都汴。", "今晚庶民，不许一人落后在京辇。", "生长升平，谁曾惯遭离乱。", "苦怎言，胆颤心惊，如何可免？。"]'),
('yuanqu-2918','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','听街坊巷陌，唯闻得炒炒哀声遍。',56,'元曲/yuanqu.json','["听街坊巷陌，唯闻得炒炒哀声遍。", "急去打叠金共宝，随身带做盘缠。", "田业家私不能守，不能恋。", "两泪涟，生死安危，只得靠天。"]'),
('yuanqu-2919','贺圣朝','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生上)斩龙射虎威风，擒王捉将英雄。',34,'元曲/yuanqu.json','["(小生上)斩龙射虎威风，擒王捉将英雄。", "锦征袍相称茜巾红，镇山北山东。"]'),
('yuanqu-2920','豹子令','施惠《幽闺记》','元','元曲','yuanqu','','[]','闻说中都起战尘，起战尘。',53,'元曲/yuanqu.json','["闻说中都起战尘，起战尘。", "黎民逃难乱纷纷，乱纷纷。", "怕有推车儋提人经过，劫掠财宝共金银。", "(合)登山蓦领用心巡。"]'),
('yuanqu-2921','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净)休避些儿苦共勤，苦共勤。',48,'元曲/yuanqu.json','["(净)休避些儿苦共勤，苦共勤。", "提刀携剑共成群，共成群。", "士农工商钱夺下，回来山寨醉醺醺。", "(合前)。"]'),
('yuanqu-2922','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(丑)劫掠金珠个要分，不要分。',49,'元曲/yuanqu.json','["(丑)劫掠金珠个要分，不要分。", "肥羊美酒不沾唇，不沾唇。", "但愿捉得个多娇女。", "将来压寨做大人。", "(合前)。"]'),
('yuanqu-2923','破阵子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦上)况是君臣分散。',40,'元曲/yuanqu.json','["(老旦上)况是君臣分散。", "那堪母子临危。", "(旦上)严父东行何日返？天子南迁甚日回？。"]'),
('yuanqu-2924','渔家傲','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)天不念去国愁人最惨凄，淋淋的雨若盆倾，风如箭急。',74,'元曲/yuanqu.json','["(老旦)天不念去国愁人最惨凄，淋淋的雨若盆倾，风如箭急。", "(旦)侍妾从人皆星散，各逃生计。", "(合)身居处华尾高堂，但寻常珠绕翠围。", "那曾经地覆天翻受苦时。"]'),
('yuanqu-2925','摊破地锦花','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)绣鞋儿，分不得帮和底。',55,'元曲/yuanqu.json','["(旦)绣鞋儿，分不得帮和底。", "-步步提，百忙里褪了跟儿。", "(老旦)冒雨荡风，带水拖泥。", "(合)步难移，全没些气和力。"]'),
('yuanqu-2926','麻婆子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)路途路途行不惯，心惊胆颤摧。',81,'元曲/yuanqu.json','["(老旦)路途路途行不惯，心惊胆颤摧。", "(旦)地冷地冷行不上，人慌语乱催。", "(老旦)年高力弱怎支持？(倒科，旦扶科。", "旦)泥滑跌倒在冻田地。", "款款扶将起，(合)心急步行迟。"]'),
('yuanqu-2927','薄幸','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生上)凛冽寒风，淋漓冷雨，送君臣南北，父子东西。',42,'元曲/yuanqu.json','["(生上)凛冽寒风，淋漓冷雨，送君臣南北，父子东西。", "(小旦上)心肠痛，不幸见刀兵冗冗。"]'),
('yuanqu-2928','赛观音','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)雨儿催，风儿送。',45,'元曲/yuanqu.json','["(生)雨儿催，风儿送。", "叹一旦家邦尽空。", "(小旦)想富贵荣华如梦。", "(合)哽咽伤心，教我气填胸。"]'),
('yuanqu-2929','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)意儿慌，脚儿痛。',44,'元曲/yuanqu.json','["(小旦)意儿慌，脚儿痛。", "颤笃速如痴似懵。", "(生)苦捱着疾忙行动。", "(合)郊野看看又早晚烟笼。"]'),
('yuanqu-2930','人月圆','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)途路里，奔走流民拥，胆丧魂飞心惊恐。',59,'元曲/yuanqu.json','["(生)途路里，奔走流民拥，胆丧魂飞心惊恐。", "(小旦)风吹雨湿衣襟重，止不住双双珠泪涌。", "(合)行不上，惟闻得战鼓声振苍穹。"]'),
('yuanqu-2931','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)军马又来，四下如铁桶。',61,'元曲/yuanqu.json','["(生)军马又来，四下如铁桶。", "眼见得京师城壁空。", "(小旦)他每赶着无轻纵，人似豺狼马似龙。", "(合)遭驱虏，亲骨肉甚年何日重逢？。"]'),
('yuanqu-2932','满江红','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦、旦上)身遭兵火，身遭兵火，母子逃生受奔波。',94,'元曲/yuanqu.json','["(老旦、旦上)身遭兵火，身遭兵火，母子逃生受奔波。", "怎禁得风雨摧残。", "田地上坎坷。", "泥滑路生行未多。", "军马追急，教我怎奈何？弹珠颗，冒雨荡风，沿山转坡。", "(众番上，赶老旦、旦下，众番抢伞诨科，下)。"]'),
('yuanqu-2933','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生、小旦上)身遭兵火，身遭兵火，兄妹逃生受奔波。',72,'元曲/yuanqu.json','["(生、小旦上)身遭兵火，身遭兵火，兄妹逃生受奔波。", "怎禁得风雨摧残，田地上坎坷。", "泥滑路生行末多。", "军马追急，教我怎奈何？弹珠颗，冒雨荡风，沿山转坡。"]'),
('yuanqu-2934','东瓯令','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦上)我那娘！心如醉，泪交流。',53,'元曲/yuanqu.json','["(旦上)我那娘！心如醉，泪交流。", "去远家尊绝信久，途中母子生离别。", "这苦如何受？一重愁翻做两重愁，是我命合休。"]'),
('yuanqu-2935','望梅花','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生上)瑞莲！叫得我不绝口。',50,'元曲/yuanqu.json','["(生上)瑞莲！叫得我不绝口。", "恰被喊杀声流民四走。", "慌急便寻，不知个所有。", "此间无处安身，想只在前头后头。"]'),
('yuanqu-2936','东瓯令','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦上)瑞兰！寻思苦，路生疏。',53,'元曲/yuanqu.json','["(老旦上)瑞兰！寻思苦，路生疏。", "军喊风传行路促，娘儿挽手相回护，这苦难分诉。", "望天天怜念老身孤，免使受奔波。"]'),
('yuanqu-2937','满江红尾','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦上)我那哥哥！大喊一声过，唬得人獐狂鼠窜。',52,'元曲/yuanqu.json','["(小旦上)我那哥哥！大喊一声过，唬得人獐狂鼠窜。", "那里去了，哥哥！怎生撇下了我？教我无处安身，无门路可躲。"]'),
('yuanqu-2938','金莲子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦上)古今愁，古今愁，谁似我目下这样愁？听军马骤，听军马骤，人乱语稠。',52,'元曲/yuanqu.json','["(旦上)古今愁，古今愁，谁似我目下这样愁？听军马骤，听军马骤，人乱语稠。", "向深林中逃难，恐有人搜。", "(下)。"]'),
('yuanqu-2939','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生上)百忙里散失，差了路头。',61,'元曲/yuanqu.json','["(生上)百忙里散失，差了路头。", "寻妹子不见，教我怎措手？瑞莲！(旦内应科。", "生)神天佑，神天佑，这答儿是有亲骨肉。", "见了向前走。"]'),
('yuanqu-2940','菊花新','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦应上)你是何人我是准？(生)应了还应，呀，见又非。',44,'元曲/yuanqu.json','["(旦应上)你是何人我是准？(生)应了还应，呀，见又非。", "(旦)将咱小名提，进前去问他端的。"]'),
('yuanqu-2941','古轮台','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)自惊疑，相呼厮呼两相回。',166,'元曲/yuanqu.json','["(旦)自惊疑，相呼厮呼两相回。", "瑞兰和先辈不曾相识。", "(生)瑞莲名儿本是卑人亲妹。", "不知娘子因甚到此？(旦)妾因兵火急，离乡故。", "(生)娘子如何独行？(旦)母子随迁往南避，中途相失。", "秀才在何处不见了令妹？(生)喊杀声，各各逃生，电奔星驰。", "中途里差池，因循寻至。", "应声错，偶逢伊。", "娘子不见了母亲，小生不见了妹子。", "正是两人俱错意，一般烦恼两心知。"]'),
('yuanqu-2942','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)名儿应错了自先回。',116,'元曲/yuanqu.json','["(生)名儿应错了自先回。", "(旦)秀才那里去？(生)急急便往跟寻，岂容迟滞。", "(旦)事到如今，事到头来，怎生惜得羞耻。", "(拜科)秀才念苦怜孤，救奴残喘，带奴离此免灾危，我也不忘你的恩义。", "(生)娘子，你方才说不见了令堂，远远望见一位妈妈来了。"]'),
('yuanqu-2943','扑灯蛾','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)自亲妹不见影，自亲妹不见影，他人怎相庇？(旦)秀才，你读书也不曾？(生)秀才家何书不读览？(旦)书上说道"恻隐之心，人皆有之。',155,'元曲/yuanqu.json','["(生)自亲妹不见影，自亲妹不见影，他人怎相庇？(旦)秀才，你读书也不曾？(生)秀才家何书不读览？(旦)书上说道\"恻隐之心，人皆有之。", "\"既然读诗书，恻隐心怎不周急也？(生)你只晓得有恻隐之心，那晓得有别嫌之礼？我是个孤男，你是寡女。", "厮赶着教人猜疑。", "(旦)乱军中，乱军中，有谁来问你？(生)缓急间，语言须是要支持。"]'),
('yuanqu-2944','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)路中不挡拦，(生)路中若挡拦？。',19,'元曲/yuanqu.json','["(旦)路中不挡拦，(生)路中若挡拦？。"]'),
('yuanqu-2945','尾','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)今日得君提掇起，免使一身在污泥。',19,'元曲/yuanqu.json','["(旦)今日得君提掇起，免使一身在污泥。"]'),
('yuanqu-2946','普天乐','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦上)我那哥哥。',105,'元曲/yuanqu.json','["(小旦上)我那哥哥。", "叫得我气全无，哭得我声难语。", "只教我两头来往到千百步。", "兄安在？妾是何如？真个是逆旅穷途。", "哥哥，须念我，念我爹娘身故，须是一蒂一瓜儿和女，怎割得断兄妹肠肚，将奴闪下在这里？进无门，退也还又无所。"]'),
('yuanqu-2947','山桃红','施惠《幽闺记》','元','元曲','yuanqu','','[]','大道上，难前去。',60,'元曲/yuanqu.json','["大道上，难前去。", "小路里，怎逃伏？遥望窝梁三两间茅檐屋，转弯环野径，休辞苦，暂安身，少避些风和雨。", "多管是村野民居。", "(下)。"]'),
('yuanqu-2948','生查子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦上)行寻行又寻。',51,'元曲/yuanqu.json','["(老旦上)行寻行又寻。", "瑞兰！(小旦内应科。", "老旦)远远闻人应。", "瑞兰！(小旦应上)呼唤瑞莲名，听了还重省。"]'),
('yuanqu-2949','水仙子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)眼又昏，天将暝，趁声儿向前厮认。',104,'元曲/yuanqu.json','["(老旦)眼又昏，天将暝，趁声儿向前厮认。", "(认科)我那儿，浑身上雨水淋漓，尽皆泥泞，生来这苦何曾惯经？(小旦)眼见错，十分定。", "事无可奈，只得陪些下情。", "老娘？(合)你是高年人，怎生行得这山径？瑞莲款款扶着娘慢行。"]'),
('yuanqu-2950','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)观模佯，听浯声。',72,'元曲/yuanqu.json','["(老旦)观模佯，听浯声。", "呀，你是阿谁便应承？枉了许多时，教娘苦相等。", "(小旦)非诈应。", "瑞莲听得名儿厮类，怕寻觅是我家兄。", "偶遇老娘如再生。", "(合前)。"]'),
('yuanqu-2951','刮地风','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)看他举止，与我孩儿也不甚争。',112,'元曲/yuanqu.json','["(老旦)看他举止，与我孩儿也不甚争。", "小娘子，厮跟去，你可心肯？(小旦)奴家不见了哥哥，望老娘带奴同行则个。", "(老旦)事既如此，我就把你做女儿看承罢。", "(小旦)情愿做小为婢身，焉敢指望做儿称？(老旦)若得干戈宁静，和你同往到神京。"]'),
('yuanqu-2952','高阳台引','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生、旦上。',71,'元曲/yuanqu.json','["(生、旦上。", "生)凛凛严寒，漫漫肃气，依稀晓色将开。", "宿水餐风，去客尘埃。", "(旦)思今念往心自骇，受这苦谁想谁猜。", "(合)望家乡，水远山遥，雾锁云埋。"]'),
('yuanqu-2953','山坡羊','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)翠巍巍云山一带，碧澄澄寒波几派？深密密烟林数簇，滴溜溜黄叶都飘败。',92,'元曲/yuanqu.json','["(生)翠巍巍云山一带，碧澄澄寒波几派？深密密烟林数簇，滴溜溜黄叶都飘败。", "一两阵风，三五声过雁哀。", "(旦)伤心对景愁无奈。", "回首家乡，珠洲满腮。", "(合)情怀，急煎煎闷似海。", "形骸，骨岩岩瘦似柴。"]'),
('yuanqu-2954','水红花','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)忆昔歌舞宴楼台，会金钗。',40,'元曲/yuanqu.json','["(旦)忆昔歌舞宴楼台，会金钗。", "欢娱难再。", "(生)思之诗酒看书斋，命多乖，风光难再。"]'),
('yuanqu-2955','金钱花','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生、旦)听得数声锣筛，锣筛。',59,'元曲/yuanqu.json','["(生、旦)听得数声锣筛，锣筛。", "好汉山前齐摆。", "齐摆。", "个个狞恶似狼豺。", "(外、末、净、丑上)留买路，与钱财；不留与，便杀坏。"]'),
('yuanqu-2956','念佛子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生、旦)穷秀才，夫和妇，为士马逃难登途。',65,'元曲/yuanqu.json','["(生、旦)穷秀才，夫和妇，为士马逃难登途。", "望相怜，壮士略放一路。", "［众］捉住。", "枉自说闲言语。", "买路钱留下金珠，稍迟延，便教你身丧须臾。"]'),
('yuanqu-2957','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生、旦)区区，山行路宿，粥食无觅处。',51,'元曲/yuanqu.json','["(生、旦)区区，山行路宿，粥食无觅处。", "有盘缠肯相推阻？(众)穷酸饿儒，模样须寻俗。", "随行所有，疾忙分付。"]'),
('yuanqu-2958','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生、旦)苦不苦。',55,'元曲/yuanqu.json','["(生、旦)苦不苦。", "从头至足，衣衫皆褴褛。", "难同他往来客旅。", "(众)你不与，我施威仗勇，轮动刀和斧。", "激得人忿心发怒。"]'),
('yuanqu-2959','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生、旦)告饶恕。',76,'元曲/yuanqu.json','["(生、旦)告饶恕。", "魂飞胆颤摧，神恐心惊惧。", "此身恁地负屈死，真实何辜？(众绑生、旦科)且执缚，管押前去山寨里，听从区处。", "(生、旦)到那里，吉凶事全然未知。"]'),
('yuanqu-2960','粉蝶儿','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生上)山寨鸣金，白鹤半空展翅。',17,'元曲/yuanqu.json','["(小生上)山寨鸣金，白鹤半空展翅。"]'),
('yuanqu-2961','尾犯序','施惠《幽闺记》','元','元曲','yuanqu','','[]','山径路幽僻，但寻常此间来往人稀。',68,'元曲/yuanqu.json','["山径路幽僻，但寻常此间来往人稀。", "男女相随。", "岂是良人行上？(生、旦)凶时，遭士马流民散失，避干戈村臣远徙。", "夫和妇，为天摧地塌，逃难路途迷。"]'),
('yuanqu-2962','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生)无非买命与赎身，但随行有何囊箧资费？(生、旦)没有，将军。',94,'元曲/yuanqu.json','["(小生)无非买命与赎身，但随行有何囊箧资费？(生、旦)没有，将军。", "(众)快口强舌，休同儿戏。", "(生、旦)听启，乱慌慌行来数日，苦滴滴实没半厘。", "(众)你好不知礼。", "常言道：\"打鱼猎射怎空回？\"。"]'),
('yuanqu-2963','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生)军前令怎移？但一言既出，驷马难追。',89,'元曲/yuanqu.json','["(小生)军前令怎移？但一言既出，驷马难追。", "(生、旦)将军可怜饶命。", "(众)枉自厚礼卑词，休想饶你。", "(旦)伤悲，王瑞兰遭刑枉死。", "(生)蒋世隆衔冤负屈。", "天和地，有谁人可怜？烧陌纸钱灰。"]'),
('yuanqu-2964','梁州赚','施惠《幽闺记》','元','元曲','yuanqu','','[]','且与我留人，押回来问取详细。',108,'元曲/yuanqu.json','["且与我留人，押回来问取详细。", "那汉子，你家居在那里？农种工商学文艺？(生)通诗礼，乡进士，州痒屡魁，中都路离城三里。", "(小生)因甚到此？(生)闲居止，因兵火弃家无所倚。", "(小生)听说仔细。", "汉子，抬起头来我看。", "(生抬头科)。"]'),
('yuanqu-2965','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生)紧降阶，释缚扶将起，是兄弟负恩忘义。',67,'元曲/yuanqu.json','["(小生)紧降阶，释缚扶将起，是兄弟负恩忘义。", "这是何人？(生)是我浑家。", "(小生)尊嫂受礼。", "谁知此地能完聚？(旦)愁为喜，深谢得贤叔盗跖。"]'),
('yuanqu-2966','鲍老催','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生)朝廷当时巡捕急，闪避在围墙内。',62,'元曲/yuanqu.json','["(小生)朝廷当时巡捕急，闪避在围墙内。", "若非恩人救难危，险赴法云阳市。", "(生)呀，原来是兴福兄弟。", "相逢狭路难叫避，这言语古来提。"]'),
('yuanqu-2967','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','酒浮嫩醅，酒浮嫩醅，压惊解烦休要推。',87,'元曲/yuanqu.json','["酒浮嫩醅，酒浮嫩醅，压惊解烦休要推。", "嫂嫂请酒，(旦)奴家天性不饮。", "(小生)寒色告少饮半杯。", "(旦)非诈伪，量浅窄，休央及。", "(小牛)高歌畅饮展放眉，开怀醉了重还醉。", "酒待人无恶意。"]'),
('yuanqu-2968','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)秀才，你儒业祖传袭，文章幼攻习。',41,'元曲/yuanqu.json','["(旦)秀才，你儒业祖传袭，文章幼攻习。", "我低低问，暗暗猜，心疑忌，叔伯远房姑舅的？。"]'),
('yuanqu-2969','尾','施惠《幽闺记》','元','元曲','yuanqu','','[]','男儿志。',26,'元曲/yuanqu.json','["男儿志。", "心肯灰？一旦风云际会，怎肯依旧中原一布衣？。"]'),
('yuanqu-2970','天下乐','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦上)行尽长亭又短亭，穷途路，那曾经？(小旦上)飘零此身如萍梗，叹何日归到神京？。',43,'元曲/yuanqu.json','["(老旦上)行尽长亭又短亭，穷途路，那曾经？(小旦上)飘零此身如萍梗，叹何日归到神京？。"]'),
('yuanqu-2971','羽调排歌','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)黯黯云迷，寒天暮景，驱驰水涉山登。',74,'元曲/yuanqu.json','["(老旦)黯黯云迷，寒天暮景，驱驰水涉山登。", "萧萧黄叶舞风轻，这样愁烦不惯经。", "不忍听，不美听，听得胡笳野外两三声。", "(合)风力劲，天气冷。", "一程分作两程行。"]'),
('yuanqu-2972','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)只见数点寒鸦，投林乱鸣，晚烟宿雾冥冥。',62,'元曲/yuanqu.json','["(小旦)只见数点寒鸦，投林乱鸣，晚烟宿雾冥冥。", "迢迢古岸水澄澄，野渡无人舟自横。", "不忍听，不美听，听得孤鸿天外两三声。", "(合前)。"]'),
('yuanqu-2973','忆多娇犯','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)前路梗，行步生，那更大将暝。',84,'元曲/yuanqu.json','["(老旦)前路梗，行步生，那更大将暝。", "尤心战兢兢，伤情泪盈盈。", "那些儿凄惨，那些儿寂寞，清风明月最关情。", "无人来往冷清清，叫他不应天怎闻？不忍听，不美听，听得疏钟山外两三声。"]'),
('yuanqu-2974','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)忽地明，一盏灯，遥望茅檐近。',87,'元曲/yuanqu.json','["(老旦)忽地明，一盏灯，遥望茅檐近。", "不须意儿省。", "休得慢腾腾。", "休辞迢递，望明前去。", "远临此地叩柴扃。", "今宵付舍暂消停，卧却山城长短更。", "不忍听。", "不美听，听得寒砧林外两三声。", "(合前)。"]'),
('yuanqu-2975','尾','施惠《幽闺记》','元','元曲','yuanqu','','[]','(合)得暂宁，天之幸，一夕安稳到天明，免使狼藉遑遑登路程。',29,'元曲/yuanqu.json','["(合)得暂宁，天之幸，一夕安稳到天明，免使狼藉遑遑登路程。"]'),
('yuanqu-2976','驻马听','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生、旦上)一路里奔驰，多少艰辛，来到这里。',71,'元曲/yuanqu.json','["(生、旦上)一路里奔驰，多少艰辛，来到这里。", "且喜略时才肃静，渐次平安，稍而宁息。", "恨悠悠千里旅情悲，苦恹恹一片乡心碎。", "感叹咨嗟，伤情满眼关山泪。"]'),
('yuanqu-2977','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(丑)草舍茅檐，门面不妆酒味美。',33,'元曲/yuanqu.json','["(丑)草舍茅檐，门面不妆酒味美。", "真个杯浮绿蚁。", "榨滴珍珠，瓮泼新醅。"]'),
('yuanqu-2978','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(丑)潋滟流霞。',66,'元曲/yuanqu.json','["(丑)潋滟流霞。", "(生)酒保，你怎么把脸儿遮了？(丑)小人脸儿不那个，恐娘子见了不肯吃酒。", "不比寻常卖酒家。", "娘子请一杯。", "(旦)我不会吃。"]'),
('yuanqu-2979','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)闷可消除，只怕醉倒黄公旧酒垆。',18,'元曲/yuanqu.json','["(生)闷可消除，只怕醉倒黄公旧酒垆。"]'),
('yuanqu-2980','绛都春','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)担烦受恼，岂容易，共伊得到今朝？有分忧愁，无缘恩爱，何时了？(旦)长吁短叹，我心自晓。',99,'元曲/yuanqu.json','["(生)担烦受恼，岂容易，共伊得到今朝？有分忧愁，无缘恩爱，何时了？(旦)长吁短叹，我心自晓。", "(生)娘子，你晓得我甚么？(旦)有甚的真情深奥？(生)正要娘子晓得。", "(旦)礼法所制，人非土木，待说也难道。"]'),
('yuanqu-2981','降黄龙','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)说甚么宦室门楣，寒士寻常，望若云霄？时移事迁，为地覆天翻，君去民逃。',69,'元曲/yuanqu.json','["(生)说甚么宦室门楣，寒士寻常，望若云霄？时移事迁，为地覆天翻，君去民逃。", "多娇，此时相遇，料应我和你姻缘非小，做夫妻相呼厮唤，怎生忘了？。"]'),
('yuanqu-2982','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)秀才，何劳，奖誉过高。',40,'元曲/yuanqu.json','["(旦)秀才，何劳，奖誉过高。", "昔日荣华，眼前穷暴。", "身无所倚，幸然遇君家，危途相保。"]'),
('yuanqu-2983','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)听告。',65,'元曲/yuanqu.json','["(生)听告。", "你身到行朝，与父母团圆，再同欢笑。", "那时节呵！你在深沉院宇，要见你除非是梦魂来到。", "(旦)我禀过父亲，那时与你成亲也不迟。"]'),
('yuanqu-2984','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)休焦，所许前问，侍枕之私，敢惜微眇。',56,'元曲/yuanqu.json','["(旦)休焦，所许前问，侍枕之私，敢惜微眇。", "(生)既如此，却又推三阻四怎么？(旦)怕仁人累德，娶而不告，朋友相嘲。"]'),
('yuanqu-2985','太平令','施惠《幽闺记》','元','元曲','yuanqu','','[]','曲径非遥，深夜柴门带月敲。',36,'元曲/yuanqu.json','["曲径非遥，深夜柴门带月敲。", "邮亭一宿姻缘好，又何故浯叨叨？(生、旦见科)。"]'),
('yuanqu-2986','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)旅邸萧条，回首乡关路转遥。',31,'元曲/yuanqu.json','["(生)旅邸萧条，回首乡关路转遥。", "寒灯照影伤怀抱。", "因此上话通宵。"]'),
('yuanqu-2987','扑灯蛾','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末、净)才郎殊美好，佳人正年少。',66,'元曲/yuanqu.json','["(末、净)才郎殊美好，佳人正年少。", "相逢邂逅间，姻缘会合非小也。", "天然凑巧，把招商店权做个蓝桥。", "翠帷中风清月皎，算欢娱。", "各金难买是今宵。"]'),
('yuanqu-2988','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)礼仪谨化源，关雎始风教。',67,'元曲/yuanqu.json','["(旦)礼仪谨化源，关雎始风教。", "一时见君子，匆匆遽成人道也。", "(生)我是山鸡野鸟，配青鸾无福难消。", "仗冰人一言已定，此生此德，何以报琼瑶？。"]'),
('yuanqu-2989','衮遍','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)不肯赋情薄，不肯赋情薄，随顺教人笑，空使我意沉吟，眉留目乱羞难道。',62,'元曲/yuanqu.json','["(旦)不肯赋情薄，不肯赋情薄，随顺教人笑，空使我意沉吟，眉留目乱羞难道。", "(生)看他喜时模样，愁时容貌，灯儿下，越看着越波俏。"]'),
('yuanqu-2990','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)才郎意坚牢，才郎意坚牢，贱妾难推调。',109,'元曲/yuanqu.json','["(旦)才郎意坚牢，才郎意坚牢，贱妾难推调。", "只恐容易间，把恩情心事都忘了。", "(生)蒋世隆若有此心。", "与你星前月下去罚下誓来。", "(旦)你自去罚。", "(生)蒋世隆若忘了小姐厚恩，永远前程不吉。", "海誓山盟，神大须表。", "办至诚，图久远同谐老。"]'),
('yuanqu-2991','尾声','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)恩情岂比闲花草？(生)往常恨更长寂寥，今夜只愁天易晓。',30,'元曲/yuanqu.json','["(旦)恩情岂比闲花草？(生)往常恨更长寂寥，今夜只愁天易晓。"]'),
('yuanqu-2992','三棒鼓','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外王尚书、丑六儿引众上。',69,'元曲/yuanqu.json','["(外王尚书、丑六儿引众上。", "外)一鞭行色塑南京，喜得两国通和也无战争。", "边疆罢征，边烽罢惊，不暂停。", "(合)如今海晏河清也，重逢太平，重乐太平。"]'),
('yuanqu-2993','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)远闻军马犯边城，怎奈奉旨登途也离乡背井。',73,'元曲/yuanqu.json','["(外)远闻军马犯边城，怎奈奉旨登途也离乡背井。", "这场战争，这场恐惊，谁惯经？(合前)玉帛交欢四海清，家无王事国无征。", "太平元是将军定，还许将军见太平。"]'),
('yuanqu-2994','称人心','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生上)宵行昼伏，脱离虎门鲸牙。',53,'元曲/yuanqu.json','["(小生上)宵行昼伏，脱离虎门鲸牙。", "不得已截道打家，聚亡生，集舍死，山间林下。", "逆天无道。", "这荣华。", "成甚生涯？。"]'),
('yuanqu-2995','五韵美','施惠《幽闺记》','元','元曲','yuanqu','','[]','休戈甲，罢征戍，区宇宣王化，惠及生灵。',51,'元曲/yuanqu.json','["休戈甲，罢征戍，区宇宣王化，惠及生灵。", "恩沾遐迩。", "如今日之际，海之涯，普天之下，再生重见太平，欢声四洽。"]'),
('yuanqu-2996','三登乐','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦扶生上)世乱人荒，幸脱离天罗地网。',52,'元曲/yuanqu.json','["(旦扶生上)世乱人荒，幸脱离天罗地网。", "不提防病染这场。", "事不宁，身未稳，天降灾殃。", "淹留旅邸，望河南怎往？。"]'),
('yuanqu-2997','水底鱼','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净上)三世行医，四方人尽知。',51,'元曲/yuanqu.json','["(净上)三世行医，四方人尽知。", "不论贵贱。", "请着的即便医。", "卢医扁鹊，料他直甚的？人人道我，道我是个催命鬼。"]'),
('yuanqu-2998','柰子花','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净)他犯着产后惊风。',17,'元曲/yuanqu.json','["(净)他犯着产后惊风。", "(旦)不是。"]'),
('yuanqu-2999','驻马听','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净)这咏息昏沉，两手如冰骇死人。',54,'元曲/yuanqu.json','["(净)这咏息昏沉，两手如冰骇死人。", "叫几个尼姑和尚，做些功果，送出南门，鬼门关上来招魂。", "叫些木匠，早把棺材钉。"]'),
('yuanqu-3000','剔银灯','施惠《幽闺记》','元','元曲','yuanqu','','[]','(净)他浑身上如汤似火烧？(旦)不热。',119,'元曲/yuanqu.json','["(净)他浑身上如汤似火烧？(旦)不热。", "(净)口儿里常常干燥？(旦)也不。", "(净)终朝饭食都个要？(旦)也还吃些。", "(净)耳闻得蝉鸣声噪？(旦)也不。", "(净)心焦？(旦)也不。", "(净)莫不是害劳？(旦)这先生说的一些也不是。", "(净)都不是，不医便了。"]'),
('yuanqu-3001','山坡羊','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)娘子，我病体难医难治，你这苦如何存济？(旦)原流恩降福，降福灾星退。',101,'元曲/yuanqu.json','["(生)娘子，我病体难医难治，你这苦如何存济？(旦)原流恩降福，降福灾星退。", "(生)势渐危，料应我不久矣！若还我死，你必选个高门配，我便死向黄泉，一心只念你。", "(旦)休提。", "不由人泪暗垂。", "伤悲，何时得归故里？。"]'),
('yuanqu-3002','三棒鼓','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外、丑引众上。',66,'元曲/yuanqu.json','["(外、丑引众上。", "外)君臣迁徙去如星。", "只怕土产凋零也。", "人不见程。", "(众)一程两程，长亭短亭，不住行。", "如今海晏河清也，重逢太平，重乐太平。"]'),
('yuanqu-3003','五供养','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)别来久矣，自离朝尊体无恙。',59,'元曲/yuanqu.json','["(旦)别来久矣，自离朝尊体无恙。", "骨肉重再睹，喜非常。", "(外)孩儿，屈指数月，折倒尽昔时模样。", "思故里，念家乡，多少鬓边霜。"]'),
('yuanqu-3004','园林好','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)才说起迁都汴梁，闹炒炒哀声四方。',43,'元曲/yuanqu.json','["(旦)才说起迁都汴梁，闹炒炒哀声四方。", "不忍诉凄凉情况；家所有，尽撇漾；家使奴，尽逃亡。"]'),
('yuanqu-3005','嘉庆子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)你一双子母何所傍？(旦)更雨紧风寒势怎当？心急行程不上。',47,'元曲/yuanqu.json','["(外)你一双子母何所傍？(旦)更雨紧风寒势怎当？心急行程不上。", "人乱乱，世慌慌，愁戚戚，泪汪汪。"]'),
('yuanqu-3006','尹令','施惠《幽闺记》','元','元曲','yuanqu','','[]','那时又无倚仗，那时有亲难傍，那时有家难向。',48,'元曲/yuanqu.json','["那时又无倚仗，那时有亲难傍，那时有家难向。", "他东我西。", "地乱天慌，事怎防。", "(外)你母亲如今在那里？。"]'),
('yuanqu-3007','品令','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)逃生士民，在官道驿程傍。',64,'元曲/yuanqu.json','["(旦)逃生士民，在官道驿程傍。", "天色渐晚，阴云黯穹苍。", "匆匆正往，喊声如雷响。", "各各奔走，都向树林中抗。", "偷生苟免，瓦解星飞，子离了娘。"]'),
('yuanqu-3008','豆叶黄','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)我儿，你一身见在谁行？(旦)我随着个秀……(外)甚么秀？(旦)我随着个秀才栖身。',114,'元曲/yuanqu.json','["(外)我儿，你一身见在谁行？(旦)我随着个秀……(外)甚么秀？(旦)我随着个秀才栖身。", "(外)呀，他是甚么人？你随着他。", "(旦)他是我的家长。", "(外怒科)谁为媒妁？甚人主张？(旦)爹爹，人在那乱，人在那乱离时节，怎选得高门厮对厮当？。"]'),
('yuanqu-3009','月上海棠','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)你自想，甚年发迹穷形状？。',16,'元曲/yuanqu.json','["(外)你自想，甚年发迹穷形状？。"]'),
('yuanqu-3010','五韵关','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)意儿里想，眼儿里望，望救取东君艳阳，与花柳增芳。',81,'元曲/yuanqu.json','["(旦)意儿里想，眼儿里望，望救取东君艳阳，与花柳增芳。", "(生)全没些可伤，身凛凛如雪上加霜。", "(外)孩儿，你快随我去。", "(生、旦)更没些和气一味莽，铁胆铜心，打开凤凰。"]'),
('yuanqu-3011','二犯么令','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)你是娘生父养，逆亲言，心向情郎。',66,'元曲/yuanqu.json','["(外)你是娘生父养，逆亲言，心向情郎。", "(生)我向地，我向地狱相救你到天堂，怎下得撇在没人的店房。", "(旦合)若是两分张，管取拚残生命亡。"]'),
('yuanqu-3012','江儿水','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)眼见得今朝去，直恁忙。',87,'元曲/yuanqu.json','["(旦)眼见得今朝去，直恁忙。", "相随百步，尚且情悒怏，何况我夫妻月余上，怎下得霎时间如天样？(外、丑)若要成双，休指望。", "(生、旦)一对鸳鸯，生被跌天风浪。", "(外)六儿，快扯上马去。"]'),
('yuanqu-3013','川拨棹','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)心相诳，更不将恩义想。',39,'元曲/yuanqu.json','["(生)心相诳，更不将恩义想。", "(旦)无奈何事，无奈何事有参商。", "父逼女，夫言妇伤。"]'),
('yuanqu-3014','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)男儿赎药。',63,'元曲/yuanqu.json','["(旦)男儿赎药。", "把衣衫典当偿。", "我不能够觑，我不能够觑得你身体康。", "(生)我和你再。", "我和你再得成双，怕死后一灵儿到你行。", "(合前)。"]'),
('yuanqu-3015','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)休为我相思损天常，紧攻书，临选场。',81,'元曲/yuanqu.json','["(旦)休为我相思损天常，紧攻书，临选场。", "(生)我不道再，我不道再娶重婚，你焉肯终身守孀？(合)苦别离。", "愁断肠；两分离，愁断畅。", "(外)六儿。", "快扯上马去。", "(丑扯科)。"]'),
('yuanqu-3016','哭相思','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生、旦)怎下得将人离别，愁万缕，肠千结。',21,'元曲/yuanqu.json','["(生、旦)怎下得将人离别，愁万缕，肠千结。"]'),
('yuanqu-3017','卜算子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)病弱身着地，(末上扶生科。',67,'元曲/yuanqu.json','["(生)病弱身着地，(末上扶生科。", "生)气咽魂离体，拆散鸳鸯两处飞。", "天哪！多少衔冤气！店主人放手，我拚命去赶他转来。", "(末劝科)已去远了！。"]'),
('yuanqu-3018','上马踢','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦上)干戈动地来，车驾迁都汴。',56,'元曲/yuanqu.json','["(老旦上)干戈动地来，车驾迁都汴。", "儿夫离帝京，路遥人又远。", "军马临城。", "无计将身免。", "这苦怎言，祸不单行，中路儿不见。"]'),
('yuanqu-3019','銮江令','施惠《幽闺记》','元','元曲','yuanqu','','[]','(合)烦恼多历遍，忧愁怎消遣？眼儿哭得破，脚儿行得倦。',53,'元曲/yuanqu.json','["(合)烦恼多历遍，忧愁怎消遣？眼儿哭得破，脚儿行得倦。", "五甲复十里，一日如同过一年。", "但愿前途去，早早逢亲眷。"]'),
('yuanqu-3020','狼草生','施惠《幽闺记》','元','元曲','yuanqu','','[]','(合)劲风寒四合，暮烟昏惨惨。',52,'元曲/yuanqu.json','["(合)劲风寒四合，暮烟昏惨惨。", "彤云布，晚天变，只愁那长空雪舞絮绵绵。", "去心如箭，旅舍全无，何处安歇停眠？。"]'),
('yuanqu-3021','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末上)孟津驿舍住，在黄河岸边，乘船坐马十分便。',50,'元曲/yuanqu.json','["(末上)孟津驿舍住，在黄河岸边，乘船坐马十分便。", "(老旦，小旦)子母忙向前，可怜穷面，暂借安身望周全。"]'),
('yuanqu-3022','罗带儿','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)妾身本宦族，京城久居。',87,'元曲/yuanqu.json','["(老旦)妾身本宦族，京城久居。", "为侵边犯阙军奋武，君臣迁徒离中都也。", "(小旦)散乱人逃避，奔程途，身无主，去无所，惨可可地千生受万苦辛。", "(合)今宵得借一宿，可怜见子母每天翻地覆。"]'),
('yuanqu-3023','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末)兵戈起路程，人不惯经，早寻个旅邸休待等，怎容你行客寓邮亭也。',65,'元曲/yuanqu.json','["(末)兵戈起路程，人不惯经，早寻个旅邸休待等，怎容你行客寓邮亭也。", "(老旦)心下贪行路，望南京，不觉得暮云平，远涉涉地不知处人又生。"]'),
('yuanqu-3024','新水令','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)凄凉逆旅人千早，(旦)这萦牵怎生成寐？(小旦)万苦横心里。',48,'元曲/yuanqu.json','["(老旦)凄凉逆旅人千早，(旦)这萦牵怎生成寐？(小旦)万苦横心里。", "(合)睡不着，是愁都做枕边泪。"]'),
('yuanqu-3025','销金帐','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)黄昏悄悄，助冷风儿起。',71,'元曲/yuanqu.json','["(老旦)黄昏悄悄，助冷风儿起。", "想今朝，思向日，曾对这般时节，这般天气。", "羊羔美酒，美酒销金帐里。", "兵乱人慌，远远离乡里。", "如今怎生，怎生街头上睡？。"]'),
('yuanqu-3026','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)是二更鼓了。',76,'元曲/yuanqu.json','["(小旦)是二更鼓了。", "冬冬二鼓，则叶敲窗纸，响扑簌聒闷耳，难禁这般萧索，这般岑寂。", "骨肉到此，到此你东我西，去又无门，住又无依倚，伤心怎生，怎生街头上睡？。"]'),
('yuanqu-3027','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)三更漏转，寒雁声嘹呖。',70,'元曲/yuanqu.json','["(旦)三更漏转，寒雁声嘹呖。", "半明灭灯火煤，寻思这般沉疾，这般狼狈。", "相别到今，到今凶吉未知！冷落空房，药食准调理？床儿上怎生，怎生独自个睡？。"]'),
('yuanqu-3028','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)楼头四鼓，风掷檐铃碎。',70,'元曲/yuanqu.json','["(老旦)楼头四鼓，风掷檐铃碎。", "略朦胧惊梦回，娘女这般相逢，这般重会。", "飒然觉来，觉来孩儿那里？多少伤悲，多少萦牵系。", "教人怎生，怎生街头上睡？。"]'),
('yuanqu-3029','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)五更又催，野外疏钟。',76,'元曲/yuanqu.json','["(小旦)五更又催，野外疏钟。", "急算通宵，几叹息，一似这般烦恼，这般孤凄，一身苟活，苟活成得甚的？(旦)俺这里愁烦，那壁厢长吁气。", "听得怎生，怎生独自个睡？。"]'),
('yuanqu-3030','思园春','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)久阻尊颜想念勤。',66,'元曲/yuanqu.json','["(旦)久阻尊颜想念勤。", "(老旦)孩儿，此逢将谓是梦和魂。", "(外)这女儿是谁？(老旦)是我途中厮认来的。", "(小旦)奴是不应亲者，今日强来亲。"]'),
('yuanqu-3031','粉孩儿','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)相公，匆匆地离皇朝，你心不稳，弃家私老小，去得安忍？(外)只知国难识大臣，不提防万马千军犯京城。',67,'元曲/yuanqu.json','["(老旦)相公，匆匆地离皇朝，你心不稳，弃家私老小，去得安忍？(外)只知国难识大臣，不提防万马千军犯京城。", "君去民逃，常言道\"龙斗鱼损\"。"]'),
('yuanqu-3032','福马郎','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)那日里风寒雨又紧，正行里喊声如雷震。',38,'元曲/yuanqu.json','["(旦)那日里风寒雨又紧，正行里喊声如雷震。", "无处藏隐，急向林榔中躲，道途上奔。"]'),
('yuanqu-3033','红芍药','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)兵扰攘，阻隔关津。',81,'元曲/yuanqu.json','["(外)兵扰攘，阻隔关津。", "思量着，役梦劳魂。", "(丑)眼见得家中受危闲，望吾乡，有家难齐。", "(老旦)孩儿，历尽了苦共辛，娘逢人见人寻问。", "只愁你举目无亲，子父每何处厮认？。"]'),
('yuanqu-3034','会河阳','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)相公，有甚事争差，旺息怒嗔；闲言语总休论。',71,'元曲/yuanqu.json','["(老旦)相公，有甚事争差，旺息怒嗔；闲言语总休论。", "(小旦)贱妾不惧责罚，将片言语陈；难得见今朝分。", "(旦)甚时除得我心头闷？甚日除得我心头恨？。"]'),
('yuanqu-3035','缕缕金','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)教准备展芳樽，得团网都喜庆，尽欢欣。',56,'元曲/yuanqu.json','["(外)教准备展芳樽，得团网都喜庆，尽欢欣。", "(老旦)馆驿中有杂人来往，其实不稳。", "到南京得见圣明君，那时节好会佳宾。"]'),
('yuanqu-3036','红绣鞋','施惠《幽闺记》','元','元曲','yuanqu','','[]','(丑)画船已在河滨，河滨。',62,'元曲/yuanqu.json','["(丑)画船已在河滨，河滨。", "不劳马足车轮，车轮。", "(外)六儿，就此起程去罢。", "(众)离孟津，望前进，风力顺，水程紧，咫尺是汴梁城。"]'),
('yuanqu-3037','尾声','施惠《幽闺记》','元','元曲','yuanqu','','[]','别离会合皆缘分，受过忧危心自忖。',26,'元曲/yuanqu.json','["别离会合皆缘分，受过忧危心自忖。", "从今暮乐朝欢还再整。"]'),
('yuanqu-3038','步蟾宫','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生上)龙潭虎穴愁难数，更染病耽疾羁旅。',144,'元曲/yuanqu.json','["(生上)龙潭虎穴愁难数，更染病耽疾羁旅。", "分别人妻两南北，谁念我无穷凄楚？［眼儿媚］倾家荡业任飘零，受尽苦和辛。", "雁行中断，鸾俦生拆，无限伤情；穷途更多灾病，囊底已无缗。", "恁般正是福无双至，祸不单行。", "我蒋世隆自从与娘子分别，忽已月余。", "这几日身子虽觉渐安，争奈举目无亲，萧条旅馆，好生感伤人也！。"]'),
('yuanqu-3039','五样锦','施惠《幽闺记》','元','元曲','yuanqu','','[]','姻缘将谓五百年眷属。',183,'元曲/yuanqu.json','["姻缘将谓五百年眷属。", "十生九死成欢聚。", "经艰历险，幸然无虞。", "也指望否极生泰，祸绝受福。", "未妥，尚有如是苦：急浪狂风，风吹折并根连枝树；浪惊散鸳鸯两处孤，更全然不想我这病体疾躯。", "那肯放容他些儿个叮咛嘱付，将他倒拽横拖奔去途。", "回头道不得声将息，几曾有这般慈父！跌得我气绝再复。", "死绝再苏，一回价上心来，一回价痛哭。", "暮雨朝云去不还，强移栖息一枝安；春蚕到老丝方尽，蜡烛成灰泪始干。"]'),
('yuanqu-3040','孤飞雁','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生上)吾皇恩诏从天降。',78,'元曲/yuanqu.json','["(小生上)吾皇恩诏从天降。", "遍遐迩万民钦仰，宥极刑自有重生望。", "散群辈与群党，回凶就吉，转祸为祥。", "前临帝辇，绝却亲党，回首家乡，没了父娘。", "感伤，寻思着两泪千行。"]'),
('yuanqu-3041','惜黄花','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生)中都路是本乡，年驾望南往，一程程来到广阳，特来相访。',99,'元曲/yuanqu.json','["(小生)中都路是本乡，年驾望南往，一程程来到广阳，特来相访。", "(末)小可敢覆尊丈，有何事嘶问？当买货请商量，要安下却无妨。", "(小生)小生也非为买货，也不要安下，特来寻人。", "(末)若是问寻人，道如何模样？。"]'),
('yuanqu-3042','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生)店名须号招商？(末)是。',70,'元曲/yuanqu.json','["(小生)店名须号招商？(末)是。", "这里是招商店。", "(小生)少浼劳尊长。", "(末)且说怎么祥个人，姓甚么？(小生)有个秀才身姓蒋。", "(末)多少年纪了？。"]'),
('yuanqu-3043','惜奴引','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生上)祸不单行先自速，遭兵火那堪更重重坎坷。',42,'元曲/yuanqu.json','["(生上)祸不单行先自速，遭兵火那堪更重重坎坷。", "(末)官人你回来了？(生)是，回来了。"]'),
('yuanqu-3044','本序','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)自与相别，风寒劳役，受尽奔波，那更忧愁思虑。',74,'元曲/yuanqu.json','["(生)自与相别，风寒劳役，受尽奔波，那更忧愁思虑。", "在旅邸顿染沉疴。", "(小生)违和。", "天相吉人身痊可。", "却望节饮食，休劳碌。", "怎忘却，忘了问别来尊嫂贵体安乐。"]'),
('yuanqu-3045','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)提着心肠惨凄，不由人忍不住泪珠流颗，但有死别生离，那烦恼似天来大。',90,'元曲/yuanqu.json','["(生)提着心肠惨凄，不由人忍不住泪珠流颗，但有死别生离，那烦恼似天来大。", "(小生)缘何？莫非他弃旧怜新，从了别个？(生)不是。", "(小生)多应是疾病亡，遭非祸。", "(生)不是。", "你道为甚么？。"]'),
('yuanqu-3046','虾蟆序','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)摧挫。',70,'元曲/yuanqu.json','["(生)摧挫。", "艰共险，愁和闷，要躲怎躲，到如今尚有平地风波！(小生)惊愕。", "焰腾腾心上火，是谁人道与我？(生)你道如何，爱富嫌贫，岳丈倚强凌弱。"]'),
('yuanqu-3047','传言玉女','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外上)得睹天颜，真为主忧臣辱。',111,'元曲/yuanqu.json','["(外上)得睹天颜，真为主忧臣辱。", "(老旦上)皇恩深沐，享千钟重禄。", "(旦、小旦上)如今幸得再整银屏金屋。", "(合)皇朝重见，太严重睹。", "(外)尽日笙歌按玉楼，(老旦)忽朝军马犯皇州，(旦、小旦)但知会取非常乐，(合)须是提防不测忧。"]'),
('yuanqu-3048','玉漏迟序','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)得宠念辱，想其时驾迁民移前上，父母妻儿散离。',58,'元曲/yuanqu.json','["(旦)得宠念辱，想其时驾迁民移前上，父母妻儿散离。", "值此天数，抵多少吃辛受苦，抵多少亡家失所。", "(合)今幸得在画堂深处。"]'),
('yuanqu-3049','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)驿程去速，奈何被士马拦截归路，国败家亡，怎知此日完聚！知几遍宵行昼伏，知几遍风餐露宿！(合前)。',51,'元曲/yuanqu.json','["(外)驿程去速，奈何被士马拦截归路，国败家亡，怎知此日完聚！知几遍宵行昼伏，知几遍风餐露宿！(合前)。"]'),
('yuanqu-3050','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)轰雷战鼓，喊杀声散亡人尽奔逐，那时无他可怜。',51,'元曲/yuanqu.json','["(旦)轰雷战鼓，喊杀声散亡人尽奔逐，那时无他可怜。", "救我在危途，知何处作婢奴，知何处遭驱被虏。", "(合前)。"]'),
('yuanqu-3051','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)兄南妹北，乱兵中怎知生死！须臾骨肉分别，此身去住无所，感谢得恤寡念孤，感谢得为亲做主。',52,'元曲/yuanqu.json','["(小旦)兄南妹北，乱兵中怎知生死！须臾骨肉分别，此身去住无所，感谢得恤寡念孤，感谢得为亲做主。", "(合前)。"]'),
('yuanqu-3052','扑灯蛾','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)到行朝汴梁，看山河壮帝居。',70,'元曲/yuanqu.json','["(老旦)到行朝汴梁，看山河壮帝居。", "四时有常开花木，论繁华不减中都也。", "(外)受恩深处便为家，自来俗语。", "(合)休思故里，对良辰美景，宴乐且欢娱。"]'),
('yuanqu-3053','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)依旧珠围翠簇，依旧雕鞍绣毂，列侍妾丫鬟使女，送金杯听歌观舞也。',57,'元曲/yuanqu.json','["(旦)依旧珠围翠簇，依旧雕鞍绣毂，列侍妾丫鬟使女，送金杯听歌观舞也。", "(小旦)因灾致福，爱惜奴似亲生儿女。", "(合前)。"]'),
('yuanqu-3054','尾声','施惠《幽闺记》','元','元曲','yuanqu','','[]','从今休把光阴负，但畅饮高歌休阻，共醉乐神仙洞府。',24,'元曲/yuanqu.json','["从今休把光阴负，但畅饮高歌休阻，共醉乐神仙洞府。"]'),
('yuanqu-3055','夜行船','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦上)六曲栏杆和闷倚，不觉又媚景芳菲。',45,'元曲/yuanqu.json','["(旦上)六曲栏杆和闷倚，不觉又媚景芳菲。", "(小旦上)微雨昨宵，新晴今日。", "(合)知道海棠开未。"]'),
('yuanqu-3056','本序','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)春思恹恹，此愁谁诉，此情谁知；心撩乱，慵睹妆台梳洗。',68,'元曲/yuanqu.json','["(旦)春思恹恹，此愁谁诉，此情谁知；心撩乱，慵睹妆台梳洗。", "(小旦)芳时不暖不寒，秋千院宇，堪游堪戏。", "(旦)空对莺花燕柳，悄忽地暗皱双眉。"]'),
('yuanqu-3057','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)姐姐，因谁牵惹芳心，媚容香褪，嫩脸桃衰，看看恁宽尽金缕罗衣。',73,'元曲/yuanqu.json','["(小旦)姐姐，因谁牵惹芳心，媚容香褪，嫩脸桃衰，看看恁宽尽金缕罗衣。", "(旦)休疑，只为伤春，知他怎生，年年如是。", "(丑)休对晴天暖日，轻可地过了寒食。"]'),
('yuanqu-3058','风入松','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)甚心情闲步小园西。',74,'元曲/yuanqu.json','["(旦)甚心情闲步小园西。", "(小旦)姐姐为甚不去？(旦背唱科)推一个身倦神疲。", "(丑)趁春风桃李花开日，谁不待去寻芳拾翠？九十日光阴捻指，三分景，二分归。"]'),
('yuanqu-3059','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)那春光也应笑咱伊。',67,'元曲/yuanqu.json','["(小旦)那春光也应笑咱伊。", "(旦)笑甚的来？(小旦)笑你恁瘦减香肌。", "(旦)东君不管人憔悴，眼见得绿密红稀香闺掩，珠帘镇垂，不肯放燕双飞。"]'),
('yuanqu-3060','尾声','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)衷心先自不如意，纵然间旨同随喜，也做了兴尽空回。',28,'元曲/yuanqu.json','["(小旦)衷心先自不如意，纵然间旨同随喜，也做了兴尽空回。"]'),
('yuanqu-3061','望远行','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生上)春风紫陌，又是大涯行客。',106,'元曲/yuanqu.json','["(生上)春风紫陌，又是大涯行客。", "(小生上)野草闲花，掩映水光山色。", "(末、净上)杏花朵朵欹红，杨柳丝丝弄碧，沙岸远涟漪初溢。", "(生)携书挟策赴天邦，(小生)那更风光直艳阳，(末)路上野花钻地出。", "(净)村中美酒透瓶香。"]'),
('yuanqu-3062','望吾乡','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)降诏颁敕，搜贤赴帝域，文武远投安邦策，星斗文章谁能及，下笔如神力。',52,'元曲/yuanqu.json','["(生)降诏颁敕，搜贤赴帝域，文武远投安邦策，星斗文章谁能及，下笔如神力。", "(合)一朝里身显迹，受赏加官职。"]'),
('yuanqu-3063','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生)万里鹏翼，功名唾手得；英雄果是千人敌，正是男儿峥嵘日。',42,'元曲/yuanqu.json','["(小生)万里鹏翼，功名唾手得；英雄果是千人敌，正是男儿峥嵘日。", "岂敢辞劳役！(合前)。"]'),
('yuanqu-3064','感亭秋','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末)短亭长亭程程去，知几驿，逆旅中过寒食，见点点残红飞絮白，夕阳影里啼蜀魄。',56,'元曲/yuanqu.json','["(末)短亭长亭程程去，知几驿，逆旅中过寒食，见点点残红飞絮白，夕阳影里啼蜀魄。", "(合)家乡远，心慢忆，回首云烟隔。"]'),
('yuanqu-3065','红绣鞋','施惠《幽闺记》','元','元曲','yuanqu','','[]','(合)小径迢迢狭窄，狭窄；野水潺潺湍激，湍激。',47,'元曲/yuanqu.json','["(合)小径迢迢狭窄，狭窄；野水潺潺湍激，湍激。", "饮数杯解愁戚，那里堪观赏，可闲适，只愁他天晚逼。"]'),
('yuanqu-3066','尾声','施惠《幽闺记》','元','元曲','yuanqu','','[]','酒家眠，权休息，韫匮藏珠隐尘迹，万里前程在咫尺。',24,'元曲/yuanqu.json','["酒家眠，权休息，韫匮藏珠隐尘迹，万里前程在咫尺。"]'),
('yuanqu-3067','齐天乐','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦上)恹恹捱过残春也，又是困人时节。',71,'元曲/yuanqu.json','["(旦上)恹恹捱过残春也，又是困人时节。", "景色供愁，天气倦人，针指何曾拈刺？(小旦上)闲庭静悄，琐窗潇洒，小池澄澈。", "(合)叠青钱。", "泛水圆小嫩荷叶。"]'),
('yuanqu-3068','青衲袄','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)我几时得烦恼绝？几时得离恨彻？本待散闷闲行到台榭，伤情对景肠寸结。',87,'元曲/yuanqu.json','["(旦)我几时得烦恼绝？几时得离恨彻？本待散闷闲行到台榭，伤情对景肠寸结。", "(小旦)姐姐，撇下些罢。", "(旦)闷怀些儿，待撇下怎忍撇？待割舍难割舍。", "倚遍阑干，万感情切，都分付长叹嗟。"]'),
('yuanqu-3069','红衲袄','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)姐姐，你绣裙儿宽褪了褶，为伤春憔悴些。',84,'元曲/yuanqu.json','["(小旦)姐姐，你绣裙儿宽褪了褶，为伤春憔悴些。", "近日庞儿瘦成劳怯。", "莫不是又伤夏月？姊妹每休见撇，斟量着你非为别。", "(旦)你量着我甚么？(小旦)多应把姐夫来萦牵，别无些话说。"]'),
('yuanqu-3070','青衲袄','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦怒科)你把滥名儿将咱引惹，直恁的情性乖，心意劣，女孩儿家多口共饶舌，爹娘行快活要他做甚的？要妆衣满箧，要食珍羞则盛设，和你宽打周折。',116,'元曲/yuanqu.json','["(旦怒科)你把滥名儿将咱引惹，直恁的情性乖，心意劣，女孩儿家多口共饶舌，爹娘行快活要他做甚的？要妆衣满箧，要食珍羞则盛设，和你宽打周折。", "(走科。", "小旦)姐姐，到那里去？(旦)到父亲行先去说。", "(小旦)说些甚么？(旦)说你小鬼头春心动也。"]'),
('yuanqu-3071','红衲袄','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)我特地错赌别。',113,'元曲/yuanqu.json','["(小旦)我特地错赌别。", "(跪科)姐姐，望高抬贵手饶过些，一句话儿伤了俺贤姐姐。", "(旦)起来，且饶你这次，今后再不可如此。", "(小旦)若再如此呵，瑞莲甘痛决，姐姐闲耍歇，小的妹先去也。", "(旦)你那里去？(小旦)只管在此闲行，忘收了针线帖。"]'),
('yuanqu-3072','莺集御林春','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)恰才的乱掩胡遮，事到如今漏泄，姊妹每心肠休见别，夫妻每是有些周折。',37,'元曲/yuanqu.json','["(小旦)恰才的乱掩胡遮，事到如今漏泄，姊妹每心肠休见别，夫妻每是有些周折。"]'),
('yuanqu-3073','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦悲介)听说罢姓名家乡，这情苦意切，闷海愁山将我心上撇，不由人不泪珠流血！。',40,'元曲/yuanqu.json','["(小旦悲介)听说罢姓名家乡，这情苦意切，闷海愁山将我心上撇，不由人不泪珠流血！。"]'),
('yuanqu-3074','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)他须是瑞莲亲兄。',106,'元曲/yuanqu.json','["(小旦)他须是瑞莲亲兄。", "(旦)呀！原来是令兄。", "为何散失了！(小旦)为军马犯阙。", "(旦)是，我晓得了。", "散失忙寻相应者，那时节只争个字儿差迭。", "妹子，和你比先前又亲，自今越更着疼热，你休随着我跟脚，久已后是我男儿那枝叶。"]'),
('yuanqu-3075','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)我须是你妹妹姑姑，你是我的嫂嫂又是姐姐，未审家兄和你因甚别，两分离是何时节？(旦)正遇寒冬冷月，恨爹爹把奴拆散在招商舍。',64,'元曲/yuanqu.json','["(小旦)我须是你妹妹姑姑，你是我的嫂嫂又是姐姐，未审家兄和你因甚别，两分离是何时节？(旦)正遇寒冬冷月，恨爹爹把奴拆散在招商舍。"]'),
('yuanqu-3076','四犯黄莺儿','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)他直恁太情切，你十分忒软怯，眼睁睁怎忍相抛撇。',73,'元曲/yuanqu.json','["(小旦)他直恁太情切，你十分忒软怯，眼睁睁怎忍相抛撇。", "(旦)枉是怨嗟，无可计设，当不过他抢来推去望前扯。", "(合)意似虺蛇，性似蝎螫，一言如何诉说！。"]'),
('yuanqu-3077','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)流水一似马和车，倾刻间途路赊，他在穷途逆旅应难舍。',80,'元曲/yuanqu.json','["(小旦)流水一似马和车，倾刻间途路赊，他在穷途逆旅应难舍。", "(旦)那时节呵！囊箧又竭，药饵又缺。", "他那里闷恹恹难捱过如年夜。", "(合)宝镜分破，玉簪跌折，甚日重圆再接。"]'),
('yuanqu-3078','尾声','施惠《幽闺记》','元','元曲','yuanqu','','[]','自从别后音书绝，这些时魂惊梦怯，莫不是烦恼忧愁将人断送也。',29,'元曲/yuanqu.json','["自从别后音书绝，这些时魂惊梦怯，莫不是烦恼忧愁将人断送也。"]'),
('yuanqu-3079','秋蕊香','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦上)半载萦牵方寸，何时不泪滴眉颦！(小旦上)欲语难言信难问，即渐渐里恹恹瘦损。',160,'元曲/yuanqu.json','["(旦上)半载萦牵方寸，何时不泪滴眉颦！(小旦上)欲语难言信难问，即渐渐里恹恹瘦损。", "［玉楼春］(旦)深沉院宇无人问，纵然有便难传信。", "(小旦)这边愁似那边愁，伊的恨如奴的恨。", "(旦)心下慢然思又忖，口中枉自评和论。", "(合)有时欲向梦中诉，梦又不成灯又烬。", "(旦)妹子，这些时天下文武贤良。", "都来赴选，不知你哥哥也曾来否？好闷人也！。"]'),
('yuanqu-3080','二犯孝顺歌','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)从别后，渡孟津，思君尽日欲见君。',61,'元曲/yuanqu.json','["(旦)从别后，渡孟津，思君尽日欲见君。", "风北鸾南，生生地镜剖与钗分。", "镇千思万想，要见无门。", "(合)放不落心上人，撇不下心上人。"]'),
('yuanqu-3081','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)一回价，暗自忖，非亲怎知却是亲；你东咱西，荒荒地路途人乱奔，自一别半载，杳然无闻。',50,'元曲/yuanqu.json','["(小旦)一回价，暗自忖，非亲怎知却是亲；你东咱西，荒荒地路途人乱奔，自一别半载，杳然无闻。", "(合前)。"]'),
('yuanqu-3082','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)恩和爱，苦共辛，衷肠告天天怎闻？妾后夫前，恹恹地几曾忘半分，有三言两语，寄也无因。',49,'元曲/yuanqu.json','["(旦)恩和爱，苦共辛，衷肠告天天怎闻？妾后夫前，恹恹地几曾忘半分，有三言两语，寄也无因。", "(合前)。"]'),
('yuanqu-3083','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)当时苦，值乱军，离乡背井兄妹分。',50,'元曲/yuanqu.json','["(小旦)当时苦，值乱军，离乡背井兄妹分。", "做小服低，看看地过冬还过春。", "捱十生九死，举目无亲。", "(合前)。"]'),
('yuanqu-3084','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦上)兰堂日永湘帘卷，画檐前燕鹊声喧。',41,'元曲/yuanqu.json','["(老旦上)兰堂日永湘帘卷，画檐前燕鹊声喧。", "(旦、小旦上)喜椿萱晚景安然，感谢苍人。"]'),
('yuanqu-3085','普贤歌','施惠《幽闺记》','元','元曲','yuanqu','','[]','(丑上)媒婆终日脚奔波，成就人间好事多。',41,'元曲/yuanqu.json','["(丑上)媒婆终日脚奔波，成就人间好事多。", "这家也是我，那家也是我，也只为家贫没奈何。"]'),
('yuanqu-3086','黄莺儿','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)二女正青年，相门高，当遴选。',70,'元曲/yuanqu.json','["(外)二女正青年，相门高，当遴选。", "乘龙未遂吾心愿。", "幸朝廷命宣，配文武状元，郎才女貌真堪羡！(老旦合)媒婆，你去递丝鞭，一双两美，成就好姻缘。"]'),
('yuanqu-3087','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)口诵柏舟篇，更何心续断弦。',16,'元曲/yuanqu.json','["(旦)口诵柏舟篇，更何心续断弦。"]'),
('yuanqu-3088','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)媒婆，你也听我道，那日涉风烟，望关山路八千，乱军中不见了哥哥面。',94,'元曲/yuanqu.json','["(小旦)媒婆，你也听我道，那日涉风烟，望关山路八千，乱军中不见了哥哥面。", "幸夫人见怜，将奴身保全。", "胜似嫡亲，相待恩非浅。", "今日递丝鞭，我红生羞脸，黄色上眉间。", "(外)媒婆休要多言，疾忙递丝鞭去。"]'),
('yuanqu-3089','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(丑)钧命敢迟延。',98,'元曲/yuanqu.json','["(丑)钧命敢迟延。", "这姻缘非偶然，匪媒弗克成姻眷，调和两边并无一言。", "人间第一要行方便，今日递丝鞭，仙郎肯受，多赠贯头钱。", "(外)媒婆，还有一件，恐二位状元不知小姐媸妍，将这真容与他看去。", "(丑)理会得。"]'),
('yuanqu-3090','风入松','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生上)同声相应气相求，同占鳌头。',17,'元曲/yuanqu.json','["(生上)同声相应气相求，同占鳌头。"]'),
('yuanqu-3091','胜葫芦','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末、丑上)圣主忧虞及大臣，因无子继家门。',45,'元曲/yuanqu.json','["(末、丑上)圣主忧虞及大臣，因无子继家门。", "二女如花，未曾谐秦晋，特来说合，两两仙郎共成亲。"]'),
('yuanqu-3092','集贤宾','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)那时挈家逃难走，正鬼哭神愁，喊杀声如雷军马骤，乱荒荒过壑经丘。',89,'元曲/yuanqu.json','["(生)那时挈家逃难走，正鬼哭神愁，喊杀声如雷军马骤，乱荒荒过壑经丘。", "妹子瑞莲呵！相失在后，寻讨处不知所有，难措手。", "忽有人同声相应，同气相求。", "(小生)向日山寨中见的嫂嫂，想就是了。"]'),
('yuanqu-3093','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)途中见时虽厮守，犹觉满面娇羞。',199,'元曲/yuanqu.json','["(生)途中见时虽厮守，犹觉满面娇羞。", "到得磁州广阳镇招商店中呵！直待媒妁之言成配偶。", "不意他父亲王尚书，缉探虎狼军，回到招商店中，遇见是他女儿，竟自夺回去了。", "(小生)哥哥，你那时怎割舍得他去！(生)病恹恹无计相留。", "(小生)若是小弟，一定与他厮闹一场。", "(生)他是尚书，我是穷儒。", "怎敢与他龙争虎斗？(小生)别后曾有音信么？(生)分别后知他安否！(小生)如今圣旨议亲，怎辞得他？(生)恩德厚，有何颜再配鸾俦。"]'),
('yuanqu-3094','琥珀猫儿堕','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小生)听哥说罢，方识此根由。',88,'元曲/yuanqu.json','["(小生)听哥说罢，方识此根由。", "这是王尚书，招商店也是王尚书。", "有事可疑。", "哥哥，破镜重圆从古有，何须疑虑反生愁？(生)兄弟，断无此事，不可错疑了。", "(小生)不谬。", "重整备乘龙花烛风流。"]'),
('yuanqu-3095','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末、丑)正是义夫节妇，语意两相投，多应是有分姻缘当辏偶。',56,'元曲/yuanqu.json','["(末、丑)正是义夫节妇，语意两相投，多应是有分姻缘当辏偶。", "状元老爷，此情分付与东流。", "休休，把旧恨新愁一笔都勾！。"]'),
('yuanqu-3096','似娘儿','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外上)姻事未和谐，媒婆去不见回来。',49,'元曲/yuanqu.json','["(外上)姻事未和谐，媒婆去不见回来。", "(老旦上)教人望眼悬悬待。", "(合)玉音已降，冰人已遣，汗简何乖。"]'),
('yuanqu-3097','啄木鸟','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末、丑)他说遭离乱，值变迁，民庶逃生离故园；兄携妹远涉风烟，乱纷纷戈戟森然，喊杀中妹子忽不见，前村后陌都寻遍，声唤多娇蒋瑞莲。',75,'元曲/yuanqu.json','["(末、丑)他说遭离乱，值变迁，民庶逃生离故园；兄携妹远涉风烟，乱纷纷戈戟森然，喊杀中妹子忽不见，前村后陌都寻遍，声唤多娇蒋瑞莲。", "(外)那时寻见也未？。"]'),
('yuanqu-3098','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末、丑)兄寻妹，涕泪涟。',122,'元曲/yuanqu.json','["(末、丑)兄寻妹，涕泪涟。", "忽听得悠悠声应远，只道是妹见哥哥，却原来错认陶潜。", "那女子呵，他娘儿拆散中途畔，叫声应声随呼唤。", "(外)那女子怎么应他？(末、丑)那女子叫名瑞兰，与瑞莲声音厮类。", "名韵相同事偶然。", "(外)那女子失散了母亲，在途路上单身不便了。"]'),
('yuanqu-3099','三段子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末、丑)欲随向前，男女辈同行未便，欲落所边，乱军中污辱未免。',86,'元曲/yuanqu.json','["(末、丑)欲随向前，男女辈同行未便，欲落所边，乱军中污辱未免。", "说只得做兄妹同行呵。", "相随同到招商店，主人翁作伐谐姻眷。", "那其问状元染病，正仗那娘子扶持，不意他岳丈相逢拆散锦鸳。"]'),
('yuanqu-3100','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(老旦)孩儿瑞兰，与伊妻名儿一般；孩儿瑞莲，与伊妹名非两般。',74,'元曲/yuanqu.json','["(老旦)孩儿瑞兰，与伊妻名儿一般；孩儿瑞莲，与伊妹名非两般。", "我中都路母子曾失散，你招商店父子重相见，事迹相同岂偶然？老相公，事在如今，却怎生是好？。"]'),
('yuanqu-3101','滴溜子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)我有一个道理：明日里，明日里，小设酒筵；媒婆去，媒婆去，传语状元，既然他心中不愿，如何强逼他谐缱绻。',102,'元曲/yuanqu.json','["(外)我有一个道理：明日里，明日里，小设酒筵；媒婆去，媒婆去，传语状元，既然他心中不愿，如何强逼他谐缱绻。", "(老旦)既如此，你请他来怎么？(外)请来饮酒之间呵，先教他妹子在堂前，隔帘认看。", "(老旦)此计甚好。"]'),
('yuanqu-3102','尾声','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外)相逢到此缘非浅，真与假明朝便见。',58,'元曲/yuanqu.json','["(外)相逢到此缘非浅，真与假明朝便见。", "你二人传语状元，亲事不敢相扳，只请枉临一会，再无他意。", "望勿推辞，特请他来赴宴。"]'),
('yuanqu-3103','玩仙灯','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生上)有事挂心怀，好一似和钩吞线。',102,'元曲/yuanqu.json','["(生上)有事挂心怀，好一似和钩吞线。", "忆自离家几变更，此身须在亦堪惊，东边日出西边雨，道是无情却有情。", "昨为王尚书遣官媒婆、院子来此说亲，教我越加烦恼，不知甚日，方得我娇妻的音耗。", "唉！不免将琴书消遣一番则个。"]'),
('yuanqu-3104','懒朝天','施惠《幽闺记》','元','元曲','yuanqu','','[]','一自瑶琴操离鸾，眼底知音少，不与弹。',43,'元曲/yuanqu.json','["一自瑶琴操离鸾，眼底知音少，不与弹。", "今朝拂试锦囊看雪窗寒，伤心一曲倚栏干，续关雎调难。"]'),
('yuanqu-3105','懒画眉','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末、丑上)空劳仙子下天台，何意刘郎事不谐？状元老爷，官媒婆、院子叩头。',68,'元曲/yuanqu.json','["(末、丑上)空劳仙子下天台，何意刘郎事不谐？状元老爷，官媒婆、院子叩头。", "(生)二人因甚去还来？(末、丑)早成就了合欢带，管取州逢笑口开。"]'),
('yuanqu-3106','卜算子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外上)一段好姻缘，说起难抛下。',30,'元曲/yuanqu.json','["(外上)一段好姻缘，说起难抛下。", "今朝开宴特相邀，试问真和假。"]'),
('yuanqu-3107','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生上)仙子宴瑶池，青鸟书传送，道是无情却有情，既信犹疑梦。',42,'元曲/yuanqu.json','["(生上)仙子宴瑶池，青鸟书传送，道是无情却有情，既信犹疑梦。", "(末)禀老爷，状元到了。"]'),
('yuanqu-3108','山坡羊','施惠《幽闺记》','元','元曲','yuanqu','','[]','那日因遭兵燹，兄妹移家迁汴，乱军中拆散雁行，两下里追寻不见，叫瑞莲，有个佳人忽偶然。',215,'元曲/yuanqu.json','["那日因遭兵燹，兄妹移家迁汴，乱军中拆散雁行，两下里追寻不见，叫瑞莲，有个佳人忽偶然。", "(净)那佳人怎么就肯答应？(生)那佳人叫名瑞兰，与瑞莲声音厮类，故应错了。", "(净)既如此，曾与他配合也不曾？(生)相随同到招商店，合卺曾凭媒妁言，交欢，谁知一病缠？学生正染病间，被他父亲--也是王尚书--偶然遇见，夺回去了。", "(净)咳！这个天杀的老忘八！(生)堪怜，分开凤与鸾。", "(净)那是一时的事，也抛撇得下了。", "今日相府认亲，状元大人如何再三不允？。"]'),
('yuanqu-3109','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)佩德衔恩非浅，别后心常怀念。',17,'元曲/yuanqu.json','["(生)佩德衔恩非浅，别后心常怀念。"]'),
('yuanqu-3110','哭相思','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生、小旦)兄妹当初两分散，谁知此地重相见？。',23,'元曲/yuanqu.json','["(生、小旦)兄妹当初两分散，谁知此地重相见？。"]'),
('yuanqu-3111','香柳娘','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)想当初难中，想当初难中，与哥哥分散，孤身途路谁相盼。',78,'元曲/yuanqu.json','["(小旦)想当初难中，想当初难中，与哥哥分散，孤身途路谁相盼。", "幸夫人见怜，幸夫人见怜，相挈在身边，慈悲做方便。", "与亲生女儿，与亲生女儿，相看一般，喜今朝重见！。"]'),
('yuanqu-3112','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)叹兄南妹北，叹兄南妹北，无由会面，你身有托吾无伴；绕山坡叫转，绕山坡叫转，蓦地遇蝉娟，天教遂姻眷。',88,'元曲/yuanqu.json','["(生)叹兄南妹北，叹兄南妹北，无由会面，你身有托吾无伴；绕山坡叫转，绕山坡叫转，蓦地遇蝉娟，天教遂姻眷。", "奈时乖运蹇，奈时乖运蹇，一别数年，存亡未判。", "(小旦)哥哥，嫂嫂也在这里。"]'),
('yuanqu-3113','五更转','施惠《幽闺记》','元','元曲','yuanqu','','[]','(小旦)你望故人如天远，相逢在目前。',117,'元曲/yuanqu.json','["(小旦)你望故人如天远，相逢在目前。", "(生)妹子，你为何认得嫂嫂？(小旦)闺中小姐，曾会你在招商店，拜月亭前，说出心愿。", "(生)你莫非差了？(小旦)乡贯同，名字真，非讹舛，爹爹、母亲望乞垂怜见，早使相逢，不索留恋。", "待我请嫂嫂来。", "姐姐有请。"]'),
('yuanqu-3114','似娘儿','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦上)梦里流莺声尚在，出兰房风翻佩带。',20,'元曲/yuanqu.json','["(旦上)梦里流莺声尚在，出兰房风翻佩带。"]'),
('yuanqu-3115','哭相思','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生)一别招商已数年，今朝重续旧姻缘，贞心一片如明月，映入清波到底圆。',35,'元曲/yuanqu.json','["(生)一别招商已数年，今朝重续旧姻缘，贞心一片如明月，映入清波到底圆。"]'),
('yuanqu-3116','五更转','施惠《幽闺记》','元','元曲','yuanqu','','[]','(旦)你的病未痊，我却离身畔，心中常挂牵。',88,'元曲/yuanqu.json','["(旦)你的病未痊，我却离身畔，心中常挂牵。", "(生)苍天保佑，保佑身康健。", "与那结义兄弟呵，武举文科，同登魁选，蒙圣恩特议亲，岂吾愿！(合)相逢到此，到此真希罕。", "喜动离怀，笑生愁脸。"]'),
('yuanqu-3117','恋芳春','施惠《幽闺记》','元','元曲','yuanqu','','[]','(生、小生上)宝马骄嘶，香车毕集，灯光如昼通明。',93,'元曲/yuanqu.json','["(生、小生上)宝马骄嘶，香车毕集，灯光如昼通明。", "(旦、小旦上)彷佛天台刘阮，仙子相迎。", "(合)夙世姻缘已定，昔离别今成欢庆；相随美满夫妻，强如鸾凤和鸣。", "(净赞礼拜撒帐科。", "生、小生把酒科)。"]'),
('yuanqu-3118','画眉序','施惠《幽闺记》','元','元曲','yuanqu','','[]','文武掇巍科，丹桂高攀近嫦娥。',59,'元曲/yuanqu.json','["文武掇巍科，丹桂高攀近嫦娥。", "喜莺迁乔木，凤止高柯；十年探孔孟心传，一旦试孙吴家学。", "(合)画堂花烛光摇处，一派乐声喧和。"]'),
('yuanqu-3119','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外、老旦)两国罢干戈，民庶安生绝烽火；幸阳春忽布，网罗消磨；昨朝羡锦夺标头，今夜喜红丝牵巾莫。',53,'元曲/yuanqu.json','["(外、老旦)两国罢干戈，民庶安生绝烽火；幸阳春忽布，网罗消磨；昨朝羡锦夺标头，今夜喜红丝牵巾莫。", "(合前)。"]'),
('yuanqu-3120','滴溜子','施惠《幽闺记》','元','元曲','yuanqu','','[]','(末捧诏上)一封的，一封的，传达圣聪；天颜喜，天颜喜，满门诏封。',345,'元曲/yuanqu.json','["(末捧诏上)一封的，一封的，传达圣聪；天颜喜，天颜喜，满门诏封。", "九重红云簇拥，龙章出凤墀，蒙恩受宠。", "五拜山呼，稽首鞠躬。", "奉天承运皇帝诏曰：夫妇乃人伦所重，节义为世教所关；迩者世际阽危，失之者众矣。", "兹尔文科状元蒋世隆，讲婚礼于急遽之时，从容不苟；妻王瑞兰，待媒妁于流离之际，贞节自持。", "夫不重婚，尚宋弘之高谊；妇不再嫁，迈令女之清风。", "使乐昌之破镜重圆，致陶谷之断弦再续。", "兵部尚书王镇，保邦致治，有拨乱反正之才；解组归闲，无贪位慕禄之行。", "陀满兴福出自忠良，实非反叛。", "父遭排摈，朕实悔伤；萌蘖尚存，天意有在。", "今尔荣魁武榜，互结姻缘。", "蒋世隆授开封府尹，妻王氏封懿德夫人。", "陀满兴福世袭昭勇将军，妻蒋氏封顺德夫人。", "尚书王镇，岁支粟帛，与见任同。", "呜呼！彝伦攸序，尔宜钦哉！谢恩！(众)万岁，万岁，万万岁！。"]'),
('yuanqu-3121','望吾乡','施惠《幽闺记》','元','元曲','yuanqu','','[]','(众)仰圣瞻天恩，光照绮筵。',52,'元曲/yuanqu.json','["(众)仰圣瞻天恩，光照绮筵。", "花枝掩映春风面，女貌郎才真堪羡。", "天遣为姻眷，双飞鸟，并蒂莲，今朝得遂平生愿。"]'),
('yuanqu-3122','皂罗袍','施惠《幽闺记》','元','元曲','yuanqu','','[]','向日銮舆迁汴，正土崩瓦解，士庶纷然。',62,'元曲/yuanqu.json','["向日銮舆迁汴，正土崩瓦解，士庶纷然。", "人于颠沛节难全，坚金百炼终无变。", "娘儿兄妹，流离播迁，断而还续，破而复圆，义夫节妇人间鲜。"]'),
('yuanqu-3123','排歌','施惠《幽闺记》','元','元曲','yuanqu','','[]','今日相逢，三生有缘，文兄武弟襟联，乔公二女正芳年，孙策周瑜德并贤。',65,'元曲/yuanqu.json','["今日相逢，三生有缘，文兄武弟襟联，乔公二女正芳年，孙策周瑜德并贤。", "夫荣耀，妻贵显，宫花如锦酒如泉。", "风流事，著简编，传奇留与后人传。"]'),
('yuanqu-3124','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','(外、老旦)吾年老雪满颠，无子承家业，晨昏每忧煎。',85,'元曲/yuanqu.json','["(外、老旦)吾年老雪满颠，无子承家业，晨昏每忧煎。", "且喜东床中选，雀屏中目，一双白璧种蓝田，百岁夫妻今美满。", "山中相，地上仙，人间诸事不萦牵。", "垆边醉，瓮底眠，从今不惜杖头钱。"]'),
('yuanqu-3125','金钱花','施惠《幽闺记》','元','元曲','yuanqu','','[]','(众)翰林史笔如椽，如椽；倒流三峡词源，词源。',47,'元曲/yuanqu.json','["(众)翰林史笔如椽，如椽；倒流三峡词源，词源。", "撮成离合与悲欢。", "千百载，永流传；千百载，永流传。"]'),
('yuanqu-3126','前腔','施惠《幽闺记》','元','元曲','yuanqu','','[]','铁球漾在江边，江边；终须到底团圆，团圆。',113,'元曲/yuanqu.json','["铁球漾在江边，江边；终须到底团圆，团圆。", "戏文自古出梨园。", "今夜里且欢散，明日里再敷演，明日里再敷演。", "自来好事最多磨，天与人违奈若何？拜月事前愁不浅，招商店内恨偏多。", "乐极悲生从古有，分开复合岂今讹？风流事载风流传，太平人唱太平歌。"]'),
('yuanqu-3127','尉迟恭三夺槊・仙吕/点绛唇','尚仲贤','元','元曲','yuanqu','','[]','想当日霸业图王，岂知今亡，把江山掌。',35,'元曲/yuanqu.json','["想当日霸业图王，岂知今亡，把江山掌。", "虽不是外国他邦，今日做僚宰为卿相。"]'),
('yuanqu-3128','尉迟恭三夺槊・混江龙','尚仲贤','元','元曲','yuanqu','','[]','不着些宽洪海量，划地信谗言佞语损忠良。',76,'元曲/yuanqu.json','["不着些宽洪海量，划地信谗言佞语损忠良。", "谁不曾忘生舍死？谁不曾展土开疆？不枉了截发搓绳穿断甲，征旗作带勒金疮。", "我与你不避金瓜下丧，直言在宝殿，苦谏在昭阳。"]'),
('yuanqu-3129','尉迟恭三夺槊・天下乐','尚仲贤','元','元曲','yuanqu','','[]','谁似俺出气力功臣不气长，想当时，反在晋阳。',54,'元曲/yuanqu.json','["谁似俺出气力功臣不气长，想当时，反在晋阳。", "若不是唐元帅少年有纪纲，义伏了徐茂公，礼慑了褚遂良，智降了苏定方。"]'),
('yuanqu-3130','尉迟恭三夺槊・醉扶归','尚仲贤','元','元曲','yuanqu','','[]','当日都是那不主事萧丞相，更合着那没政事汉高皇，把韩元帅葫芦提斩在未央。',68,'元曲/yuanqu.json','["当日都是那不主事萧丞相，更合着那没政事汉高皇，把韩元帅葫芦提斩在未央。", "今日个人都讲，若有举鼎拔山的霸王，哎．汉高呀你怎敢正眼儿把韩侯望。"]'),
('yuanqu-3131','尉迟恭三夺槊・后庭花','尚仲贤','元','元曲','yuanqu','','[]','陛下，则将这美良川水冤恨想，却把那榆窠园耻英雄忘。',68,'元曲/yuanqu.json','["陛下，则将这美良川水冤恨想，却把那榆窠园耻英雄忘。", "更做道世事云千变，敬德呵则消得功名纸半张。", "陛下试参详，更做道贵人多忘，咱数年问有倚仗。"]'),
('yuanqu-3132','尉迟恭三夺槊・金盏儿','尚仲贤','元','元曲','yuanqu','','[]','那敬德自归了唐，到咱行，把六十四处烟尘荡。',65,'元曲/yuanqu.json','["那敬德自归了唐，到咱行，把六十四处烟尘荡。", "杀得敌军胆丧，马到处不能当，苦相持一万阵，恶战讨了九千场。", "全凭着竹节鞭，生并了些草头王。"]'),
('yuanqu-3133','尉迟恭三夺槊・赏花时','尚仲贤','元','元曲','yuanqu','','[]','元帅不合短箭轻弓观他洛阳，怎想阔剑长枪埋在浅岗，映着秋草半苍黄。',48,'元曲/yuanqu.json','["元帅不合短箭轻弓观他洛阳，怎想阔剑长枪埋在浅岗，映着秋草半苍黄。", "初间那唐元帅怎想，脑背后不堤防。"]'),
('yuanqu-3134','尉迟恭三夺槊・幺篇','尚仲贤','元','元曲','yuanqu','','[]','呀，则见那骨刺剌征旗遮了太阳，赤力力征鼙振动上苍，那单雄信恁高强。',49,'元曲/yuanqu.json','["呀，则见那骨刺剌征旗遮了太阳，赤力力征鼙振动上苍，那单雄信恁高强。", "他猛观了敌军势况，忙拨转紫丝缰。"]'),
('yuanqu-3135','尉迟恭三夺槊・胜葫芦','尚仲贤','元','元曲','yuanqu','','[]','打得匹不剌刺征马宛走电光，藉不得众儿郎，过涧沿坡寻路忄葱。',52,'元曲/yuanqu.json','["打得匹不剌刺征马宛走电光，藉不得众儿郎，过涧沿坡寻路忄葱。", "过了些乱烘烘的荆棘，密稠稠榆柳，齐臻臻长成行。"]'),
('yuanqu-3136','尉迟恭三夺槊・金盏儿','尚仲贤','元','元曲','yuanqu','','[]','元帅却是那些儿慌，那些忙，(带云)忙不忙，元帅也记得。',97,'元曲/yuanqu.json','["元帅却是那些儿慌，那些忙，(带云)忙不忙，元帅也记得。", "把一领锦征袍扯裸得没头当。", "单雄信先地赶上手拈着绿沉枪，枪尖儿看看地着脊背，着脊背透过胸堂。", "那时若不是胡敬德。", "(带云)陛下圣鉴谁搭救小秦王？。"]'),
('yuanqu-3137','尉迟恭三夺槊・醉扶归','尚仲贤','元','元曲','yuanqu','','[]','索甚把白己千般奖，齐王呵，不如教别人道一声强。',68,'元曲/yuanqu.json','["索甚把白己千般奖，齐王呵，不如教别人道一声强。", "若共胡敬德草草的鞭斗枪，分明立了执结并文状，则他家自卖弄伶俐半晌，把一条虎眼鞭直揽头直上。"]'),
('yuanqu-3138','尉迟恭三夺槊・尾','尚仲贤','元','元曲','yuanqu','','[]','这厮则除了铁天灵，铜脖项，铜脑袋，石镌就的脊梁。',105,'元曲/yuanqu.json','["这厮则除了铁天灵，铜脖项，铜脑袋，石镌就的脊梁。", "那鞭上常有半纸血糊涂的人脑浆，则那鞭则是铁头中取命的阎正。", "若论高强，鞭着处便不死十分地也带重伤。", "也是青天会对当，故教这尉迟恭磨障，磨障这杀君杀父的劣心肠。", "(下)。"]'),
('yuanqu-3139','尉迟恭三夺槊・南吕/一枝花','尚仲贤','元','元曲','yuanqu','','[]','箭空攒白凤翎，弓闲挂乌龙角，土培损金锁甲，尘昧了锦征袍。',76,'元曲/yuanqu.json','["箭空攒白凤翎，弓闲挂乌龙角，土培损金锁甲，尘昧了锦征袍。", "空喂得那匹战马咆哮，劈椤锏生疏却，那些儿俺心越焦。", "我往常雄纠纠的阵面上相持，恶喑喑的沙场上战讨。"]'),
('yuanqu-3140','尉迟恭三夺槊・梁州','尚仲贤','元','元曲','yuanqu','','[]','这些时但做梦早和敌军对垒，才合眼早不刺剌地战马相交。',174,'元曲/yuanqu.json','["这些时但做梦早和敌军对垒，才合眼早不刺剌地战马相交。", "则听的韵悠悠的耳畔吹寒角，一回价不冬冬的催军鼓擂，响当当的助战锣敲。", "稀撒撒地朱帘筛日，滴溜溜的绣幕翻风，只疑是古剌剌杂彩旗摇。", "那的是急煎煎心痒难揉，往常则许咱遇水叠桥，除了咱逢山开道，嗨，如今央别人跨海征辽。", "壮怀怎消，近新来病体儿直然较，我自喑约也枉了医疗，被这秋气重金疮越发作，好教我痛苦难消。"]'),
('yuanqu-3141','尉迟恭三夺槊・贺新郎','尚仲贤','元','元曲','yuanqu','','[]','我欠起这病身躯出产急相邀，你知我迭不的相迎，带云不沙，贼丑生唱你也合早些儿通报。',126,'元曲/yuanqu.json','["我欠起这病身躯出产急相邀，你知我迭不的相迎，带云不沙，贼丑生唱你也合早些儿通报。", "见齐王元吉都来到，半晌不迭手脚，我强强地曲脊低腰。", "怪早来喜蛛儿的溜溜在檐外垂，灵鹊儿咋咋地头直上噪，昨夜个银台上剥地灯花爆。", "他两个是九重天上皇太子，来探俺这半残不病旧臣僚。"]'),
('yuanqu-3142','尉迟恭三夺槊・隔尾','尚仲贤','元','元曲','yuanqu','','[]','我从二十三上早驱军校，经到四五千场恶战讨。',54,'元曲/yuanqu.json','["我从二十三上早驱军校，经到四五千场恶战讨。", "怎想头直上轮还老来到。", "我暗约，慢慢的想度，嗨，刮马似三十年过去了。"]'),
('yuanqu-3143','尉迟恭三夺槊・隔尾','尚仲贤','元','元曲','yuanqu','','[]','那鞭却似一条玉蟒生鳞角？便是半截乌龙去了牙爪，那鞭着远望了吸吸地脑门上跳。',69,'元曲/yuanqu.json','["那鞭却似一条玉蟒生鳞角？便是半截乌龙去了牙爪，那鞭着远望了吸吸地脑门上跳。", "那鞭休道十分的正着，则若轻轻地抹着，敢教你睡梦里惊急列地怕到晓。"]'),
('yuanqu-3144','尉迟恭三夺槊・尾','尚仲贤','元','元曲','yuanqu','','[]','可知道金风未动蝉先觉，那宝剑得来你怎消，不出君王行。',70,'元曲/yuanqu.json','["可知道金风未动蝉先觉，那宝剑得来你怎消，不出君王行。", "厮般调，侵着眉楞，擦着眼角。", "则若是轻轻的虎眼鞭抹着，稳情取你那天灵盖半截不见了。", "(下)。"]'),
('yuanqu-3145','尉迟恭三夺槊・步步娇','尚仲贤','元','元曲','yuanqu','','[]','便折末烂锉得我尸骸为泥粪，折末金瓜打碎我天灵尽。',64,'元曲/yuanqu.json','["便折末烂锉得我尸骸为泥粪，折末金瓜打碎我天灵尽。", "既然俺不怨恨，问那厮损坏忠臣佞词因。", "咱那亢金椅上圣明君，则但般着半句儿十分地信。"]'),
('yuanqu-3146','尉迟恭三夺槊・川拨棹','尚仲贤','元','元曲','yuanqu','','[]','听元帅说原因，心头上一千团火块滚。',48,'元曲/yuanqu.json','["听元帅说原因，心头上一千团火块滚。", "气的肚里生嗔，愁的似地惨天昏。", "恰便似心内火块滚，好教人怎受忍。"]');
